6:\"gemini-2.5-flash\";s:27:\"seopress_ai_mistral_api_key\";N;s:25:\"seopress_ai_mistral_model\";s:20:\"mistral-small-latest\";s:26:\"seopress_ai_claude_api_key\";N;s:24:\"seopress_ai_claude_model\";s:24:\"claude-sonnet-4-20250514\";s:30:\"seopress_breadcrumbs_separator\";s:0:\"\";s:24:\"seopress_breadcrumbs_cpt\";a:5:{s:8:\"category\";a:1:{s:3:\"cpt\";s:4:\"none\";}s:8:\"post_tag\";a:1:{s:3:\"cpt\";s:4:\"none\";}s:18:\"knowledgebase_type\";a:1:{s:3:\"cpt\";s:4:\"none\";}s:9:\"news_type\";a:1:{s:3:\"cpt\";s:4:\"none\";}s:11:\"person_type\";a:1:{s:3:\"cpt\";s:4:\"none\";}}s:24:\"seopress_breadcrumbs_tax\";a:5:{s:4:\"post\";a:1:{s:3:\"tax\";s:4:\"none\";}s:4:\"page\";a:1:{s:3:\"tax\";s:4:\"none\";}s:13:\"knowledgebase\";a:1:{s:3:\"tax\";s:4:\"none\";}s:4:\"news\";a:1:{s:3:\"tax\";s:4:\"none\";}s:6:\"person\";a:1:{s:3:\"tax\";s:4:\"none\";}}s:30:\"seopress_breadcrumbs_i18n_here\";s:0:\"\";s:30:\"seopress_breadcrumbs_i18n_home\";s:0:\"\";s:32:\"seopress_breadcrumbs_i18n_author\";s:0:\"\";s:29:\"seopress_breadcrumbs_i18n_404\";s:0:\"\";s:32:\"seopress_breadcrumbs_i18n_search\";s:20:\"Zoekresultaten voor:\";s:36:\"seopress_breadcrumbs_i18n_no_results\";s:24:\"Geen resultaten gevonden\";s:37:\"seopress_breadcrumbs_i18n_attachments\";s:0:\"\";s:31:\"seopress_breadcrumbs_i18n_paged\";s:0:\"\";s:38:\"seopress_breadcrumbs_separator_disable\";s:1:\"1\";s:15:\"seopress_ps_url\";s:19:\"https://brave.local\";s:19:\"seopress_ps_api_key\";s:0:\"\";s:23:\"seopress_gsc_date_range\";s:10:\"- 3 months\";s:20:\"seopress_robots_file\";s:0:\"\";s:18:\"seopress_llms_file\";s:342:\"# {{site_name}}\r\n\r\n> {{site_description}}\r\n> Last updated: {{current_date}}\r\n\r\n## Search\r\n\r\n- Search URL: `{{search_url}}`\r\n\r\n## Recent Content\r\n\r\n{{latest_posts:5}}\r\n\r\n## Complete Sitemap\r\n\r\nFor a comprehensive list of all URLs, see: {{sitemap_url}}\r\n\r\n---\r\n\r\n*This file is dynamically generated and highlights our most important content.*\r\n\";s:18:\"seopress_news_name\";s:0: