\":\"backend\",\"label\":\"Limit Login Attempts: check of de GDPR optie aanstaat\",\"checked\":false,\"relevant\":true},\"gravityforms_disable_auto_updates\":{\"section\":\"installation_subsite\",\"category\":\"backend\",\"label\":\"Gravity Forms: zet de optie automatische updates uit\",\"checked\":false,\"relevant\":true},\"gravityforms_language_dutch\":{\"section\":\"installation_subsite\",\"category\":\"backend\",\"label\":\"Gravity Forms: check of de taal Nederlands is\",\"checked\":false,\"relevant\":true},\"change_admin_password\":{\"section\":\"installation_always\",\"category\":\"backend\",\"label\":\"Verander het wachtwoord van de admin\\/beheerder (minimaal 20 characters)\",\"checked\":false,\"relevant\":true},\"credentials_shared_accept\":{\"section\":\"installation_always\",\"category\":\"backend\",\"label\":\"Gebruiker en wachtwoord staat in de wachtwoordmanager\",\"checked\":false,\"relevant\":true},\"disable_multisite_registration\":{\"section\":\"installation_always\",\"category\":\"backend\",\"label\":\"Multisite: zet registratiemelding uit\",\"checked\":false,\"relevant\":true},\"set_multisite_upload_limit\":{\"section\":\"installation_always\",\"category\":\"backend\",\"label\":\"Multisite: stel \'Maximale upload bestandsgrootte\' in op 70000 KB\",\"checked\":false,\"relevant\":true},\"allow_multisite_csv_upload\":{\"section\":\"installation_always\",\"category\":\"backend\",\"label\":\"Multisite: voeg CSV toe aan de lijst \'Upload bestandstypen\'\",\"checked\":false,\"relevant\":true},\"enable_imagify_network\":{\"section\":\"installation_always\",\"category\":\"backend\",\"label\":\"Multisite: activeer Imagify op netwerkniveau en zet de opties backup afbeeldingen en webp afbeeldingen uit\",\"checked\":false,\"relevant\":true},\"cleanup_templates\":{\"section\":\"pre_delivery_pm\",\"category\":\"frontend\",\"label\":\"Verwijder ongebruikte templates en componenten\",\"checked\":false,\"relevant\":true},\"check_404_page\":{\"section\":\"pre_delive