nt\":true},\"browser_tests\":{\"section\":\"pre_delivery_pm\",\"category\":\"frontend\",\"label\":\"Browsertest (Firefox, Safari, iOS Safari en Android Chrome)\",\"checked\":false,\"relevant\":true},\"remove_yard_dummy_content\":{\"section\":\"pre_go_live\",\"category\":\"frontend\",\"label\":\"Verwijder Yard dummy content\",\"checked\":false,\"relevant\":true},\"configure_readspeaker\":{\"section\":\"pre_go_live\",\"category\":\"frontend\",\"label\":\"Configureer Readspeaker (Customer ID: https:\\/\\/admin.readspeaker.com\\/portal\\/)\",\"checked\":false,\"relevant\":true},\"gdpr_cookie_consent\":{\"section\":\"pre_go_live\",\"category\":\"frontend\",\"label\":\"CookieYes: instellen\",\"checked\":false,\"relevant\":true},\"update_gravityforms_admin_email\":{\"section\":\"pre_go_live\",\"category\":\"frontend\",\"label\":\"Gravity Forms: {admin_mail} veranderen naar e-mailadres van klant\",\"checked\":false,\"relevant\":true},\"add_fontawesome_kit_domain\":{\"section\":\"pre_go_live\",\"category\":\"backend\",\"label\":\"Voeg het domein toe aan de FontAwesome Kit\",\"checked\":false,\"relevant\":true},\"plugins_up_to_date\":{\"section\":\"pre_go_live\",\"category\":\"backend\",\"label\":\"Alle plugins zijn up-to-date\",\"checked\":false,\"relevant\":true},\"credentials_shared_live\":{\"section\":\"pre_go_live\",\"category\":\"backend\",\"label\":\"Voeg domeinen toe in de wachtwoordmanager\",\"checked\":false,\"relevant\":true},\"configure_sentry\":{\"section\":\"pre_go_live\",\"category\":\"backend\",\"label\":\"Voeg site toe aan Sentry en sentry_dsn aan env file\",\"checked\":false,\"relevant\":true},\"setup_cronjobs\":{\"section\":\"pre_go_live\",\"category\":\"backend\",\"label\":\"Cronjobs instellen op server\",\"checked\":false,\"relevant\":true},\"configure_nginx_vhost\":{\"section\":\"pre_go_live\",\"category\":\"backend\",\"label\":\"Configureer NGINX vhost\",\"checked\":false,\"relevant\":true},\"configure_security_txt\":{\"section\":\"pre_go_live\",\"categ