(9394, 'edd_sl_921753b5a9bcbc9dc1fd54565fac51b2', 'a:2:{s:7:\"timeout\";i:1781526481;s:5:\"value\";s:110086:\"{\"name\":\"SearchWP 4\",\"new_version\":\"4.5.9\",\"stable_version\":\"4.5.9\",\"sections\":{\"description\":\"\",\"changelog\":\"<p>4.5.9<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Corrected typo in source-specific highlighting hook name `searchwp\\\\source\\\\{$source_name}\\\\do_highlighting`.<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic conflict with stemming.<\\/li>\\n<\\/ul>\\n<p>4.5.8<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added voice search to Search Forms.<\\/li>\\n<li><strong>[New]<\\/strong> Added support for shortcodes in the Promoted Ads content.<\\/li>\\n<li><strong>[Fix]<\\/strong> Unexpected results when the Split Pattern Keywords option is enabled in same cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Advanced search form filters (category, tag, author, post type) not applied when loading more results via AJAX.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Forms post-type filter not displayed if the engine sources are not listed in the forms settings.<\\/li>\\n<\\/ul>\\n<p>4.5.7<\\/p>\\n<ul>\\n<li><strong>[Update]<\\/strong> Updated embed wizard tooltips for better visibility.<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic not respected in some cases when synonyms are involved.<\\/li>\\n<li><strong>[Fix]<\\/strong> Deprecation notices on PHP 8.3+.<\\/li>\\n<\\/ul>\\n<p>4.5.6<\\/p>\\n<ul>\\n<li><strong>[Update]<\\/strong> Updated compatibility with WordPress 6.9.<\\/li>\\n<li><strong>[Change]<\\/strong> If a result has no permalink, the Read More link is not displayed, and the result tile will have no link.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP type error in some edge cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Engine Rule\'s value overflowing the parent container.<\\/li>\\n<li><strong>[Fix]<\\/strong> Relevance miscalculated when filtering by taxonomy term in some cases.<\\/li>\\n<\\/ul>\\n<p>4.5.5<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Pro extensions cannot be activated with the All Access Bundle license.<\\/li>\\n<li><strong>[Update]<\\/strong> Updated admin notifications to reflect new license types.<\\/li>\\n<li><strong>[Update]<\\/strong> Updated Translation files.<\\/li>\\n<\\/ul>\\n<p>4.5.4<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added support for All Access Bundle license.<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic not respected in some cases.<\\/li>\\n<\\/ul>\\n<p>4.5.3<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Fixed compatibility with PHP 7.4.<\\/li>\\n<\\/ul>\\n<p>4.5.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added Template option to open search result links on a new tab\\/window.<\\/li>\\n<li><strong>[New]<\\/strong> Added Template option to link media files directly instead of the attachment page.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Forms setting \'Type of search\' is empty by default to allow searches on all engine sources.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Forms setting \'Type of search\' updates automatically when the Engine setting is changed.<\\/li>\\n<li><strong>[Improvement]<\\/strong> The highlighter now prioritizes exact phrases if they are present.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Generate fallback excerpt for attachments.<\\/li>\\n<li><strong>[Change]<\\/strong> The Diagnostics \'List Unindexed Entries\' feature now also displays entries excluded using the Exclude UI extension.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting not working with the taxonomy source.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting not working on PDF content if some special characters are part of the text.<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms not working with words with accented letters.<\\/li>\\n<li><strong>[Fix]<\\/strong> Closest match output notice placement on FSE themes.<\\/li>\\n<li><strong>[Fix]<\\/strong> Corrected action hook for debug logging.<\\/li>\\n<li><strong>[Fix]<\\/strong> Target page field in Search Forms settings not saving the correct page in some cases.<\\/li>\\n<\\/ul>\\n<p>4.5.1<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> SearchWP embed Wizard appears in admin pages if the block editor is disabled.<\\/li>\\n<\\/ul>\\n<p>4.5.0<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added elements for Search Forms and Results templates for Elementor, Divi, Oxygen, Breakdance, Bricks, WPBakery, Beaver Builder.<\\/li>\\n<li><strong>[New]<\\/strong> Promoted Search Ads.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Add ARIA attributes to search forms.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved Forms and Results template embed wizard.<\\/li>\\n<li><strong>[Change]<\\/strong> Renamed the editor form block to \\\"SearchWP Form\\\".<\\/li>\\n<li><strong>[Fix]<\\/strong> Deprecation notices in the block editor.<\\/li>\\n<li><strong>[Fix]<\\/strong> JS error due to a malformed SVG path.<\\/li>\\n<li><strong>[Fix]<\\/strong> jQuery Migrate notices.<\\/li>\\n<li><strong>[Fix]<\\/strong> Corrected typo in some notification strings.<\\/li>\\n<li><strong>[Fix]<\\/strong> Choices.js deprecation notices on some settings pages.<\\/li>\\n<li><strong>[Fix]<\\/strong> HTML tags appear in the excerpt generated from the WooCommerce short product description.<\\/li>\\n<\\/ul>\\n<p>4.4.0<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added multiple results templates.<\\/li>\\n<li><strong>[New]<\\/strong> Added Gutenberg block, shortcode and PHP function for SearchWP Results templates.<\\/li>\\n<li><strong>[New]<\\/strong> Integrated Diagnostics extension into the core plugin.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Minified frontend assets.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Removed Next\\/Previous labels from pagination if pagination uses boxed or circular style.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when Engine Rule target a non-existent taxonomy.<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted\\/Phrase searches working only from main site on a multisite installation.<\\/li>\\n<li><strong>[Fix]<\\/strong> Unclosed &lt;select&gt; tag in Search Forms Advanced Search.<\\/li>\\n<\\/ul>\\n<p>4.3.18<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Quoted\\/phrase searches are now supported on multisite searches.<\\/li>\\n<li><strong>[New]<\\/strong> Added searchwp\\\\source\\\\comment\\\\disable_weight_transfer filter to disable Comment weight transfer.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved Comments Source notice for clarity.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Retry license status check before deactivation on failure.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved exact matches buoy performance and results.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved performance of quoted\\/phrase searches.<\\/li>\\n<li><strong>[Update]<\\/strong> Removed use of deprecated MySQL query modifiers and functions.<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted\\/phrase search string output has redundant quotes in SearchWP template.<\\/li>\\n<li><strong>[Fix]<\\/strong> Duplicated highlighting tags in some cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Inconsistent results order when multiple results have the same relevance.<\\/li>\\n<\\/ul>\\n<p>4.3.17<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added SearchWP Source - WPForms to Extensions page.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Forms Author dropdown now supports authors from all post types.<\\/li>\\n<li><strong>[Update]<\\/strong> Block editor API version on Forms block.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighter prioritizing partial matches even when partial matches are disabled.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighter generating wrong excerpt if the text contains \'&lt;\' or \'&gt;\' characters.<\\/li>\\n<li><strong>[Fix]<\\/strong> Indexer pausing automatically in some cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Filter to disable Email Summaries not working from theme\'s functions.php file.<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.3.16 that prevented results from displaying in some cases when using the Divi Builder.<\\/li>\\n<li><strong>[Fix]<\\/strong> Block editor link search not working.<\\/li>\\n<li><strong>[Fix]<\\/strong> Javascript warning due to Exclude UI preview block in some installations.<\\/li>\\n<li><strong>[Fix]<\\/strong> Wrong license type recognition during activation in some rare cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Wrong license level displayed in bbPress missing integration notice.<\\/li>\\n<\\/ul>\\n<p>4.3.16<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Weekly Email Summaries.<\\/li>\\n<li><strong>[New]<\\/strong> Added option to set pagination labels for SearchWP Templates.<\\/li>\\n<li><strong>[New]<\\/strong> New filter to disable the Advanced Custom Fields suggestions in the Engine settings.<\\/li>\\n<li><strong>[New]<\\/strong> New Relevance tab in the Debugging Console showing relevance for every search result.<\\/li>\\n<li><strong>[Change]<\\/strong> Use field name if field label is not set for ACF fields in the Engine settings.<\\/li>\\n<li><strong>[Change]<\\/strong> \'searchwp\\\\index\\\\process\\\\enabled\' filter overrides the Pause Indexing setting.<\\/li>\\n<li><strong>[Change]<\\/strong> SWP_Query sorting prioritizes URL arguments, then request arguments, then defaults.<\\/li>\\n<li><strong>[Change]<\\/strong> Optimised Divi theme integration.<\\/li>\\n<li><strong>[Change]<\\/strong> Improved loading of Stopwords in the Global Settings page.<\\/li>\\n<li><strong>[Change]<\\/strong> Better performance for partial matches in some cases.<\\/li>\\n<li><strong>[Change]<\\/strong> Added multisite support to SearchWP Templates.<\\/li>\\n<li><strong>[Change]<\\/strong> Added responsive grid sizing to the results templates.<\\/li>\\n<li><strong>[Change]<\\/strong> Dropped support for legacy extensions asset loading.<\\/li>\\n<li><strong>[Fix]<\\/strong> Advanced Custom Fields repeatable children not indexed correctly.<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic not working if synonyms are capitalised or have accents.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error if Weight Transfer ID doesn\'t exit.<\\/li>\\n<li><strong>[Fix]<\\/strong> Ignore delta updates during WP All Import imports.<\\/li>\\n<li><strong>[Fix]<\\/strong> \\\"true\\\" and \\\"false\\\" search strings converted to boolean in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.15<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Improved license handling.<\\/li>\\n<li><strong>[Fix]<\\/strong> Indexer running even when paused in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.14<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Onboarding Wizard to simplify the initial setup.<\\/li>\\n<li><strong>[Change]<\\/strong> Added an attribute to Search Forms to support non-default engine in Live Ajax Search.<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP Results template supports Metrics click tracking.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> SearchWP Results template produces errors in some cases when working with custom sources.<\\/li>\\n<\\/ul>\\n<p>4.3.13<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Search Form with Default engine and Default results page produces no results in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.12<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Supplemental Engines with no custom Sources can use the Default results page in Search Forms.<\\/li>\\n<li><strong>[Fix]<\\/strong> Installation error on some systems triggered by hidden system files.<\\/li>\\n<\\/ul>\\n<p>4.3.11<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> PHP error in some admin pages.<\\/li>\\n<\\/ul>\\n<p>4.3.10<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Product education sections are added throughout the admin area to showcase available SearchWP features.<\\/li>\\n<li><strong>[New]<\\/strong> Deprecated extension notices are added to inform the admin and provide the alternatives.<\\/li>\\n<li><strong>[Change]<\\/strong> Numerous feature descriptions are rephrased to explain the features better.<\\/li>\\n<li><strong>[Change]<\\/strong> Documentation links are added to multiple features to provide additional context.<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP begins indexing website content automatically once activated for the first time.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Form doesn\'t show on the search page if manually included.<\\/li>\\n<li><strong>[Fix]<\\/strong> Posts are not dropped entirely from the index when taxonomies are updated.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error in some edge cases when Users are updated.<\\/li>\\n<\\/ul>\\n<p>4.3.9<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Moved the Source Author attribute for better UI\\/UX.<\\/li>\\n<li><strong>[Fix]<\\/strong> Call to undefined function mysql_get_server_info() error in WP 6.4.<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted searches not working on custom fields when wildcards are used.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighter not working with terms that include special characters in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.8<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Update Media Source labels to match WordPress labels.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reindex Media files when changes are made on Media Library quick edits.<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP results page empty search logic is changed to match the Default results page logic.<\\/li>\\n<li><strong>[Fix]<\\/strong> MySQL error if there are no valid tokens.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when attempting to encode cookies that store an array as its value.<\\/li>\\n<\\/ul>\\n<p>4.3.7<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Search Results page \'searchwp\' parameter interferes with the custom templates.<\\/li>\\n<\\/ul>\\n<p>4.3.6<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Customizable SearchWP Search Results page.<\\/li>\\n<li><strong>[Change]<\\/strong> Add Search Form setting to change button label.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when attempting to encode the cookies in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.5<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Make the Search Form button label translatable.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when a taxonomy term is updated if the taxonomy is an Engine source attribute.<\\/li>\\n<\\/ul>\\n<p>4.3.4<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Post Author added as an engine source attribute.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Added filter for Closest Match notice text.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Added support for SVG images.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Only log statistics for the first page of results.<\\/li>\\n<li><strong>[Change]<\\/strong> Exclude taxonomy sources from default new engine settings.<\\/li>\\n<li><strong>[Change]<\\/strong> Order results by relevance first and post date after on empty native searches.<\\/li>\\n<li><strong>[Change]<\\/strong> Add a specific notice to the Engines page when the indexer is paused.<\\/li>\\n<li><strong>[Update]<\\/strong> Documentation links.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error if a site uses cookies with forbidden characters.<\\/li>\\n<li><strong>[Fix]<\\/strong> Call to a member function on bool when using WP CLI commands.<\\/li>\\n<li><strong>[Fix]<\\/strong> Empty searches running slow.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP notice for deprecated use of stripos.<\\/li>\\n<li><strong>[Fix]<\\/strong> Invalid category console notice in block editor if Modal Form extension is inactive.<\\/li>\\n<li><strong>[Fix]<\\/strong> NOT IN condition on Media rules doesn\'t apply.<\\/li>\\n<\\/ul>\\n<p>4.3.3<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Taxonomy Source is added to the Engines configuration.<\\/li>\\n<li><strong>[Change]<\\/strong> Replace site_url with home_url in Search Form action on the frontend.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> Empty search queries are logged into the statistics.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting is not working if a searched keyword is followed by special characters in the original text.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Form \\\"Type of search\\\" setting affects search results only when Advanced Search is enabled.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Form is not rendering on search results page in some cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP notice on Search Form render if a category was saved in form settings but deleted from WP.<\\/li>\\n<li><strong>[Fix]<\\/strong> The whole excerpt gets highlighted on empty search if the \\\"Highlight Terms\\\" setting is enabled.<\\/li>\\n<\\/ul>\\n<p>4.3.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Embeddable Search Forms for a customized search experience<\\/li>\\n<li><strong>[Improvement]<\\/strong> Better handling of Synonyms partial matches<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP query runs for empty searches to adhere to engine restrictions<\\/li>\\n<\\/ul>\\n<p>4.3.1<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> \\\"Did you mean?\\\" feature prevents stemming from working<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic set via the filter allows OR results<\\/li>\\n<li><strong>[Fix]<\\/strong> Partial matches use a wildcard when it is not needed<\\/li>\\n<li><strong>[Fix]<\\/strong> ACF suggestions are missing from the Custom Fields dropdown in the Source Attributes modal<\\/li>\\n<li><strong>[Fix]<\\/strong> Settings in the Misc tab are not saving in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics page shows UI which cannot be used by users with Statistics capability<\\/li>\\n<li><strong>[Fix]<\\/strong> Notifications icon is shown to users who cannot use it because of capability restrictions<\\/li>\\n<li><strong>[Fix]<\\/strong> Minor styling issues in the plugin settings<\\/li>\\n<\\/ul>\\n<p>4.3.0<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Admin settings UI redesign<\\/li>\\n<\\/ul>\\n<p>4.2.9<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Debugging Console to view debugging data in a browser panel style<\\/li>\\n<li><strong>[Improvement]<\\/strong> Prevent page slowdown when a taxonomy term is updated<\\/li>\\n<li><strong>[Improvement]<\\/strong> Set default value for Post Excerpt weight to a minimum<\\/li>\\n<li><strong>[Improvement]<\\/strong> Updated Stemmer library for better keyword stemming and PHP 8 compatibility<\\/li>\\n<li><strong>[Improvement]<\\/strong> Updated PdfParser library for better PDF parsing<\\/li>\\n<li><strong>[Fix]<\\/strong> \\\"Vue is in development mode\\\" console notice on the Settings screen<\\/li>\\n<li><strong>[Fix]<\\/strong> Deprecation notices on PHP 8.2<\\/li>\\n<li><strong>[Fix]<\\/strong> Plugin text domain is not loading properly<\\/li>\\n<\\/ul>\\n<p>4.2.8<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> In-plugin notification system to get the latest updates from SearchWP<\\/li>\\n<\\/ul>\\n<p>4.2.7<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Highlighter gives precedence to exact phrase search if present<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduced memory usage when generating the excerpt<\\/li>\\n<li><strong>[Fix]<\\/strong> Stemming prevents partial matches in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting not working with quoted searches in some cases<\\/li>\\n<\\/ul>\\n<p>4.2.6<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Improved AJAX actions security<\\/li>\\n<li><strong>[Improvement]<\\/strong> Updated the PdfParser library for better PDF parsing and improved compatibility<\\/li>\\n<li><strong>[Fix]<\\/strong> Engines errors are not accessible by external code because of the private visibility<\\/li>\\n<li><strong>[Fix]<\\/strong> License gets deactivated periodically for some rare server configurations<\\/li>\\n<\\/ul>\\n<p>4.2.5<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Exclude taxonomy name from indexed taxonomy term fields<\\/li>\\n<li><strong>[Improvement]<\\/strong> Do not index the image src attribute in the post content by default<\\/li>\\n<li><strong>[Fix]<\\/strong> No post type exists check during SWP_Query query<\\/li>\\n<li><strong>[Fix]<\\/strong> Existing SWP_Query post type can be overridden with $_REQUEST<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms and stemming affecting AND logic query<\\/li>\\n<\\/ul>\\n<p>4.2.4<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Better handling of quoted phrases in synonyms<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms not working with non-ASCII strings<\\/li>\\n<li><strong>[Fix]<\\/strong> Max nesting function when synonyms are applied<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms are not case-insensitive<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms affecting the stemming functionality<\\/li>\\n<li><strong>[Fix]<\\/strong> Metrics related click tracking error in multisite environment<\\/li>\\n<li><strong>[Fix]<\\/strong> Merging words during HTML content tokenization if<br \\/>\\nis used in the content<\\/li>\\n<li><strong>[Fix]<\\/strong> Hiding SearchWP admin menu via the hook leaves a link to it in the admin bar menu<\\/li>\\n<li><strong>[Fix]<\\/strong> MySQL error if engine sources have no attributes<\\/li>\\n<li><strong>[Fix]<\\/strong> Error if \'s\' parameter in the request is not a string<\\/li>\\n<li><strong>[Fix]<\\/strong> Warning if a custom field is added to the Users in the engine settings<\\/li>\\n<li><strong>[Fix]<\\/strong> Return type compatibility notice in PHP 8.1 for jsonSerialize() method<\\/li>\\n<\\/ul>\\n<p>4.2.3<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Performance improvement when getting \'post__in\' and \'post__not_in\' ids<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms work incorrectly when AND search logic is applied<\\/li>\\n<li><strong>[Fix]<\\/strong> Posts are not dropped from the index when a taxonomy term is updated<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted searches give too broad results on custom fields<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted searches query has redundant subqueries<\\/li>\\n<li><strong>[Fix]<\\/strong> Cross-site search limited results if \\\"all\\\" is passed as site args<\\/li>\\n<\\/ul>\\n<p>4.2.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Extensions admin page to install, activate and deactivate SearchWP extensions in one click<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance improvement when getting engines configuration<\\/li>\\n<li><strong>[Fix]<\\/strong> Search terms highlighting doesn\'t work well with quoted searches<\\/li>\\n<li><strong>[Fix]<\\/strong> Posts are not dropped from the index when a taxonomy term is deleted from the site<\\/li>\\n<li><strong>[Fix]<\\/strong> Stemming prevents partial matches in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Search terms highlighting give unexpected results with partial matches<\\/li>\\n<\\/ul>\\n<p>4.2.1<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Edited document content is not preserved<\\/li>\\n<li><strong>[Fix]<\\/strong> Broken URLs for the redirects to the legacy admin settings<\\/li>\\n<li><strong>[Fix]<\\/strong> Class prefixing error in smalot\\/pdfparser lib<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP7 static code analyzer error in symfony\\/polyfill-mbstring lib<\\/li>\\n<\\/ul>\\n<p>4.2.0<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Plugin settings moved to the top-level menu<\\/li>\\n<li><strong>[Fix]<\\/strong> Undefined function error during the \'index\' CLI command execution<\\/li>\\n<li><strong>[Fix]<\\/strong> Merging words in some cases during HTML content tokenization<\\/li>\\n<\\/ul>\\n<p>4.1.22<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Synonym application too broad in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Document content reindexing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Missing method reference in Comment source<\\/li>\\n<li><strong>[Fix]<\\/strong> Forced phrase search returns no results if the search string doesn\'t contain non-phrase tokens<\\/li>\\n<li><strong>[Improvement]<\\/strong> Search string normalization<\\/li>\\n<li><strong>[Improvement]<\\/strong> String highlight application when synonyms are applied<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of double quotes in synonym logic in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.21<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Apply AND logic when applicable during quoted search query<\\/li>\\n<li><strong>[Fix]<\\/strong> Default application of \'Did you mean?\' functionality in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.1.19 that prevented some results from displaying in some cases<\\/li>\\n<li><strong>[New]<\\/strong> Filter searchwp\\\\native\\\\args\\\\post_type to modify native search post type when necessary<\\/li>\\n<\\/ul>\\n<p>4.1.20<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Synonym processing now stops after first application unless searchwp\\\\synonyms\\\\aggressive filter returns false<\\/li>\\n<li><strong>[Fix]<\\/strong> Global excerpt and highlighting process now uses original search string, disregarding any filtration in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.19<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Consider Excerpt when performing quoted search<\\/li>\\n<li><strong>[Fix]<\\/strong> Multisite re\\/index using WP-CLI<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlight application with flanking punctuation in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlight application with stemming enabled in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP 8 compatibility<\\/li>\\n<li><strong>[New]<\\/strong> de_DE_formal translation<\\/li>\\n<li><strong>[Update]<\\/strong> Dependencies<\\/li>\\n<\\/ul>\\n<p>4.1.18<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Global excerpt generation due to newline<\\/li>\\n<li><strong>[Fix]<\\/strong> Relevance minimum clause implementation<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevent search suggestion output outside main query<\\/li>\\n<li><strong>[Fix]<\\/strong> Incorrect fields argument definition in some cases (caused FacetWP facets to not render in some cases)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Highlight matching in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.17<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added relevance() method to Mods to allow additional manipulation of relevance calculation during searches<\\/li>\\n<li><strong>[Improvement]<\\/strong> Refactored WP All Import integration<\\/li>\\n<li><strong>[Fix]<\\/strong> Character encoding when finding global excerpts in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.16<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> searchwp\\\\index\\\\source\\\\add_hooks filter to allow prevention of core hook implementation<\\/li>\\n<li><strong>[New]<\\/strong> Integration with WP All Import to better react to import processes<\\/li>\\n<li><strong>[Improvement]<\\/strong> Global excerpt generation in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer state handling when programmatically pausing\\/unpausing<\\/li>\\n<li><strong>[Fix]<\\/strong> Searching Media in the WordPress Admin in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling (omitting) of entries that failed indexing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics migration from SearchWP 3 (if Statistics failed to migrate, please open a support ticket for direct assistance)<\\/li>\\n<\\/ul>\\n<p>4.1.15<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Partial matching in synonyms has been changed, to apply partial matching add a * wildcard where partial matching should be applied<\\/li>\\n<li><strong>[Change]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Global excerpt generation in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.1.12 that prevented results in some cases when setting AND logic to be strict<\\/li>\\n<\\/ul>\\n<p>4.1.14<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[New]<\\/strong> Rule for Media to consider filename<\\/li>\\n<li><strong>[New]<\\/strong> Rule for Pages and hierarchical CPTs to consider ancestry<\\/li>\\n<li><strong>[New]<\\/strong> Rule for Pages and hierarchical CPTs to consider post_parent<\\/li>\\n<li><strong>[New]<\\/strong> Edit and View actions for omitted entries<\\/li>\\n<li><strong>[New]<\\/strong> Support for Beaver Builder Search Module<\\/li>\\n<li><strong>[Fix]<\\/strong> Parallel indexing process when rebuilding index using WP-CLI in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Customization of post stati in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Additional background process health check<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of synonym input strings in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Default regular expression patterns<\\/li>\\n<li><strong>[Update]<\\/strong> Dependencies<\\/li>\\n<\\/ul>\\n<p>4.1.13<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Admin search of hierarchical post types<\\/li>\\n<li><strong>[Fix]<\\/strong> Support ticket iframe height minimum in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Partial match logic in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.12<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[New]<\\/strong> Upper threshold that prevents AND logic when too many terms make it a performance issue (default is 5 token groups)<\\/li>\\n<li><strong>[New]<\\/strong> Filter searchwp\\\\query\\\\logic\\\\and\\\\token_threshold to control AND logic token threshold (return false to disable threshold consideration)<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with searching Users in the WP Admin<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with setting query fields in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics CSS issue in Safari in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.11<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.1.9 that prevented saving parent weight transfer<\\/li>\\n<li><strong>[Improved]<\\/strong> PDF parsing in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.10<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Background process cookie validation in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.9<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduction in index bloat in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Comment parents being incorrectly returned in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when weight transfer was enabled but no recipient defined<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when using PHP8 in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.8<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Race condition prevention in background process<\\/li>\\n<li><strong>[Change]<\\/strong> Index controller no longer observes site switching, if switching sites you will need to first use the searchwp\\\\auto_update_providers hook<\\/li>\\n<li><strong>[Change]<\\/strong> Keyword stemming enabled by default during setup<\\/li>\\n<li><strong>[Fix]<\\/strong> Results when keyword stemming and partial matching is enabled and tokens are exact matches and stemmable<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics migration from SearchWP 3 in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Automatic integration with page builder plugin in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with ACF Repeatables not appearing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with not being able to add custom Custom Field keys to an Engine Source<\\/li>\\n<\\/ul>\\n<p>4.1.7<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Multisite performance issue that could lead to an Error in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics migration from SearchWP v3 (Regression introduced in 4.1.0)<\\/li>\\n<\\/ul>\\n<p>4.1.6<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Database table index optimization introduced in 4.1.5 in some configurations<\\/li>\\n<li><strong>[Fix]<\\/strong> Partial matches with stemming enabled during AND logic in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> AND logic handling in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.5<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Exact match buoy in partial match logic<\\/li>\\n<li><strong>[Fix]<\\/strong> Implementation of query when site is set to \'all\' to search all network sites<\\/li>\\n<li><strong>[Improvement]<\\/strong> Partial match logic<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of invalid tokens when finding partial matches<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance when applying delta index updates<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance when dropping Entries<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of duplicate tokens in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Native integration in non-standard environments (e.g. page builders)<\\/li>\\n<\\/ul>\\n<p>4.1.4<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Error during partial match application on synonyms in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Admin search handling in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.3<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonym partial matches in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics display with Statistics capability but not Settings capability<\\/li>\\n<li><strong>[Fix]<\\/strong> HTTP Basic Auth credentials regression introduced in 4.1.0<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic performance regression introduced in 4.1.0 in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> AND logic performance in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Background process health check coverage<\\/li>\\n<li><strong>[Improvement]<\\/strong> PHP 8 compatibility<\\/li>\\n<\\/ul>\\n<p>4.1.2<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer handling of concurrent invocations, health check\\/restart when process encounters Errors<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer in multisite environment<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic restrictions in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.1<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when highlighting in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.0<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[New]<\\/strong> Refactored indexer for stability, reliability, and performance optimization<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\index\\\\update_entry action when an Entry is updated in the Index<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\debug\\\\front_end_summary filter to control whether the HTML comment summary is output when debugging is enabled<\\/li>\\n<li><strong>[New]<\\/strong> wp searchwp reindex WP-CLI command<\\/li>\\n<li><strong>[New]<\\/strong> wp searchwp diagnostics WP-CLI command<\\/li>\\n<li><strong>[New]<\\/strong> Primary keys added to database tables <em>for new installs<\\/em> where previously there were none<\\/li>\\n<li><strong>[New]<\\/strong> Adds $query property to \\\\SWP_Query to reference underlying query object<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\source\\\\comment\\\\parent_attribution\\\\strict hook to control whether SearchWP is strict about parent attribution which can introduce overhead in some cases<\\/li>\\n<li><strong>[New]<\\/strong> SearchWP will now generate more expected variations of regex pattern matches<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\tokens\\\\generate_parttern_match_variations filter to control whether additional pattern match variations are generated during indexing<\\/li>\\n<li><strong>[New]<\\/strong> Ability to enter custom ignored queries for Statistics (with wildcard * support)<\\/li>\\n<li><strong>[New]<\\/strong> Ability to automatically trim Statistics logs<\\/li>\\n<li><strong>[New]<\\/strong> Notice when WordPress available memory can be improved<\\/li>\\n<li><strong>[New]<\\/strong> Export\\/import now optionally includes Settings, Stopwords, and Synonyms<\\/li>\\n<li><strong>[New]<\\/strong> All ACF fields are displayed in the Custom Fields dropdown when applicable, not only ACF \\\"Repeatables\\\"<\\/li>\\n<li><strong>[New]<\\/strong> Synonyms actions: Sort ASC, Sort DESC, Clear<\\/li>\\n<li><strong>[Change]<\\/strong> Refines default data indexed for Taxonomy Terms to be: taxonomy name, term name, term slug, and term description<\\/li>\\n<li><strong>[Change]<\\/strong> Abstracts Statistics Dashboard Widget from jquery-ui-tabs<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer auto-scaling when server load is high<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of HTML-formed content during indexing<\\/li>\\n<li><strong>[Improvement]<\\/strong> Integration of partial matches and keyword stemming<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer delta trigger specificity in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Document processing handling, footprint<\\/li>\\n<li><strong>[Improvement]<\\/strong> Highlighting when a suggested search has been returned<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevent duplicate results during weight transfer in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic restriction, performance in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Persistent dismissal of missing integration notice<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms management in some cases<\\/li>\\n<li><strong>[Update]<\\/strong> Dependencies<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<li><strong>[Update]<\\/strong> Interface updates and refinements<\\/li>\\n<\\/ul>\\n<p>4.0.34<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Fixes regression introduced by Shortcodes fix in 4.0.33 (proper fix in Shortcodes 1.8.2)<\\/li>\\n<li><strong>[Update]<\\/strong> Updated updater<\\/li>\\n<\\/ul>\\n<p>4.0.33<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> searchwp\\\\swp_query\\\\mods filter to add Mods to SWP_Query<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP Warning introduced in 4.0.32<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevention of duplicate indexing processes in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Display issue on Statistics screen<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP Warning when Admin color schemes have been removed<\\/li>\\n<li><strong>[Fix]<\\/strong> PDF parsing taking place unnecssarily in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Disable searchwp_search_results Shortcode when generating excerpts so as to prevent unwanted loop<\\/li>\\n<\\/ul>\\n<p>4.0.32<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Duplicate indexer processes in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Inaccurate batch size handling in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevent redundant search suggestion output in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Post stati validation when parent attribution is enabled<\\/li>\\n<li><strong>[Improvement]<\\/strong> Attachment status handling over time<\\/li>\\n<li><strong>[New]<\\/strong> RAND(seed) support by suffixing random Mod order_by with a colon and seed e.g. random:10 will be RAND(10)<\\/li>\\n<\\/ul>\\n<p>4.0.31<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Adds NOT IN option to Media File Type Rule<\\/li>\\n<li><strong>[Improvement]<\\/strong> Debug HTML comment block output during Admin requests<\\/li>\\n<li><strong>[Fix]<\\/strong> Custom Attribute Options not returning proper Label after saving<\\/li>\\n<li><strong>[Fix]<\\/strong> Relocate searchwp\\\\query\\\\search_string hook to fire earlier<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue when performing cross-site Multisite search<\\/li>\\n<li><strong>[Fix]<\\/strong> searchwp\\\\query\\\\tokens\\\\limit default value<\\/li>\\n<li><strong>[New]<\\/strong> Action searchwp\\\\query\\\\core_mods_out_of_bounds fires when core Mods are considered out of bounds<\\/li>\\n<\\/ul>\\n<p>4.0.30<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> UI changes introduced by WordPress 5.5<\\/li>\\n<li><strong>[Fix]<\\/strong> Global excerpt generation from search suggestions<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonym migration from SearchWP 3.x<\\/li>\\n<\\/ul>\\n<p>4.0.29<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Token handling in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Document content handling when using alternate indexer in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Tokenization of HTML in some cases<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\entry\\\\update_data\\\\before action fired before Entry data is retrieved<\\/li>\\n<li><strong>[Update]<\\/strong> Bundle dependencies<\\/li>\\n<\\/ul>\\n<p>4.0.28<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Prevent inapplicable comment edit events from triggering delta updates<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduced index method checks<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reactivity when observing meta updates<\\/li>\\n<\\/ul>\\n<p>4.0.27<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> File Content meta box display in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Entries not being reintroduced after failing when using alternate indexer<\\/li>\\n<li><strong>[Fix]<\\/strong> Display of Source Attribute Options when statically defined<\\/li>\\n<li><strong>[Fix]<\\/strong> UI display edge cases<\\/li>\\n<li><strong>[Change]<\\/strong> Token handling chunked in more cases so as to avoid issues when hosts limit query character length<\\/li>\\n<\\/ul>\\n<p>4.0.26<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Handling of SWP_Query tax_query argument<\\/li>\\n<li><strong>[New]<\\/strong> Advanced setting checkbox to control whether stored document content is purged and re-indexed during index rebuilds<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<\\/ul>\\n<p>4.0.25<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.0.24 when utilizing PDF Metadata<\\/li>\\n<li><strong>[Improvement]<\\/strong> Note displayed in SearchWP Document Content meta box when document is queued but not yet processed<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<\\/ul>\\n<p>4.0.24<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Handling of PDF metadata that includes invalid characters<\\/li>\\n<li><strong>[Fix]<\\/strong> Searching of hierarchical post types in the Admin<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance when handling documents outside the indexing process<\\/li>\\n<li><strong>[Update]<\\/strong> Bundle dependencies<\\/li>\\n<\\/ul>\\n<p>4.0.23<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Utilize previously extracted PDF metadata instead of parsing it repeatedly<\\/li>\\n<li><strong>[Change]<\\/strong> Updated default batch size for Media to 3, can be customized with searchwp\\\\indexer\\\\batch_size\\\\post.attachment hook<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of urlencoded tokens in some cases<\\/li>\\n<\\/ul>\\n<p>4.0.22<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Query parameter support for post_type when using SWP_Query (additional parameter support is planned)<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with partial matching yielding zero results in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted search support for WP_Post Content, Document Content<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduced debug log volume (logs should be deleted once you\'re done debugging)<\\/li>\\n<\\/ul>\\n<p>4.0.20<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> New filter searchwp\\\\source\\\\post\\\\db_where to customize global WHERE limits per post type<\\/li>\\n<li><strong>[New]<\\/strong> License key is automatically activated when provided via constant or hook<\\/li>\\n<li><strong>[Fix]<\\/strong> Error on uninstall when removing all data<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue where Mods were not applied to SWP_Query in some cases<\\/li>\\n<li><strong>[Change]<\\/strong> No longer relying on excerpt_more when working with excerpts, now using ellipsis filtered by searchwp\\\\utils\\\\excerpt_more<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of rare cases where index would need to be woken up repeatedly in order to build<\\/li>\\n<li><strong>[Improvement]<\\/strong> Omits redundant Entry retrieval in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Significant performance retrieval when generating excerpts (e.g. Highlighting)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Advanced Custom Fields integration support<\\/li>\\n<\\/ul>\\n<p>4.0.19<\\/p>\\n<ul>\\n<li><strong>[Notice]<\\/strong> Mods have in part been cleaned up and refined in this release, which may affect your usage. Please review any Mods you are using by testing this update on a staging server. If you are manipulating relevance weight based on date, it is likely you will need to update your hooks. Snippets have been updated on the KB article <a href=\\\"https:\\/\\/searchwp.com\\/?p=222848\\\">https:\\/\\/searchwp.com\\/?p=222848<\\/a> for review. Please also ensure your SearchWP Extensions are up to date as well.<\\/li>\\n<li><strong>[Fix]<\\/strong> Source Mod WHERE clauses causing errors in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Raw Mod WHERE clauses had no local alias to utilize<\\/li>\\n<li><strong>[Fix]<\\/strong> Mod JOIN claus order was not retained causing errors in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Optimized Mod handling in SWP_Query<\\/li>\\n<li><strong>[Improvement]<\\/strong> Disable integration extension checks when doing AJAX<\\/li>\\n<\\/ul>\\n<p>4.0.18<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Error when using mod argument of \\\\SearchWP\\\\Query parameters array<\\/li>\\n<li><strong>[Improvement]<\\/strong> Control over Settings page navigation<\\/li>\\n<\\/ul>\\n<p>4.0.17<\\/p>\\n<ul>\\n<li><strong>[Note]<\\/strong> Rebuilding your index using the Rebuild Index button on the Engines tab of the SearchWP settings screen is recommended after updating<\\/li>\\n<li><strong>[Fix]<\\/strong> Delta update regression introduced in 4.0.13<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when applying delta update to Source that no longer exists<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of delta update process during failures<\\/li>\\n<li><strong>[Improvement]<\\/strong> Delta update queue handling during index rebuild<\\/li>\\n<\\/ul>\\n<p>4.0.16<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Invalid range in character class introduced in 4.0.15 for PHP 7.3+<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\tokens\\\\whitelist\\\\only_full_matches retagged as searchwp\\\\tokens\\\\regex_patterns\\\\only_full_matches<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\tokens\\\\apply_rules_to_whitelist retagged as searchwp\\\\tokens\\\\apply_rules_to_pattern_matches<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\tokens\\\\whitelist_regex_patterns retagged as searchwp\\\\tokens\\\\regex_patterns<\\/li>\\n<li><strong>[Change]<\\/strong> Regex pattern matches are now tokenized during indexing (but remain exclusive when searching by default when applicable)<\\/li>\\n<li><strong>[New]<\\/strong> Filter searchwp\\\\tokens\\\\tokenize_pattern_matches\\\\indexing to disable new tokenizing of pattern match behavior during indexing<\\/li>\\n<\\/ul>\\n<p>4.0.15<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> New filter searchwp\\\\tokens\\\\string to customize strings before tokenization<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of synonyms when finding partial matches<\\/li>\\n<li><strong>[Fix]<\\/strong> Implementation and handling of regex pattern match tokenization setting<\\/li>\\n<li><strong>[Improvement]<\\/strong> Dash\\/hyphen and word match regex patterns<\\/li>\\n<li><strong>[Improvement]<\\/strong> searchwp\\\\source\\\\post\\\\excerpt_haystack filter now passes arguments array<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<\\/ul>\\n<p>4.0.14<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where partial matches from keyword stems were not found in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Partial match token processing limited to applicable site(s)<\\/li>\\n<li><strong>[Fix]<\\/strong> Excerpt generation when handling unregistered Shortcodes<\\/li>\\n<\\/ul>\\n<p>4.0.13<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Delta update routine when using alternate indexer that caused unwanted exit<\\/li>\\n<li><strong>[Fix]<\\/strong> <strong>searchwp\\\\document\\\\content<\\/strong> implementation<\\/li>\\n<li><strong>[Improvement]<\\/strong> Index integrity check when rebuilding<\\/li>\\n<li><strong>[Improvement]<\\/strong> Source hook management in multisite<\\/li>\\n<li><strong>[Improvement]<\\/strong> Upgrade routine process<\\/li>\\n<\\/ul>\\n<p>4.0.12<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Inability to filter searchwp\\\\settings\\\\capability<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with Highlighting in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Document Content not properly considered for global excerpt in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Warning when reacting to invalid Entry during indexing<\\/li>\\n<li><strong>[Fix]<\\/strong> Namespace issue with PDF parsing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Unnecessary provider reset when switching to the same site in multisite<\\/li>\\n<li><strong>[Update]<\\/strong> Updated updater<\\/li>\\n<\\/ul>\\n<p>4.0.11<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Loss of tokens when applying partial match logic in some cases<\\/li>\\n<li><strong>[Update]<\\/strong> Revised MySQL minimum to 5.6 (MariaDB 10.0) because of utf8mb4_unicode_520_ci collation requirement<\\/li>\\n<\\/ul>\\n<p>4.0.9<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.0.6 that prevented non WP_Post results from returning<\\/li>\\n<\\/ul>\\n<p>4.0.8<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where taxonomy Rules for Media were not applied correctly in some cases<\\/li>\\n<\\/ul>\\n<p>4.0.7<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Mod WHERE clauses not restricted to Source when defined<\\/li>\\n<\\/ul>\\n<p>4.0.6<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Post is now returned when parent weight transfer is enabled but Post has no post_parent<\\/li>\\n<li><strong>[Improvement]<\\/strong> Excerpt handling for native results<\\/li>\\n<li><strong>[Improvement]<\\/strong> Additional prevention of invalid WP_Post results being returned in one case<\\/li>\\n<\\/ul>\\n<p>4.0.5<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Filter to control stemmer locale searchwp\\\\stemmer\\\\locale<\\/li>\\n<li><strong>[Improvement]<\\/strong> Token stems\\/partial matches are considered during AND logic pass<\\/li>\\n<li><strong>[Fix]<\\/strong> String not sent to searchwp\\\\stemmer\\\\custom<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\query\\\\partial_matches\\\\buoy is now opt-in<\\/li>\\n<\\/ul>\\n<p>4.0.4<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where AND logic would not apply in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue where additional unnecessary query clauses are added in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with delta updates not processing when HTTP Basic Auth is active<\\/li>\\n<li><strong>[Fix]<\\/strong> Minimum PHP version requirement check (which is 7.2)<\\/li>\\n<\\/ul>\\n<p>4.0.3<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where tokens table was not reset during index rebuild<\\/li>\\n<\\/ul>\\n<p>4.0.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Support for BETWEEN, NOT BETWEEN, LIKE, and NOT LIKE compare operators for Mod WHERE clauses<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of Mod WHERE clauses in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of REST parameters when returning search results<\\/li>\\n<\\/ul>\\n<p>4.0.1<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Check for remnants of SearchWP 3 that were not removed as per the Migration Guide<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\source\\\\post\\\\attributes\\\\comments action when retrieving Post comments<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of empty search strings in some cases<\\/li>\\n<\\/ul>\\n<p>4.0.0<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Complete rewrite of SearchWP<\\/li>\\n<\\/ul>\\n\"},\"license_check\":\"\",\"msg\":\"\",\"homepage\":\"https:\\/\\/searchwp.com\\/downloads\\/searchwp-4\\/\",\"package\":\"https:\\/\\/searchwp.com\\/edd-sl\\/package_download\\/MTc4MTYzMDg4MTo4ZDJkMGYxYzRmMjliODUwOTM5MzIzYjBmOTEzZjMyMzoyMTYwMjk6Y2EwMDNmOTAwYjgwYjJlNzYzY2Y1MGNiYTJjNzkxYjE6aHR0cHNALy9icmF2ZS53cGFjYzAxLnlhcmQubmw6MA==\",\"icons\":{\"1x\":\"https:\\/\\/searchwp.com\\/wp-content\\/uploads\\/2021\\/02\\/avatar-searchwp-alt-128x128.png\",\"2x\":\"https:\\/\\/searchwp.com\\/wp-content\\/uploads\\/2021\\/02\\/avatar-searchwp-alt-256x256.png\"},\"banners\":{\"high\":\"\",\"low\":\"\"},\"slug\":\"index\",\"url\":\"https:\\/\\/searchwp.com\\/downloads\\/searchwp-4\\/?changelog=1\",\"last_updated\":\"2026-03-26 13:10:39\",\"download_link\":\"https:\\/\\/searchwp.com\\/edd-sl\\/package_download\\/MTc4MTYzMDg4MTo4ZDJkMGYxYzRmMjliODUwOTM5MzIzYjBmOTEzZjMyMzoyMTYwMjk6Y2EwMDNmOTAwYjgwYjJlNzYzY2Y1MGNiYTJjNzkxYjE6aHR0cHNALy9icmF2ZS53cGFjYzAxLnlhcmQubmw6MA==\",\"requires_php\":\"5.6.0\",\"description\":[\"\"],\"changelog\":[\"<p>4.5.9<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Corrected typo in source-specific highlighting hook name `searchwp\\\\source\\\\{$source_name}\\\\do_highlighting`.<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic conflict with stemming.<\\/li>\\n<\\/ul>\\n<p>4.5.8<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added voice search to Search Forms.<\\/li>\\n<li><strong>[New]<\\/strong> Added support for shortcodes in the Promoted Ads content.<\\/li>\\n<li><strong>[Fix]<\\/strong> Unexpected results when the Split Pattern Keywords option is enabled in same cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Advanced search form filters (category, tag, author, post type) not applied when loading more results via AJAX.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Forms post-type filter not displayed if the engine sources are not listed in the forms settings.<\\/li>\\n<\\/ul>\\n<p>4.5.7<\\/p>\\n<ul>\\n<li><strong>[Update]<\\/strong> Updated embed wizard tooltips for better visibility.<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic not respected in some cases when synonyms are involved.<\\/li>\\n<li><strong>[Fix]<\\/strong> Deprecation notices on PHP 8.3+.<\\/li>\\n<\\/ul>\\n<p>4.5.6<\\/p>\\n<ul>\\n<li><strong>[Update]<\\/strong> Updated compatibility with WordPress 6.9.<\\/li>\\n<li><strong>[Change]<\\/strong> If a result has no permalink, the Read More link is not displayed, and the result tile will have no link.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP type error in some edge cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Engine Rule\'s value overflowing the parent container.<\\/li>\\n<li><strong>[Fix]<\\/strong> Relevance miscalculated when filtering by taxonomy term in some cases.<\\/li>\\n<\\/ul>\\n<p>4.5.5<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Pro extensions cannot be activated with the All Access Bundle license.<\\/li>\\n<li><strong>[Update]<\\/strong> Updated admin notifications to reflect new license types.<\\/li>\\n<li><strong>[Update]<\\/strong> Updated Translation files.<\\/li>\\n<\\/ul>\\n<p>4.5.4<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added support for All Access Bundle license.<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic not respected in some cases.<\\/li>\\n<\\/ul>\\n<p>4.5.3<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Fixed compatibility with PHP 7.4.<\\/li>\\n<\\/ul>\\n<p>4.5.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added Template option to open search result links on a new tab\\/window.<\\/li>\\n<li><strong>[New]<\\/strong> Added Template option to link media files directly instead of the attachment page.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Forms setting \'Type of search\' is empty by default to allow searches on all engine sources.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Forms setting \'Type of search\' updates automatically when the Engine setting is changed.<\\/li>\\n<li><strong>[Improvement]<\\/strong> The highlighter now prioritizes exact phrases if they are present.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Generate fallback excerpt for attachments.<\\/li>\\n<li><strong>[Change]<\\/strong> The Diagnostics \'List Unindexed Entries\' feature now also displays entries excluded using the Exclude UI extension.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting not working with the taxonomy source.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting not working on PDF content if some special characters are part of the text.<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms not working with words with accented letters.<\\/li>\\n<li><strong>[Fix]<\\/strong> Closest match output notice placement on FSE themes.<\\/li>\\n<li><strong>[Fix]<\\/strong> Corrected action hook for debug logging.<\\/li>\\n<li><strong>[Fix]<\\/strong> Target page field in Search Forms settings not saving the correct page in some cases.<\\/li>\\n<\\/ul>\\n<p>4.5.1<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> SearchWP embed Wizard appears in admin pages if the block editor is disabled.<\\/li>\\n<\\/ul>\\n<p>4.5.0<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added elements for Search Forms and Results templates for Elementor, Divi, Oxygen, Breakdance, Bricks, WPBakery, Beaver Builder.<\\/li>\\n<li><strong>[New]<\\/strong> Promoted Search Ads.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Add ARIA attributes to search forms.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved Forms and Results template embed wizard.<\\/li>\\n<li><strong>[Change]<\\/strong> Renamed the editor form block to \\\"SearchWP Form\\\".<\\/li>\\n<li><strong>[Fix]<\\/strong> Deprecation notices in the block editor.<\\/li>\\n<li><strong>[Fix]<\\/strong> JS error due to a malformed SVG path.<\\/li>\\n<li><strong>[Fix]<\\/strong> jQuery Migrate notices.<\\/li>\\n<li><strong>[Fix]<\\/strong> Corrected typo in some notification strings.<\\/li>\\n<li><strong>[Fix]<\\/strong> Choices.js deprecation notices on some settings pages.<\\/li>\\n<li><strong>[Fix]<\\/strong> HTML tags appear in the excerpt generated from the WooCommerce short product description.<\\/li>\\n<\\/ul>\\n<p>4.4.0<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added multiple results templates.<\\/li>\\n<li><strong>[New]<\\/strong> Added Gutenberg block, shortcode and PHP function for SearchWP Results templates.<\\/li>\\n<li><strong>[New]<\\/strong> Integrated Diagnostics extension into the core plugin.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Minified frontend assets.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Removed Next\\/Previous labels from pagination if pagination uses boxed or circular style.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when Engine Rule target a non-existent taxonomy.<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted\\/Phrase searches working only from main site on a multisite installation.<\\/li>\\n<li><strong>[Fix]<\\/strong> Unclosed &lt;select&gt; tag in Search Forms Advanced Search.<\\/li>\\n<\\/ul>\\n<p>4.3.18<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Quoted\\/phrase searches are now supported on multisite searches.<\\/li>\\n<li><strong>[New]<\\/strong> Added searchwp\\\\source\\\\comment\\\\disable_weight_transfer filter to disable Comment weight transfer.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved Comments Source notice for clarity.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Retry license status check before deactivation on failure.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved exact matches buoy performance and results.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Improved performance of quoted\\/phrase searches.<\\/li>\\n<li><strong>[Update]<\\/strong> Removed use of deprecated MySQL query modifiers and functions.<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted\\/phrase search string output has redundant quotes in SearchWP template.<\\/li>\\n<li><strong>[Fix]<\\/strong> Duplicated highlighting tags in some cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Inconsistent results order when multiple results have the same relevance.<\\/li>\\n<\\/ul>\\n<p>4.3.17<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added SearchWP Source - WPForms to Extensions page.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Forms Author dropdown now supports authors from all post types.<\\/li>\\n<li><strong>[Update]<\\/strong> Block editor API version on Forms block.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighter prioritizing partial matches even when partial matches are disabled.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighter generating wrong excerpt if the text contains \'&lt;\' or \'&gt;\' characters.<\\/li>\\n<li><strong>[Fix]<\\/strong> Indexer pausing automatically in some cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Filter to disable Email Summaries not working from theme\'s functions.php file.<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.3.16 that prevented results from displaying in some cases when using the Divi Builder.<\\/li>\\n<li><strong>[Fix]<\\/strong> Block editor link search not working.<\\/li>\\n<li><strong>[Fix]<\\/strong> Javascript warning due to Exclude UI preview block in some installations.<\\/li>\\n<li><strong>[Fix]<\\/strong> Wrong license type recognition during activation in some rare cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> Wrong license level displayed in bbPress missing integration notice.<\\/li>\\n<\\/ul>\\n<p>4.3.16<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Weekly Email Summaries.<\\/li>\\n<li><strong>[New]<\\/strong> Added option to set pagination labels for SearchWP Templates.<\\/li>\\n<li><strong>[New]<\\/strong> New filter to disable the Advanced Custom Fields suggestions in the Engine settings.<\\/li>\\n<li><strong>[New]<\\/strong> New Relevance tab in the Debugging Console showing relevance for every search result.<\\/li>\\n<li><strong>[Change]<\\/strong> Use field name if field label is not set for ACF fields in the Engine settings.<\\/li>\\n<li><strong>[Change]<\\/strong> \'searchwp\\\\index\\\\process\\\\enabled\' filter overrides the Pause Indexing setting.<\\/li>\\n<li><strong>[Change]<\\/strong> SWP_Query sorting prioritizes URL arguments, then request arguments, then defaults.<\\/li>\\n<li><strong>[Change]<\\/strong> Optimised Divi theme integration.<\\/li>\\n<li><strong>[Change]<\\/strong> Improved loading of Stopwords in the Global Settings page.<\\/li>\\n<li><strong>[Change]<\\/strong> Better performance for partial matches in some cases.<\\/li>\\n<li><strong>[Change]<\\/strong> Added multisite support to SearchWP Templates.<\\/li>\\n<li><strong>[Change]<\\/strong> Added responsive grid sizing to the results templates.<\\/li>\\n<li><strong>[Change]<\\/strong> Dropped support for legacy extensions asset loading.<\\/li>\\n<li><strong>[Fix]<\\/strong> Advanced Custom Fields repeatable children not indexed correctly.<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic not working if synonyms are capitalised or have accents.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error if Weight Transfer ID doesn\'t exit.<\\/li>\\n<li><strong>[Fix]<\\/strong> Ignore delta updates during WP All Import imports.<\\/li>\\n<li><strong>[Fix]<\\/strong> \\\"true\\\" and \\\"false\\\" search strings converted to boolean in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.15<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Improved license handling.<\\/li>\\n<li><strong>[Fix]<\\/strong> Indexer running even when paused in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.14<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Onboarding Wizard to simplify the initial setup.<\\/li>\\n<li><strong>[Change]<\\/strong> Added an attribute to Search Forms to support non-default engine in Live Ajax Search.<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP Results template supports Metrics click tracking.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> SearchWP Results template produces errors in some cases when working with custom sources.<\\/li>\\n<\\/ul>\\n<p>4.3.13<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Search Form with Default engine and Default results page produces no results in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.12<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Supplemental Engines with no custom Sources can use the Default results page in Search Forms.<\\/li>\\n<li><strong>[Fix]<\\/strong> Installation error on some systems triggered by hidden system files.<\\/li>\\n<\\/ul>\\n<p>4.3.11<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> PHP error in some admin pages.<\\/li>\\n<\\/ul>\\n<p>4.3.10<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Product education sections are added throughout the admin area to showcase available SearchWP features.<\\/li>\\n<li><strong>[New]<\\/strong> Deprecated extension notices are added to inform the admin and provide the alternatives.<\\/li>\\n<li><strong>[Change]<\\/strong> Numerous feature descriptions are rephrased to explain the features better.<\\/li>\\n<li><strong>[Change]<\\/strong> Documentation links are added to multiple features to provide additional context.<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP begins indexing website content automatically once activated for the first time.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Form doesn\'t show on the search page if manually included.<\\/li>\\n<li><strong>[Fix]<\\/strong> Posts are not dropped entirely from the index when taxonomies are updated.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error in some edge cases when Users are updated.<\\/li>\\n<\\/ul>\\n<p>4.3.9<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Moved the Source Author attribute for better UI\\/UX.<\\/li>\\n<li><strong>[Fix]<\\/strong> Call to undefined function mysql_get_server_info() error in WP 6.4.<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted searches not working on custom fields when wildcards are used.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighter not working with terms that include special characters in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.8<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Update Media Source labels to match WordPress labels.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reindex Media files when changes are made on Media Library quick edits.<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP results page empty search logic is changed to match the Default results page logic.<\\/li>\\n<li><strong>[Fix]<\\/strong> MySQL error if there are no valid tokens.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when attempting to encode cookies that store an array as its value.<\\/li>\\n<\\/ul>\\n<p>4.3.7<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Search Results page \'searchwp\' parameter interferes with the custom templates.<\\/li>\\n<\\/ul>\\n<p>4.3.6<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Customizable SearchWP Search Results page.<\\/li>\\n<li><strong>[Change]<\\/strong> Add Search Form setting to change button label.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when attempting to encode the cookies in some cases.<\\/li>\\n<\\/ul>\\n<p>4.3.5<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Make the Search Form button label translatable.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error when a taxonomy term is updated if the taxonomy is an Engine source attribute.<\\/li>\\n<\\/ul>\\n<p>4.3.4<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Post Author added as an engine source attribute.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Added filter for Closest Match notice text.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Added support for SVG images.<\\/li>\\n<li><strong>[Improvement]<\\/strong> Only log statistics for the first page of results.<\\/li>\\n<li><strong>[Change]<\\/strong> Exclude taxonomy sources from default new engine settings.<\\/li>\\n<li><strong>[Change]<\\/strong> Order results by relevance first and post date after on empty native searches.<\\/li>\\n<li><strong>[Change]<\\/strong> Add a specific notice to the Engines page when the indexer is paused.<\\/li>\\n<li><strong>[Update]<\\/strong> Documentation links.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP error if a site uses cookies with forbidden characters.<\\/li>\\n<li><strong>[Fix]<\\/strong> Call to a member function on bool when using WP CLI commands.<\\/li>\\n<li><strong>[Fix]<\\/strong> Empty searches running slow.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP notice for deprecated use of stripos.<\\/li>\\n<li><strong>[Fix]<\\/strong> Invalid category console notice in block editor if Modal Form extension is inactive.<\\/li>\\n<li><strong>[Fix]<\\/strong> NOT IN condition on Media rules doesn\'t apply.<\\/li>\\n<\\/ul>\\n<p>4.3.3<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Taxonomy Source is added to the Engines configuration.<\\/li>\\n<li><strong>[Change]<\\/strong> Replace site_url with home_url in Search Form action on the frontend.<\\/li>\\n<li><strong>[Update]<\\/strong> Translation files.<\\/li>\\n<li><strong>[Fix]<\\/strong> Empty search queries are logged into the statistics.<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting is not working if a searched keyword is followed by special characters in the original text.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Form \\\"Type of search\\\" setting affects search results only when Advanced Search is enabled.<\\/li>\\n<li><strong>[Fix]<\\/strong> Search Form is not rendering on search results page in some cases.<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP notice on Search Form render if a category was saved in form settings but deleted from WP.<\\/li>\\n<li><strong>[Fix]<\\/strong> The whole excerpt gets highlighted on empty search if the \\\"Highlight Terms\\\" setting is enabled.<\\/li>\\n<\\/ul>\\n<p>4.3.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Embeddable Search Forms for a customized search experience<\\/li>\\n<li><strong>[Improvement]<\\/strong> Better handling of Synonyms partial matches<\\/li>\\n<li><strong>[Change]<\\/strong> SearchWP query runs for empty searches to adhere to engine restrictions<\\/li>\\n<\\/ul>\\n<p>4.3.1<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> \\\"Did you mean?\\\" feature prevents stemming from working<\\/li>\\n<li><strong>[Fix]<\\/strong> Strict AND logic set via the filter allows OR results<\\/li>\\n<li><strong>[Fix]<\\/strong> Partial matches use a wildcard when it is not needed<\\/li>\\n<li><strong>[Fix]<\\/strong> ACF suggestions are missing from the Custom Fields dropdown in the Source Attributes modal<\\/li>\\n<li><strong>[Fix]<\\/strong> Settings in the Misc tab are not saving in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics page shows UI which cannot be used by users with Statistics capability<\\/li>\\n<li><strong>[Fix]<\\/strong> Notifications icon is shown to users who cannot use it because of capability restrictions<\\/li>\\n<li><strong>[Fix]<\\/strong> Minor styling issues in the plugin settings<\\/li>\\n<\\/ul>\\n<p>4.3.0<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Admin settings UI redesign<\\/li>\\n<\\/ul>\\n<p>4.2.9<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Debugging Console to view debugging data in a browser panel style<\\/li>\\n<li><strong>[Improvement]<\\/strong> Prevent page slowdown when a taxonomy term is updated<\\/li>\\n<li><strong>[Improvement]<\\/strong> Set default value for Post Excerpt weight to a minimum<\\/li>\\n<li><strong>[Improvement]<\\/strong> Updated Stemmer library for better keyword stemming and PHP 8 compatibility<\\/li>\\n<li><strong>[Improvement]<\\/strong> Updated PdfParser library for better PDF parsing<\\/li>\\n<li><strong>[Fix]<\\/strong> \\\"Vue is in development mode\\\" console notice on the Settings screen<\\/li>\\n<li><strong>[Fix]<\\/strong> Deprecation notices on PHP 8.2<\\/li>\\n<li><strong>[Fix]<\\/strong> Plugin text domain is not loading properly<\\/li>\\n<\\/ul>\\n<p>4.2.8<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> In-plugin notification system to get the latest updates from SearchWP<\\/li>\\n<\\/ul>\\n<p>4.2.7<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Highlighter gives precedence to exact phrase search if present<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduced memory usage when generating the excerpt<\\/li>\\n<li><strong>[Fix]<\\/strong> Stemming prevents partial matches in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlighting not working with quoted searches in some cases<\\/li>\\n<\\/ul>\\n<p>4.2.6<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Improved AJAX actions security<\\/li>\\n<li><strong>[Improvement]<\\/strong> Updated the PdfParser library for better PDF parsing and improved compatibility<\\/li>\\n<li><strong>[Fix]<\\/strong> Engines errors are not accessible by external code because of the private visibility<\\/li>\\n<li><strong>[Fix]<\\/strong> License gets deactivated periodically for some rare server configurations<\\/li>\\n<\\/ul>\\n<p>4.2.5<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Exclude taxonomy name from indexed taxonomy term fields<\\/li>\\n<li><strong>[Improvement]<\\/strong> Do not index the image src attribute in the post content by default<\\/li>\\n<li><strong>[Fix]<\\/strong> No post type exists check during SWP_Query query<\\/li>\\n<li><strong>[Fix]<\\/strong> Existing SWP_Query post type can be overridden with $_REQUEST<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms and stemming affecting AND logic query<\\/li>\\n<\\/ul>\\n<p>4.2.4<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Better handling of quoted phrases in synonyms<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms not working with non-ASCII strings<\\/li>\\n<li><strong>[Fix]<\\/strong> Max nesting function when synonyms are applied<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms are not case-insensitive<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms affecting the stemming functionality<\\/li>\\n<li><strong>[Fix]<\\/strong> Metrics related click tracking error in multisite environment<\\/li>\\n<li><strong>[Fix]<\\/strong> Merging words during HTML content tokenization if<br \\/>\\nis used in the content<\\/li>\\n<li><strong>[Fix]<\\/strong> Hiding SearchWP admin menu via the hook leaves a link to it in the admin bar menu<\\/li>\\n<li><strong>[Fix]<\\/strong> MySQL error if engine sources have no attributes<\\/li>\\n<li><strong>[Fix]<\\/strong> Error if \'s\' parameter in the request is not a string<\\/li>\\n<li><strong>[Fix]<\\/strong> Warning if a custom field is added to the Users in the engine settings<\\/li>\\n<li><strong>[Fix]<\\/strong> Return type compatibility notice in PHP 8.1 for jsonSerialize() method<\\/li>\\n<\\/ul>\\n<p>4.2.3<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Performance improvement when getting \'post__in\' and \'post__not_in\' ids<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms work incorrectly when AND search logic is applied<\\/li>\\n<li><strong>[Fix]<\\/strong> Posts are not dropped from the index when a taxonomy term is updated<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted searches give too broad results on custom fields<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted searches query has redundant subqueries<\\/li>\\n<li><strong>[Fix]<\\/strong> Cross-site search limited results if \\\"all\\\" is passed as site args<\\/li>\\n<\\/ul>\\n<p>4.2.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Extensions admin page to install, activate and deactivate SearchWP extensions in one click<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance improvement when getting engines configuration<\\/li>\\n<li><strong>[Fix]<\\/strong> Search terms highlighting doesn\'t work well with quoted searches<\\/li>\\n<li><strong>[Fix]<\\/strong> Posts are not dropped from the index when a taxonomy term is deleted from the site<\\/li>\\n<li><strong>[Fix]<\\/strong> Stemming prevents partial matches in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Search terms highlighting give unexpected results with partial matches<\\/li>\\n<\\/ul>\\n<p>4.2.1<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Edited document content is not preserved<\\/li>\\n<li><strong>[Fix]<\\/strong> Broken URLs for the redirects to the legacy admin settings<\\/li>\\n<li><strong>[Fix]<\\/strong> Class prefixing error in smalot\\/pdfparser lib<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP7 static code analyzer error in symfony\\/polyfill-mbstring lib<\\/li>\\n<\\/ul>\\n<p>4.2.0<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Plugin settings moved to the top-level menu<\\/li>\\n<li><strong>[Fix]<\\/strong> Undefined function error during the \'index\' CLI command execution<\\/li>\\n<li><strong>[Fix]<\\/strong> Merging words in some cases during HTML content tokenization<\\/li>\\n<\\/ul>\\n<p>4.1.22<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Synonym application too broad in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Document content reindexing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Missing method reference in Comment source<\\/li>\\n<li><strong>[Fix]<\\/strong> Forced phrase search returns no results if the search string doesn\'t contain non-phrase tokens<\\/li>\\n<li><strong>[Improvement]<\\/strong> Search string normalization<\\/li>\\n<li><strong>[Improvement]<\\/strong> String highlight application when synonyms are applied<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of double quotes in synonym logic in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.21<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Apply AND logic when applicable during quoted search query<\\/li>\\n<li><strong>[Fix]<\\/strong> Default application of \'Did you mean?\' functionality in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.1.19 that prevented some results from displaying in some cases<\\/li>\\n<li><strong>[New]<\\/strong> Filter searchwp\\\\native\\\\args\\\\post_type to modify native search post type when necessary<\\/li>\\n<\\/ul>\\n<p>4.1.20<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Synonym processing now stops after first application unless searchwp\\\\synonyms\\\\aggressive filter returns false<\\/li>\\n<li><strong>[Fix]<\\/strong> Global excerpt and highlighting process now uses original search string, disregarding any filtration in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.19<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Consider Excerpt when performing quoted search<\\/li>\\n<li><strong>[Fix]<\\/strong> Multisite re\\/index using WP-CLI<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlight application with flanking punctuation in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Highlight application with stemming enabled in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP 8 compatibility<\\/li>\\n<li><strong>[New]<\\/strong> de_DE_formal translation<\\/li>\\n<li><strong>[Update]<\\/strong> Dependencies<\\/li>\\n<\\/ul>\\n<p>4.1.18<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Global excerpt generation due to newline<\\/li>\\n<li><strong>[Fix]<\\/strong> Relevance minimum clause implementation<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevent search suggestion output outside main query<\\/li>\\n<li><strong>[Fix]<\\/strong> Incorrect fields argument definition in some cases (caused FacetWP facets to not render in some cases)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Highlight matching in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.17<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Added relevance() method to Mods to allow additional manipulation of relevance calculation during searches<\\/li>\\n<li><strong>[Improvement]<\\/strong> Refactored WP All Import integration<\\/li>\\n<li><strong>[Fix]<\\/strong> Character encoding when finding global excerpts in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.16<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> searchwp\\\\index\\\\source\\\\add_hooks filter to allow prevention of core hook implementation<\\/li>\\n<li><strong>[New]<\\/strong> Integration with WP All Import to better react to import processes<\\/li>\\n<li><strong>[Improvement]<\\/strong> Global excerpt generation in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer state handling when programmatically pausing\\/unpausing<\\/li>\\n<li><strong>[Fix]<\\/strong> Searching Media in the WordPress Admin in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling (omitting) of entries that failed indexing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics migration from SearchWP 3 (if Statistics failed to migrate, please open a support ticket for direct assistance)<\\/li>\\n<\\/ul>\\n<p>4.1.15<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Partial matching in synonyms has been changed, to apply partial matching add a * wildcard where partial matching should be applied<\\/li>\\n<li><strong>[Change]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Global excerpt generation in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.1.12 that prevented results in some cases when setting AND logic to be strict<\\/li>\\n<\\/ul>\\n<p>4.1.14<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[New]<\\/strong> Rule for Media to consider filename<\\/li>\\n<li><strong>[New]<\\/strong> Rule for Pages and hierarchical CPTs to consider ancestry<\\/li>\\n<li><strong>[New]<\\/strong> Rule for Pages and hierarchical CPTs to consider post_parent<\\/li>\\n<li><strong>[New]<\\/strong> Edit and View actions for omitted entries<\\/li>\\n<li><strong>[New]<\\/strong> Support for Beaver Builder Search Module<\\/li>\\n<li><strong>[Fix]<\\/strong> Parallel indexing process when rebuilding index using WP-CLI in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Customization of post stati in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Additional background process health check<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of synonym input strings in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Default regular expression patterns<\\/li>\\n<li><strong>[Update]<\\/strong> Dependencies<\\/li>\\n<\\/ul>\\n<p>4.1.13<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Admin search of hierarchical post types<\\/li>\\n<li><strong>[Fix]<\\/strong> Support ticket iframe height minimum in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Partial match logic in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.12<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[New]<\\/strong> Upper threshold that prevents AND logic when too many terms make it a performance issue (default is 5 token groups)<\\/li>\\n<li><strong>[New]<\\/strong> Filter searchwp\\\\query\\\\logic\\\\and\\\\token_threshold to control AND logic token threshold (return false to disable threshold consideration)<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with searching Users in the WP Admin<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with setting query fields in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics CSS issue in Safari in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.11<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.1.9 that prevented saving parent weight transfer<\\/li>\\n<li><strong>[Improved]<\\/strong> PDF parsing in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.10<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Background process cookie validation in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.9<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduction in index bloat in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Comment parents being incorrectly returned in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when weight transfer was enabled but no recipient defined<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when using PHP8 in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.8<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Race condition prevention in background process<\\/li>\\n<li><strong>[Change]<\\/strong> Index controller no longer observes site switching, if switching sites you will need to first use the searchwp\\\\auto_update_providers hook<\\/li>\\n<li><strong>[Change]<\\/strong> Keyword stemming enabled by default during setup<\\/li>\\n<li><strong>[Fix]<\\/strong> Results when keyword stemming and partial matching is enabled and tokens are exact matches and stemmable<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics migration from SearchWP 3 in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Automatic integration with page builder plugin in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with ACF Repeatables not appearing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with not being able to add custom Custom Field keys to an Engine Source<\\/li>\\n<\\/ul>\\n<p>4.1.7<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Multisite performance issue that could lead to an Error in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics migration from SearchWP v3 (Regression introduced in 4.1.0)<\\/li>\\n<\\/ul>\\n<p>4.1.6<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Database table index optimization introduced in 4.1.5 in some configurations<\\/li>\\n<li><strong>[Fix]<\\/strong> Partial matches with stemming enabled during AND logic in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> AND logic handling in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.5<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Exact match buoy in partial match logic<\\/li>\\n<li><strong>[Fix]<\\/strong> Implementation of query when site is set to \'all\' to search all network sites<\\/li>\\n<li><strong>[Improvement]<\\/strong> Partial match logic<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of invalid tokens when finding partial matches<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance when applying delta index updates<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance when dropping Entries<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of duplicate tokens in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Native integration in non-standard environments (e.g. page builders)<\\/li>\\n<\\/ul>\\n<p>4.1.4<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Error during partial match application on synonyms in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Admin search handling in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.3<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonym partial matches in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Statistics display with Statistics capability but not Settings capability<\\/li>\\n<li><strong>[Fix]<\\/strong> HTTP Basic Auth credentials regression introduced in 4.1.0<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic performance regression introduced in 4.1.0 in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> AND logic performance in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Background process health check coverage<\\/li>\\n<li><strong>[Improvement]<\\/strong> PHP 8 compatibility<\\/li>\\n<\\/ul>\\n<p>4.1.2<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer handling of concurrent invocations, health check\\/restart when process encounters Errors<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer in multisite environment<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic restrictions in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.1<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> As of version 4.1 Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when highlighting in some cases<\\/li>\\n<\\/ul>\\n<p>4.1.0<\\/p>\\n<ul>\\n<li><strong>[IMPORTANT]<\\/strong> Comments are now a separate Source (if you are using Comments for any Post Type Source you <em>will need to edit your Engine and rebuild your index<\\/em>, this is not done automatically and should be planned for when updating)<\\/li>\\n<li><strong>[New]<\\/strong> Refactored indexer for stability, reliability, and performance optimization<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\index\\\\update_entry action when an Entry is updated in the Index<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\debug\\\\front_end_summary filter to control whether the HTML comment summary is output when debugging is enabled<\\/li>\\n<li><strong>[New]<\\/strong> wp searchwp reindex WP-CLI command<\\/li>\\n<li><strong>[New]<\\/strong> wp searchwp diagnostics WP-CLI command<\\/li>\\n<li><strong>[New]<\\/strong> Primary keys added to database tables <em>for new installs<\\/em> where previously there were none<\\/li>\\n<li><strong>[New]<\\/strong> Adds $query property to \\\\SWP_Query to reference underlying query object<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\source\\\\comment\\\\parent_attribution\\\\strict hook to control whether SearchWP is strict about parent attribution which can introduce overhead in some cases<\\/li>\\n<li><strong>[New]<\\/strong> SearchWP will now generate more expected variations of regex pattern matches<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\tokens\\\\generate_parttern_match_variations filter to control whether additional pattern match variations are generated during indexing<\\/li>\\n<li><strong>[New]<\\/strong> Ability to enter custom ignored queries for Statistics (with wildcard * support)<\\/li>\\n<li><strong>[New]<\\/strong> Ability to automatically trim Statistics logs<\\/li>\\n<li><strong>[New]<\\/strong> Notice when WordPress available memory can be improved<\\/li>\\n<li><strong>[New]<\\/strong> Export\\/import now optionally includes Settings, Stopwords, and Synonyms<\\/li>\\n<li><strong>[New]<\\/strong> All ACF fields are displayed in the Custom Fields dropdown when applicable, not only ACF \\\"Repeatables\\\"<\\/li>\\n<li><strong>[New]<\\/strong> Synonyms actions: Sort ASC, Sort DESC, Clear<\\/li>\\n<li><strong>[Change]<\\/strong> Refines default data indexed for Taxonomy Terms to be: taxonomy name, term name, term slug, and term description<\\/li>\\n<li><strong>[Change]<\\/strong> Abstracts Statistics Dashboard Widget from jquery-ui-tabs<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer auto-scaling when server load is high<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of HTML-formed content during indexing<\\/li>\\n<li><strong>[Improvement]<\\/strong> Integration of partial matches and keyword stemming<\\/li>\\n<li><strong>[Improvement]<\\/strong> Indexer delta trigger specificity in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Document processing handling, footprint<\\/li>\\n<li><strong>[Improvement]<\\/strong> Highlighting when a suggested search has been returned<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevent duplicate results during weight transfer in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> AND logic restriction, performance in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Persistent dismissal of missing integration notice<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonyms management in some cases<\\/li>\\n<li><strong>[Update]<\\/strong> Dependencies<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<li><strong>[Update]<\\/strong> Interface updates and refinements<\\/li>\\n<\\/ul>\\n<p>4.0.34<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Fixes regression introduced by Shortcodes fix in 4.0.33 (proper fix in Shortcodes 1.8.2)<\\/li>\\n<li><strong>[Update]<\\/strong> Updated updater<\\/li>\\n<\\/ul>\\n<p>4.0.33<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> searchwp\\\\swp_query\\\\mods filter to add Mods to SWP_Query<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP Warning introduced in 4.0.32<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevention of duplicate indexing processes in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Display issue on Statistics screen<\\/li>\\n<li><strong>[Fix]<\\/strong> PHP Warning when Admin color schemes have been removed<\\/li>\\n<li><strong>[Fix]<\\/strong> PDF parsing taking place unnecssarily in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Disable searchwp_search_results Shortcode when generating excerpts so as to prevent unwanted loop<\\/li>\\n<\\/ul>\\n<p>4.0.32<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Duplicate indexer processes in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Inaccurate batch size handling in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Prevent redundant search suggestion output in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Post stati validation when parent attribution is enabled<\\/li>\\n<li><strong>[Improvement]<\\/strong> Attachment status handling over time<\\/li>\\n<li><strong>[New]<\\/strong> RAND(seed) support by suffixing random Mod order_by with a colon and seed e.g. random:10 will be RAND(10)<\\/li>\\n<\\/ul>\\n<p>4.0.31<\\/p>\\n<ul>\\n<li><strong>[Improvement]<\\/strong> Adds NOT IN option to Media File Type Rule<\\/li>\\n<li><strong>[Improvement]<\\/strong> Debug HTML comment block output during Admin requests<\\/li>\\n<li><strong>[Fix]<\\/strong> Custom Attribute Options not returning proper Label after saving<\\/li>\\n<li><strong>[Fix]<\\/strong> Relocate searchwp\\\\query\\\\search_string hook to fire earlier<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue when performing cross-site Multisite search<\\/li>\\n<li><strong>[Fix]<\\/strong> searchwp\\\\query\\\\tokens\\\\limit default value<\\/li>\\n<li><strong>[New]<\\/strong> Action searchwp\\\\query\\\\core_mods_out_of_bounds fires when core Mods are considered out of bounds<\\/li>\\n<\\/ul>\\n<p>4.0.30<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> UI changes introduced by WordPress 5.5<\\/li>\\n<li><strong>[Fix]<\\/strong> Global excerpt generation from search suggestions<\\/li>\\n<li><strong>[Fix]<\\/strong> Synonym migration from SearchWP 3.x<\\/li>\\n<\\/ul>\\n<p>4.0.29<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Token handling in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Document content handling when using alternate indexer in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Tokenization of HTML in some cases<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\entry\\\\update_data\\\\before action fired before Entry data is retrieved<\\/li>\\n<li><strong>[Update]<\\/strong> Bundle dependencies<\\/li>\\n<\\/ul>\\n<p>4.0.28<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Prevent inapplicable comment edit events from triggering delta updates<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduced index method checks<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reactivity when observing meta updates<\\/li>\\n<\\/ul>\\n<p>4.0.27<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> File Content meta box display in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Entries not being reintroduced after failing when using alternate indexer<\\/li>\\n<li><strong>[Fix]<\\/strong> Display of Source Attribute Options when statically defined<\\/li>\\n<li><strong>[Fix]<\\/strong> UI display edge cases<\\/li>\\n<li><strong>[Change]<\\/strong> Token handling chunked in more cases so as to avoid issues when hosts limit query character length<\\/li>\\n<\\/ul>\\n<p>4.0.26<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Handling of SWP_Query tax_query argument<\\/li>\\n<li><strong>[New]<\\/strong> Advanced setting checkbox to control whether stored document content is purged and re-indexed during index rebuilds<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<\\/ul>\\n<p>4.0.25<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.0.24 when utilizing PDF Metadata<\\/li>\\n<li><strong>[Improvement]<\\/strong> Note displayed in SearchWP Document Content meta box when document is queued but not yet processed<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<\\/ul>\\n<p>4.0.24<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Handling of PDF metadata that includes invalid characters<\\/li>\\n<li><strong>[Fix]<\\/strong> Searching of hierarchical post types in the Admin<\\/li>\\n<li><strong>[Improvement]<\\/strong> Performance when handling documents outside the indexing process<\\/li>\\n<li><strong>[Update]<\\/strong> Bundle dependencies<\\/li>\\n<\\/ul>\\n<p>4.0.23<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Utilize previously extracted PDF metadata instead of parsing it repeatedly<\\/li>\\n<li><strong>[Change]<\\/strong> Updated default batch size for Media to 3, can be customized with searchwp\\\\indexer\\\\batch_size\\\\post.attachment hook<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of urlencoded tokens in some cases<\\/li>\\n<\\/ul>\\n<p>4.0.22<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Query parameter support for post_type when using SWP_Query (additional parameter support is planned)<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with partial matching yielding zero results in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Quoted search support for WP_Post Content, Document Content<\\/li>\\n<li><strong>[Improvement]<\\/strong> Reduced debug log volume (logs should be deleted once you\'re done debugging)<\\/li>\\n<\\/ul>\\n<p>4.0.20<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> New filter searchwp\\\\source\\\\post\\\\db_where to customize global WHERE limits per post type<\\/li>\\n<li><strong>[New]<\\/strong> License key is automatically activated when provided via constant or hook<\\/li>\\n<li><strong>[Fix]<\\/strong> Error on uninstall when removing all data<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue where Mods were not applied to SWP_Query in some cases<\\/li>\\n<li><strong>[Change]<\\/strong> No longer relying on excerpt_more when working with excerpts, now using ellipsis filtered by searchwp\\\\utils\\\\excerpt_more<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of rare cases where index would need to be woken up repeatedly in order to build<\\/li>\\n<li><strong>[Improvement]<\\/strong> Omits redundant Entry retrieval in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Significant performance retrieval when generating excerpts (e.g. Highlighting)<\\/li>\\n<li><strong>[Improvement]<\\/strong> Advanced Custom Fields integration support<\\/li>\\n<\\/ul>\\n<p>4.0.19<\\/p>\\n<ul>\\n<li><strong>[Notice]<\\/strong> Mods have in part been cleaned up and refined in this release, which may affect your usage. Please review any Mods you are using by testing this update on a staging server. If you are manipulating relevance weight based on date, it is likely you will need to update your hooks. Snippets have been updated on the KB article <a href=\\\"https:\\/\\/searchwp.com\\/?p=222848\\\">https:\\/\\/searchwp.com\\/?p=222848<\\/a> for review. Please also ensure your SearchWP Extensions are up to date as well.<\\/li>\\n<li><strong>[Fix]<\\/strong> Source Mod WHERE clauses causing errors in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Raw Mod WHERE clauses had no local alias to utilize<\\/li>\\n<li><strong>[Fix]<\\/strong> Mod JOIN claus order was not retained causing errors in some cases<\\/li>\\n<li><strong>[Improvement]<\\/strong> Optimized Mod handling in SWP_Query<\\/li>\\n<li><strong>[Improvement]<\\/strong> Disable integration extension checks when doing AJAX<\\/li>\\n<\\/ul>\\n<p>4.0.18<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Error when using mod argument of \\\\SearchWP\\\\Query parameters array<\\/li>\\n<li><strong>[Improvement]<\\/strong> Control over Settings page navigation<\\/li>\\n<\\/ul>\\n<p>4.0.17<\\/p>\\n<ul>\\n<li><strong>[Note]<\\/strong> Rebuilding your index using the Rebuild Index button on the Engines tab of the SearchWP settings screen is recommended after updating<\\/li>\\n<li><strong>[Fix]<\\/strong> Delta update regression introduced in 4.0.13<\\/li>\\n<li><strong>[Fix]<\\/strong> Error when applying delta update to Source that no longer exists<\\/li>\\n<li><strong>[Improvement]<\\/strong> Handling of delta update process during failures<\\/li>\\n<li><strong>[Improvement]<\\/strong> Delta update queue handling during index rebuild<\\/li>\\n<\\/ul>\\n<p>4.0.16<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Invalid range in character class introduced in 4.0.15 for PHP 7.3+<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\tokens\\\\whitelist\\\\only_full_matches retagged as searchwp\\\\tokens\\\\regex_patterns\\\\only_full_matches<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\tokens\\\\apply_rules_to_whitelist retagged as searchwp\\\\tokens\\\\apply_rules_to_pattern_matches<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\tokens\\\\whitelist_regex_patterns retagged as searchwp\\\\tokens\\\\regex_patterns<\\/li>\\n<li><strong>[Change]<\\/strong> Regex pattern matches are now tokenized during indexing (but remain exclusive when searching by default when applicable)<\\/li>\\n<li><strong>[New]<\\/strong> Filter searchwp\\\\tokens\\\\tokenize_pattern_matches\\\\indexing to disable new tokenizing of pattern match behavior during indexing<\\/li>\\n<\\/ul>\\n<p>4.0.15<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> New filter searchwp\\\\tokens\\\\string to customize strings before tokenization<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of synonyms when finding partial matches<\\/li>\\n<li><strong>[Fix]<\\/strong> Implementation and handling of regex pattern match tokenization setting<\\/li>\\n<li><strong>[Improvement]<\\/strong> Dash\\/hyphen and word match regex patterns<\\/li>\\n<li><strong>[Improvement]<\\/strong> searchwp\\\\source\\\\post\\\\excerpt_haystack filter now passes arguments array<\\/li>\\n<li><strong>[Update]<\\/strong> Translation source<\\/li>\\n<\\/ul>\\n<p>4.0.14<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where partial matches from keyword stems were not found in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Partial match token processing limited to applicable site(s)<\\/li>\\n<li><strong>[Fix]<\\/strong> Excerpt generation when handling unregistered Shortcodes<\\/li>\\n<\\/ul>\\n<p>4.0.13<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Delta update routine when using alternate indexer that caused unwanted exit<\\/li>\\n<li><strong>[Fix]<\\/strong> <strong>searchwp\\\\document\\\\content<\\/strong> implementation<\\/li>\\n<li><strong>[Improvement]<\\/strong> Index integrity check when rebuilding<\\/li>\\n<li><strong>[Improvement]<\\/strong> Source hook management in multisite<\\/li>\\n<li><strong>[Improvement]<\\/strong> Upgrade routine process<\\/li>\\n<\\/ul>\\n<p>4.0.12<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Inability to filter searchwp\\\\settings\\\\capability<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with Highlighting in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Document Content not properly considered for global excerpt in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Warning when reacting to invalid Entry during indexing<\\/li>\\n<li><strong>[Fix]<\\/strong> Namespace issue with PDF parsing in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Unnecessary provider reset when switching to the same site in multisite<\\/li>\\n<li><strong>[Update]<\\/strong> Updated updater<\\/li>\\n<\\/ul>\\n<p>4.0.11<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Loss of tokens when applying partial match logic in some cases<\\/li>\\n<li><strong>[Update]<\\/strong> Revised MySQL minimum to 5.6 (MariaDB 10.0) because of utf8mb4_unicode_520_ci collation requirement<\\/li>\\n<\\/ul>\\n<p>4.0.9<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Regression introduced in 4.0.6 that prevented non WP_Post results from returning<\\/li>\\n<\\/ul>\\n<p>4.0.8<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where taxonomy Rules for Media were not applied correctly in some cases<\\/li>\\n<\\/ul>\\n<p>4.0.7<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Mod WHERE clauses not restricted to Source when defined<\\/li>\\n<\\/ul>\\n<p>4.0.6<\\/p>\\n<ul>\\n<li><strong>[Change]<\\/strong> Post is now returned when parent weight transfer is enabled but Post has no post_parent<\\/li>\\n<li><strong>[Improvement]<\\/strong> Excerpt handling for native results<\\/li>\\n<li><strong>[Improvement]<\\/strong> Additional prevention of invalid WP_Post results being returned in one case<\\/li>\\n<\\/ul>\\n<p>4.0.5<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Filter to control stemmer locale searchwp\\\\stemmer\\\\locale<\\/li>\\n<li><strong>[Improvement]<\\/strong> Token stems\\/partial matches are considered during AND logic pass<\\/li>\\n<li><strong>[Fix]<\\/strong> String not sent to searchwp\\\\stemmer\\\\custom<\\/li>\\n<li><strong>[Change]<\\/strong> searchwp\\\\query\\\\partial_matches\\\\buoy is now opt-in<\\/li>\\n<\\/ul>\\n<p>4.0.4<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where AND logic would not apply in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue where additional unnecessary query clauses are added in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Issue with delta updates not processing when HTTP Basic Auth is active<\\/li>\\n<li><strong>[Fix]<\\/strong> Minimum PHP version requirement check (which is 7.2)<\\/li>\\n<\\/ul>\\n<p>4.0.3<\\/p>\\n<ul>\\n<li><strong>[Fix]<\\/strong> Issue where tokens table was not reset during index rebuild<\\/li>\\n<\\/ul>\\n<p>4.0.2<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Support for BETWEEN, NOT BETWEEN, LIKE, and NOT LIKE compare operators for Mod WHERE clauses<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of Mod WHERE clauses in some cases<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of REST parameters when returning search results<\\/li>\\n<\\/ul>\\n<p>4.0.1<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Check for remnants of SearchWP 3 that were not removed as per the Migration Guide<\\/li>\\n<li><strong>[New]<\\/strong> searchwp\\\\source\\\\post\\\\attributes\\\\comments action when retrieving Post comments<\\/li>\\n<li><strong>[Fix]<\\/strong> Handling of empty search strings in some cases<\\/li>\\n<\\/ul>\\n<p>4.0.0<\\/p>\\n<ul>\\n<li><strong>[New]<\\/strong> Complete rewrite of SearchWP<\\/li>\\n<\\/ul>\\n\"],\"plugin\":\"searchwp\\/index.php\",\"id\":\"searchwp\\/index.php\"}\";}', 'off'),
(9412, 'gform_email_count', '5', 'auto'),
(10556, 'adminhash', 'a:2:{s:4:\"hash\";s:32:\"430da3d2a82d4b3e26f4d1d1aa341551\";s:8:\"newemail\";s:10:\"wp@yard.nl\";}', 'off'),
(10601, 'edd_sl_c397ed7a535465d30ffa680d89b6e587', 'a:2:{s:7:\"timeout\";i:1779811043;s:5:\"value\";s:45612:\"{\"name\":\"SEOPress PRO\",\"new_version\":\"9.9\",\"stable_version\":\"9.9\",\"sections\":{\"description\":\"<h3>SEOPress \\u2013 The fast, privacy-first WordPress SEO plugin, ready for AI search<\\/h3>\\n<p><strong>Rank higher in Google AND in AI answer engines<\\/strong> (ChatGPT, Claude, Perplexity, Gemini). SEOPress is the all-in-one WordPress SEO plugin trusted by <strong>350,000+ websites since 2017<\\/strong>: fully white label, <strong>privacy by design<\\/strong>, and now AI-ready.<\\/p>\\n<p>[youtube <a href=\\\"https:\\/\\/www.youtube.com\\/watch?v=4ysKFVr_nu0\\\">https:\\/\\/www.youtube.com\\/watch?v=4ysKFVr_nu0<\\/a>]<\\/p>\\n<p>&#x2714; <strong>One SEO plugin, every page builder<\\/strong>: Universal SEO metabox for Gutenberg, Elementor, Divi, Bricks, Oxygen, Breakdance, WPBakery, Avada, Kadence and more. <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/page-builders-integration\\/\\\">See all integrations<\\/a>.\\n&#x2714; <strong>AI-powered metadata<\\/strong>: Generate SEO titles, meta descriptions, Open Graph, X (Twitter) Cards and image alt text in bulk with OpenAI, Google Gemini, Anthropic Claude, MistralAI or DeepSeek. <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/openai\\/\\\">Learn more<\\/a>.\\n&#x2714; <strong>Built for AI search (AEO \\/ GEO)<\\/strong>: Native llms.txt support and one-click Agent Readiness toggle so ChatGPT, Claude, Perplexity &amp; Gemini understand your content.\\n&#x2714; <strong>Privacy-first &amp; fully white label<\\/strong>: No tracking, no data footprint, no upsells in admin. Your data stays yours. <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/seopress-white-label\\/\\\">Why white label matters<\\/a>.\\n&#x2714; <strong>Content analysis with unlimited target keywords<\\/strong>: No artificial limit per post.\\n&#x2714; <strong>Migrate in one click<\\/strong>: From Yoast SEO, Rank Math, AIOSEO, The SEO Framework, Slim SEO, SmartCrawl, Squirrly, SEO Ultimate, WP Meta SEO, Premium SEO Pack, SiteSEO. <a href=\\\"https:\\/\\/www.seopress.org\\/solutions\\/migrate-from\\/\\\">Start migration<\\/a>.\\n&#x2714; <strong>Translated into 27+ languages<\\/strong> with professional translations. <a href=\\\"https:\\/\\/translate.wordpress.org\\/projects\\/wp-plugins\\/wp-seopress\\\">Help translate<\\/a>.<\\/p>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>SEOPress PRO from $49\\/year: 1 site \\u2022 Unlimited sites for $149\\/year<\\/strong><\\/a><\\/p>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/\\\">Features<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/solutions\\/migrate-from\\/\\\">Migrate<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/wordpress-seo-plugins\\/pro\\/\\\">PRO<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/integrations\\/\\\">Integrations<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/\\\">Support<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/seopress-white-label\\/\\\">White Label<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/openai\\/\\\">AI<\\/a><\\/p>\\n<h3>What\'s new in SEOPress 9.9<\\/h3>\\n<p>A major UX release: redesigned SEO dashboard, smarter SEO box, sharper Content Analysis and a fully accessible admin.<\\/p>\\n<ul>\\n    <li><strong>&#x1f9ed; Brand new SEO dashboard &amp; admin header<\\/strong>: Cleaner two-column layout, one-click module toggles, guided \\\"Get Started\\\" with numbered steps, and quick access to Help, Display options and notifications (with counter badge) on every SEO page.<\\/li>\\n    <li><strong>&#x1fa84; Setup wizard, fully redesigned<\\/strong>: Faster, mobile-friendly, and easier to follow from start to finish.<\\/li>\\n    <li><strong>&#x26a1; Smarter SEO box<\\/strong>: Double-click target keywords to edit in place, Google keyword suggestions with autocomplete as you type, and a single \\\"Update\\\" in the Block Editor now saves every section at once (Title, Description, Advanced, Social, Redirections, Content Analysis).<\\/li>\\n    <li><strong>&#x1f4dd; Content Analysis<\\/strong>: New content quality &amp; structure checks to help you write better articles, plus the ability to hide an issue you don\'t want to fix on a given page.<\\/li>\\n    <li><strong>&#x1f504; One-click migration from SureRank<\\/strong> and a full migration from SmartCrawl (variables in your titles &amp; descriptions are automatically translated).<\\/li>\\n    <li><strong>&#x1f6e0;&#xfe0f; Tools redesigned<\\/strong>: Reset page with confirmation prompts so nothing happens by accident, and Import \\/ Export with a cleaner layout, \\\"export everything\\\" by default, and a Cancel button on CSV exports.<\\/li>\\n    <li><strong>&#x1f441;&#xfe0f; Appearance \\u203a Columns<\\/strong>: Live preview of your post lists with grouped checkboxes \\u2014 see what you\'ll get before you save.<\\/li>\\n    <li><strong>&#x267f; Big accessibility upgrade<\\/strong> across the whole SEO admin (WCAG 2.1 AA \\/ RGAA 4.1 compliant), and the admin now matches your WordPress color scheme automatically.<\\/li>\\n    <li><strong>&#x1f4ca; Site Overview on the dashboard<\\/strong> (PRO): Your Google Analytics 4 and Matomo stats directly on the SEO dashboard, with period &amp; metric filters, an interactive chart, and a sync button.<\\/li>\\n    <li><strong>&#x1f3ac; Video schema auto-filled<\\/strong> (PRO): Populated from the first YouTube video found in your post \\u2014 no manual copy-paste.<\\/li>\\n    <li><strong>&#x21aa;&#xfe0f; Redirections<\\/strong> (PRO): Quick Edit, search results that stay when you go back, search by destination URL, and a dedicated 404 view with a \\\"Delete 404s\\\" shortcut.<\\/li>\\n    <li><strong>&#x1fa7a; Site Audit<\\/strong> (PRO): Detects the new content quality &amp; structure issues.<\\/li>\\n    <li><strong>&#x1f30d; Better Search Console URL matching<\\/strong> (PRO) for multilingual sites (WPML \\/ Polylang).<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/newsroom\\/product-news\\/seopress-9-9\\/\\\"><strong>Read the full 9.9 release notes \\u2192<\\/strong><\\/a><\\/p>\\n<h3>Why SEOPress is the best WordPress SEO plugin?<\\/h3>\\n<ul>\\n    <li><strong>All-in-one<\\/strong>: Schemas, redirections, XML sitemaps, GSC, image SEO, breadcrumbs, broken links and more in one plugin. Fewer plugins, fewer conflicts, lower maintenance.<\\/li>\\n    <li><strong>Modular<\\/strong>: Don\'t need a feature? Disable it in one click without losing your settings.<\\/li>\\n    <li><strong>Affordable<\\/strong>: PRO from $49\\/year for 1 site. Unlimited sites for $149\\/year. No \\\"agency\\\" tax.<\\/li>\\n    <li><strong>White label by default<\\/strong>: Replace plugin name, logo, links and screens. Perfect for agencies and freelancers.<\\/li>\\n    <li><strong>GDPR-friendly<\\/strong>: Privacy by design. Built-in compatibility with consent platforms.<\\/li>\\n    <li><strong>Beginner to expert<\\/strong>: Installation wizard for newcomers, hundreds of hooks, REST API and WP-CLI for developers. Free <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/\\\">guides<\\/a> and <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/ebooks\\/\\\">SEO ebooks<\\/a>.<\\/li>\\n    <li><strong>Battle-tested<\\/strong>: 350,000+ active installs, weekly releases, dedicated team since 2017.<\\/li>\\n<\\/ul>\\n<h3>SEOPress Free Features<\\/h3>\\n<ul>\\n    <li><strong>Installation wizard<\\/strong>: Get configured in minutes.<\\/li>\\n    <li><strong>Universal SEO metabox<\\/strong>: Edit titles, descriptions, Open Graph, X Cards, schema, robots and canonical from any editor (Gutenberg, Elementor, Divi, Bricks, Oxygen, Breakdance, WPBakery, Avada, Kadence\\u2026).<\\/li>\\n    <li><strong>Command palette<\\/strong> (Cmd\\/Ctrl+K): Jump to any setting instantly.<\\/li>\\n    <li><strong>Content analysis<\\/strong> with **unlimited target keywords** to write content that ranks.<\\/li>\\n    <li><strong>Mobile &amp; Desktop Google preview<\\/strong>: See your SERP snippet before you publish.<\\/li>\\n    <li><strong>Facebook &amp; X (Twitter) social preview<\\/strong> for higher CTR on social.<\\/li>\\n    <li><strong>Titles &amp; meta descriptions<\\/strong> with <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/manage-titles-meta-descriptions\\/\\\">dynamic variables<\\/a> (custom fields, terms, taxonomies).<\\/li>\\n    <li><strong>Open Graph &amp; X (Twitter) Cards<\\/strong> for Facebook, LinkedIn, Instagram, Pinterest, WhatsApp, Threads\\u2026<\\/li>\\n    <li><strong>Google Knowledge Graph<\\/strong>: Organization data with address &amp; legal fields (new in 9.8).<\\/li>\\n    <li><strong>llms.txt &amp; Agent Readiness<\\/strong>: Help AI search engines understand your site (new in 9.8).<\\/li>\\n    <li><strong>Google Analytics 4 &amp; Matomo<\\/strong>: Downloads tracking, custom dimensions, IP anonymization, remarketing, demographics, cross-domain tracking, GDPR-friendly.<\\/li>\\n    <li><strong>Microsoft Clarity<\\/strong> integration: Free heatmaps and session recordings.<\\/li>\\n    <li><strong>Custom canonical URLs<\\/strong> and <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/manage-meta-robots\\/\\\">meta robots<\\/a> (noindex, nofollow, noimageindex, nosnippet).<\\/li>\\n    <li><strong>XML sitemaps<\\/strong> (posts, pages, CPTs, taxonomies, images, authors): <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/sitemaps\\/\\\">faster than ever<\\/a> in 9.8.<\\/li>\\n    <li><strong>HTML sitemap<\\/strong> for accessibility &amp; navigation.<\\/li>\\n    <li><strong>Image XML sitemap<\\/strong> for Google Images.<\\/li>\\n    <li><strong>Redirections<\\/strong> at the post \\/ page \\/ CPT level.<\\/li>\\n    <li><strong>URL clean-up<\\/strong>: Remove \\/category\\/, \\/product-category\\/, ?replytocom; redirect attachment pages to parent or file URL.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/image-seo\\/\\\"><strong>Image SEO<\\/strong><\\/a>: Auto-set image title, alt, caption and description.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/google-indexing-api-with-seopress\\/\\\"><strong>Google Indexing API &amp; IndexNow<\\/strong><\\/a> (Bing\\/Yandex) for instant indexing.<\\/li>\\n    <li><strong>Import\\/export settings<\\/strong> from site to site.<\\/li>\\n    <li><strong>One-click migration<\\/strong> from Yoast, Rank Math, AIOSEO, SEO Framework, SureRank, Slim SEO, SmartCrawl, Squirrly, SEO Ultimate, WP Meta SEO, Premium SEO Pack, SiteSEO.<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/wordpress-seo-plugins\\/free\\/features\\/\\\">Check out all SEOPress Free features here<\\/a><\\/p>\\n<h3>SEOPress PRO: Take SEO further<\\/h3>\\n<p>[youtube <a href=\\\"https:\\/\\/youtu.be\\/zxGCY-bJYwE\\\">https:\\/\\/youtu.be\\/zxGCY-bJYwE<\\/a>]<\\/p>\\n<ul>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/openai\\/\\\"><strong>AI SEO<\\/strong><\\/a>: Auto-generate titles, descriptions, OG \\/ X tags and image alt text in bulk with OpenAI, Google Gemini (incl. **Gemini 3 Flash &amp; 3.1 Pro**), Anthropic Claude, MistralAI, DeepSeek.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/site-audit\\/\\\"><strong>Site Audit<\\/strong><\\/a>: Full React + DataViews experience with **GSC-backed recommendations**, scan history, live progress, one-click AI alt text fixes, CSV export.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/seo-alerts\\/\\\"><strong>SEO alerts<\\/strong><\\/a>: Be warned before SEO regressions hit production.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-search-console\\/\\\"><strong>Google Search Console<\\/strong><\\/a>: Clicks, impressions, CTR, average position right inside post lists.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-suggest\\/\\\"><strong>Google Suggestions<\\/strong><\\/a> in content analysis for long-tail keyword discovery.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/301-redirects\\/\\\"><strong>Redirect manager<\\/strong><\\/a>: Unlimited 301\\/302\\/307\\/410\\/451 redirects, regex, URL tester modal, categories, CSV\\/htaccess import &amp; export.<\\/li>\\n    <li><strong>404 monitoring &amp; auto-redirect<\\/strong> with email notifications.<\\/li>\\n    <li><strong>Broken link checker<\\/strong>: Reliable CRON-based batch scan, even on the largest sites.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-structured-data-types\\/\\\"><strong>Schema.org \\/ JSON-LD editor<\\/strong><\\/a> with **live preview**: Article, LocalBusiness, Service, How-to, FAQ, Course, Recipe, SoftwareApplication, Video, Event, Product, JobPosting, Review, ProfilePage, Custom schema.<\\/li>\\n    <li><strong>Automatic schemas<\\/strong> with advanced conditions (AND\\/OR, post types, taxonomies).<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/breadcrumbs\\/\\\"><strong>Accessible breadcrumbs<\\/strong><\\/a>: Schema.org, A11Y-ready, live preview, custom per CPT\\/term.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/local-seo\\/\\\"><strong>Local SEO<\\/strong><\\/a>: Local Business schema with opening hours, multiple stores.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/woocommerce-seo\\/\\\"><strong>WooCommerce SEO<\\/strong><\\/a>: Product schema with global identifiers (GTIN, MPN, brand), Enhanced Ecommerce, OG price\\/currency, noindex on cart\\/checkout\\/account.<\\/li>\\n    <li><strong>Easy Digital Downloads<\\/strong> integration.<\\/li>\\n    <li><strong>Internal linking suggestions<\\/strong>.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/sitemaps\\/\\\"><strong>Video XML Sitemap<\\/strong><\\/a> with automatic YouTube discovery + **Google News sitemap**.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-analytics\\/\\\"><strong>Google Analytics dashboard<\\/strong><\\/a>: Metrics inside WordPress, no context switching.<\\/li>\\n    <li><strong>PageSpeed Insights &amp; Core Web Vitals<\\/strong> reports.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/htaccess-robots-txt\\/\\\"><strong>robots.txt &amp; .htaccess editor<\\/strong><\\/a>: Multisite \\/ multidomain ready.<\\/li>\\n    <li><strong>Custom RSS feed<\\/strong> options.<\\/li>\\n    <li><strong>Multilingual llms.txt<\\/strong> with TranslatePress.<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>Get SEOPress PRO \\u2192<\\/strong><\\/a><\\/p>\\n<h3>SEOPress Insights: Track rankings &amp; backlinks inside WordPress<\\/h3>\\n<ul>\\n    <li><strong>Keyword rank tracker<\\/strong>: 52 Google Search locations.<\\/li>\\n    <li>Track <strong>50 keywords\\/site daily<\\/strong>.<\\/li>\\n    <li><strong>Competitor tracking<\\/strong>: See who outranks you.<\\/li>\\n    <li><strong>Backlinks<\\/strong> monitored weekly.<\\/li>\\n    <li><strong>Google Trends<\\/strong>: Find new content angles.<\\/li>\\n    <li><strong>Lifetime data access<\\/strong>: Export to CSV \\/ PDF \\/ Excel.<\\/li>\\n    <li><strong>Email &amp; Slack alerts<\\/strong>.<\\/li>\\n<\\/ul>\\n<p>[youtube <a href=\\\"https:\\/\\/youtu.be\\/p6v9Jd5lRIU\\\">https:\\/\\/youtu.be\\/p6v9Jd5lRIU<\\/a>]<\\/p>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>Get SEOPress Insights \\u2192<\\/strong><\\/a><\\/p>\\n<h3>WooCommerce &amp; EDD SEO (SEOPress PRO)<\\/h3>\\n<ul>\\n    <li>Product schema with global identifiers (GTIN, MPN, brand).<\\/li>\\n    <li>OG price &amp; currency for richer social shares.<\\/li>\\n    <li>XML sitemaps for products, including image galleries.<\\/li>\\n    <li>Centralized noindex for cart\\/checkout\\/account\\/thank-you pages.<\\/li>\\n    <li>Removes WooCommerce\\/EDD generator meta tag.<\\/li>\\n    <li>Manual or automatic JSON-LD product schemas.<\\/li>\\n    <li>Breadcrumbs with WooCommerce support.<\\/li>\\n    <li>Global dynamic tags for titles &amp; meta descriptions.<\\/li>\\n    <li>Google Enhanced Ecommerce: purchases, product views, cart events.<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>Boost your store\'s SEO \\u2192<\\/strong><\\/a><\\/p>\\n<h3>Universal SEO metabox: works with every editor<\\/h3>\\n<p>[youtube <a href=\\\"https:\\/\\/youtu.be\\/sf0ocG7vQMM\\\">https:\\/\\/youtu.be\\/sf0ocG7vQMM<\\/a>]<\\/p>\\n<p>Edit your SEO directly inside Gutenberg, Elementor, Divi, Bricks, Oxygen, Breakdance, WPBakery, Avada, Kadence, WP Fusion. <strong>No more back-and-forth<\\/strong> between page builder and WordPress admin.<\\/p>\\n<h3>Built for developers<\\/h3>\\n<ul>\\n    <li><strong>Hundreds of hooks<\\/strong>: <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/hooks\\/\\\">Browse the hooks reference<\\/a>.<\\/li>\\n    <li><strong>REST API<\\/strong>: Power headless and static sites. <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/get-started-with-the-seopress-rest-api\\/\\\">Get started<\\/a>.<\\/li>\\n    <li><strong>WP-CLI commands<\\/strong>: Automate everything. <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/seopress-wp-cli\\/\\\">CLI reference<\\/a>.<\\/li>\\n    <li><strong>13+ new dev hooks in 9.8<\\/strong>.<\\/li>\\n<\\/ul>\\n<h3>From the same team<\\/h3>\\n<a href=\\\"https:\\/\\/wordpress.org\\/plugins\\/mailerpress\\/\\\">Try MailerPress, the best email marketing plugin for WordPress<\\/a>\",\"changelog\":\"<h4> 9.9 <a href=\\\"https:\\/\\/www.seopress.org\\/newsroom\\/product-news\\/seopress-9-9\\/\\\">Read the blog post update<\\/a> <\\/h4>\\n<ul>\\n<li>NEW Brand new SEO dashboard and admin header: cleaner two-column layout, one-click module toggles, a guided \\\"Get Started\\\" with numbered steps, and quick access to Help, Display options and notifications (with counter badge) on every SEO page<\\/li>\\n<li>NEW Setup wizard fully redesigned: faster, mobile-friendly, and easier to follow from start to finish<\\/li>\\n<li>NEW Smarter SEO box: double-click your target keywords to edit them in place, Google keyword suggestions with autocomplete as you type, and clicking \\\"Update\\\" in the Block Editor now saves every section at once (Title, Description, Advanced, Social, Redirections, Content Analysis)<\\/li>\\n<li>NEW Content Analysis: new content quality &amp; structure checks to help you write better articles, plus the ability to hide an issue you don\'t want to fix on a given page<\\/li>\\n<li>NEW One-click migration from SureRank, and a full migration from SmartCrawl (variables in your titles &amp; descriptions are automatically translated)<\\/li>\\n<li>NEW Tools redesigned: Reset page with confirmation prompts so nothing happens by accident, and Import \\/ Export with a cleaner layout, \\\"export everything\\\" by default, and a Cancel button on CSV exports<\\/li>\\n<li>NEW Appearance \\u203a Columns: live preview of your post lists with grouped checkboxes \\u2014 see what you\'ll get before you save<\\/li>\\n<li>NEW Category URL settings now read directly from your WordPress permalink settings (no risk of mismatch)<\\/li>\\n<li>NEW Easier-to-remember date variables for schemas (ISO 8601 aliases)<\\/li>\\n<li>NEW Big accessibility upgrade across the whole SEO admin (WCAG 2.1 AA \\/ RGAA 4.1 compliant), and the admin now matches your WordPress color scheme automatically<\\/li>\\n<li>NEW Cleaner dashboard: removed the Newsroom and SEO Ebooks sections<\\/li>\\n<li>NEW [PRO] Site Overview now shows your Google Analytics 4 and Matomo stats directly on the SEO dashboard, with period &amp; metric filters, an interactive chart, and a sync button<\\/li>\\n<li>NEW [PRO] Video schema is auto-filled from the first YouTube video found in your post \\u2014 no manual copy-paste<\\/li>\\n<li>NEW [PRO] Redirections: Quick Edit, search results that stay when you go back, search by destination URL, and a dedicated 404 view with a \\\"Delete 404s\\\" shortcut<\\/li>\\n<li>NEW [PRO] Friendlier empty states on Schemas and Broken Links screens (clear guidance when there\'s nothing yet)<\\/li>\\n<li>NEW [PRO] Site Audit: detects the new content quality &amp; structure issues<\\/li>\\n<li>NEW [PRO] Better Search Console URL matching for multilingual sites (WPML \\/ Polylang), <\\/li>\\n<li>NEW Developer filters: <code>seopress_search_console_match_url<\\/code>, <code>seopress_search_console_match_post_id<\\/code>, and <code>seopress_gtag_ec_item_id<\\/code> to customize the product identifier sent to GA4<\\/li>\\n<li>INFO Tested up to WordPress 7.0<\\/li>\\n<li>FIX Google snippet preview now displays the correct title and description, and no longer shows the Elementor template instead of your actual post<\\/li>\\n<li>FIX Internal Linking tab no longer crashes the whole SEO box, and the tag picker no longer scrolls uncontrollably when hovering the last item<\\/li>\\n<li>FIX Title \\/ meta description templates: spaces around variables are preserved on save, and custom field variables (%%<em>cf<\\/em><em>%%, %%<\\/em><em>ct<\\/em>%%, %%<em>ucf<\\/em>*%%) now work on the home page and blog page<\\/li>\\n<li>FIX White-label \\\"remove help links\\\" setting is now respected in the new admin header<\\/li>\\n<li>FIX SEOPress columns and bulk actions in your post lists are restored after toggling the metabox option (and no error when the bulk actions list is empty)<\\/li>\\n<li>FIX Notifications counter and \\\"hide notification\\\" behavior now work as expected<\\/li>\\n<li>FIX X (Twitter) handle is now cleaned up automatically in social tags<\\/li>\\n<li>FIX [PRO] Custom automatic schemas created in the new editor are now correctly displayed on the front-end, and the Knowledge Graph logo appears in the JSON-LD preview<\\/li>\\n<li>FIX [PRO] Redirections: URLs with accented \\/ non-Latin characters are saved correctly, and sorting (hits, type, last hit\\u2026) + category counts now match what\'s shown in the list<\\/li>\\n<li>FIX [PRO] OpenAI \\\"Test connection\\\" now works again after OpenAI retired the previous endpoint<\\/li>\\n<li>FIX [PRO] AI metadata generation now uses the correct language per post on WPML \\/ Polylang sites<\\/li>\\n<li>FIX [PRO] Article schema: X handle and domain are normalized in <code>sameAs<\\/code><\\/li>\\n<li>FIX [PRO] Breadcrumbs: display a name fallback when a crumb has no URL<\\/li>\\n<li>FIX [PRO] Translations now load correctly when running WP-CLI commands or cron jobs<\\/li>\\n<li>FIX [PRO] CSV export: cleaner error messages, no leftover data between exports<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/changelog\\/\\\">View our complete changelog<\\/a>\\n<a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/how-to-downgrade-seopress-pro-to-a-previous-version\\/\\\">Need to downgrade\\/rollback?<\\/a><\\/p>\",\"installation\":\"<ol>\\n<li>Upload <code>wp-seopress<\\/code> to <code>\\/wp-content\\/plugins\\/<\\/code>, or install via <strong>Plugins \\u2192 Add New<\\/strong> in your WordPress admin.<\\/li>\\n<li>Activate SEOPress through the <strong>Plugins<\\/strong> menu.<\\/li>\\n<li>Run the installation wizard from <strong>SEO<\\/strong> in the admin sidebar.<\\/li>\\n<\\/ol>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/get-started-seopress\\/\\\">Full installation &amp; getting-started guide \\u2192<\\/a><\\/p>\"},\"license_check\":\"\",\"msg\":\"No license key has been provided.\",\"homepage\":\"https:\\/\\/www.seopress.org\\/\",\"package\":\"\",\"icons\":{\"1x\":\"https:\\/\\/www.seopress.org\\/wp-content\\/uploads\\/edd\\/2024\\/02\\/logo-square-seopress-pro-128x128.png\",\"2x\":\"https:\\/\\/www.seopress.org\\/wp-content\\/uploads\\/edd\\/2024\\/02\\/logo-square-seopress-pro-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/wp-seopress\\/assets\\/banner-1544x500.png?rev=1\",\"low\":\"https:\\/\\/ps.w.org\\/wp-seopress\\/assets\\/banner-772x250.png?rev=1\"},\"slug\":\"wp-seopress-pro\",\"url\":\"https:\\/\\/www.seopress.org\\/downloads\\/seopress-pro\\/?changelog=1\",\"last_updated\":\"2026-05-25 08:35:18\",\"download_link\":\"\",\"upgrade_notice\":\"\",\"stable_tag\":\"9.9\",\"tested\":\"7.0\",\"description\":[\"<h3>SEOPress \\u2013 The fast, privacy-first WordPress SEO plugin, ready for AI search<\\/h3>\\n<p><strong>Rank higher in Google AND in AI answer engines<\\/strong> (ChatGPT, Claude, Perplexity, Gemini). SEOPress is the all-in-one WordPress SEO plugin trusted by <strong>350,000+ websites since 2017<\\/strong>: fully white label, <strong>privacy by design<\\/strong>, and now AI-ready.<\\/p>\\n<p>[youtube <a href=\\\"https:\\/\\/www.youtube.com\\/watch?v=4ysKFVr_nu0\\\">https:\\/\\/www.youtube.com\\/watch?v=4ysKFVr_nu0<\\/a>]<\\/p>\\n<p>&#x2714; <strong>One SEO plugin, every page builder<\\/strong>: Universal SEO metabox for Gutenberg, Elementor, Divi, Bricks, Oxygen, Breakdance, WPBakery, Avada, Kadence and more. <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/page-builders-integration\\/\\\">See all integrations<\\/a>.\\n&#x2714; <strong>AI-powered metadata<\\/strong>: Generate SEO titles, meta descriptions, Open Graph, X (Twitter) Cards and image alt text in bulk with OpenAI, Google Gemini, Anthropic Claude, MistralAI or DeepSeek. <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/openai\\/\\\">Learn more<\\/a>.\\n&#x2714; <strong>Built for AI search (AEO \\/ GEO)<\\/strong>: Native llms.txt support and one-click Agent Readiness toggle so ChatGPT, Claude, Perplexity &amp; Gemini understand your content.\\n&#x2714; <strong>Privacy-first &amp; fully white label<\\/strong>: No tracking, no data footprint, no upsells in admin. Your data stays yours. <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/seopress-white-label\\/\\\">Why white label matters<\\/a>.\\n&#x2714; <strong>Content analysis with unlimited target keywords<\\/strong>: No artificial limit per post.\\n&#x2714; <strong>Migrate in one click<\\/strong>: From Yoast SEO, Rank Math, AIOSEO, The SEO Framework, Slim SEO, SmartCrawl, Squirrly, SEO Ultimate, WP Meta SEO, Premium SEO Pack, SiteSEO. <a href=\\\"https:\\/\\/www.seopress.org\\/solutions\\/migrate-from\\/\\\">Start migration<\\/a>.\\n&#x2714; <strong>Translated into 27+ languages<\\/strong> with professional translations. <a href=\\\"https:\\/\\/translate.wordpress.org\\/projects\\/wp-plugins\\/wp-seopress\\\">Help translate<\\/a>.<\\/p>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>SEOPress PRO from $49\\/year: 1 site \\u2022 Unlimited sites for $149\\/year<\\/strong><\\/a><\\/p>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/\\\">Features<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/solutions\\/migrate-from\\/\\\">Migrate<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/wordpress-seo-plugins\\/pro\\/\\\">PRO<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/integrations\\/\\\">Integrations<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/\\\">Support<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/seopress-white-label\\/\\\">White Label<\\/a> | <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/openai\\/\\\">AI<\\/a><\\/p>\\n<h3>What\'s new in SEOPress 9.9<\\/h3>\\n<p>A major UX release: redesigned SEO dashboard, smarter SEO box, sharper Content Analysis and a fully accessible admin.<\\/p>\\n<ul>\\n    <li><strong>&#x1f9ed; Brand new SEO dashboard &amp; admin header<\\/strong>: Cleaner two-column layout, one-click module toggles, guided \\\"Get Started\\\" with numbered steps, and quick access to Help, Display options and notifications (with counter badge) on every SEO page.<\\/li>\\n    <li><strong>&#x1fa84; Setup wizard, fully redesigned<\\/strong>: Faster, mobile-friendly, and easier to follow from start to finish.<\\/li>\\n    <li><strong>&#x26a1; Smarter SEO box<\\/strong>: Double-click target keywords to edit in place, Google keyword suggestions with autocomplete as you type, and a single \\\"Update\\\" in the Block Editor now saves every section at once (Title, Description, Advanced, Social, Redirections, Content Analysis).<\\/li>\\n    <li><strong>&#x1f4dd; Content Analysis<\\/strong>: New content quality &amp; structure checks to help you write better articles, plus the ability to hide an issue you don\'t want to fix on a given page.<\\/li>\\n    <li><strong>&#x1f504; One-click migration from SureRank<\\/strong> and a full migration from SmartCrawl (variables in your titles &amp; descriptions are automatically translated).<\\/li>\\n    <li><strong>&#x1f6e0;&#xfe0f; Tools redesigned<\\/strong>: Reset page with confirmation prompts so nothing happens by accident, and Import \\/ Export with a cleaner layout, \\\"export everything\\\" by default, and a Cancel button on CSV exports.<\\/li>\\n    <li><strong>&#x1f441;&#xfe0f; Appearance \\u203a Columns<\\/strong>: Live preview of your post lists with grouped checkboxes \\u2014 see what you\'ll get before you save.<\\/li>\\n    <li><strong>&#x267f; Big accessibility upgrade<\\/strong> across the whole SEO admin (WCAG 2.1 AA \\/ RGAA 4.1 compliant), and the admin now matches your WordPress color scheme automatically.<\\/li>\\n    <li><strong>&#x1f4ca; Site Overview on the dashboard<\\/strong> (PRO): Your Google Analytics 4 and Matomo stats directly on the SEO dashboard, with period &amp; metric filters, an interactive chart, and a sync button.<\\/li>\\n    <li><strong>&#x1f3ac; Video schema auto-filled<\\/strong> (PRO): Populated from the first YouTube video found in your post \\u2014 no manual copy-paste.<\\/li>\\n    <li><strong>&#x21aa;&#xfe0f; Redirections<\\/strong> (PRO): Quick Edit, search results that stay when you go back, search by destination URL, and a dedicated 404 view with a \\\"Delete 404s\\\" shortcut.<\\/li>\\n    <li><strong>&#x1fa7a; Site Audit<\\/strong> (PRO): Detects the new content quality &amp; structure issues.<\\/li>\\n    <li><strong>&#x1f30d; Better Search Console URL matching<\\/strong> (PRO) for multilingual sites (WPML \\/ Polylang).<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/newsroom\\/product-news\\/seopress-9-9\\/\\\"><strong>Read the full 9.9 release notes \\u2192<\\/strong><\\/a><\\/p>\\n<h3>Why SEOPress is the best WordPress SEO plugin?<\\/h3>\\n<ul>\\n    <li><strong>All-in-one<\\/strong>: Schemas, redirections, XML sitemaps, GSC, image SEO, breadcrumbs, broken links and more in one plugin. Fewer plugins, fewer conflicts, lower maintenance.<\\/li>\\n    <li><strong>Modular<\\/strong>: Don\'t need a feature? Disable it in one click without losing your settings.<\\/li>\\n    <li><strong>Affordable<\\/strong>: PRO from $49\\/year for 1 site. Unlimited sites for $149\\/year. No \\\"agency\\\" tax.<\\/li>\\n    <li><strong>White label by default<\\/strong>: Replace plugin name, logo, links and screens. Perfect for agencies and freelancers.<\\/li>\\n    <li><strong>GDPR-friendly<\\/strong>: Privacy by design. Built-in compatibility with consent platforms.<\\/li>\\n    <li><strong>Beginner to expert<\\/strong>: Installation wizard for newcomers, hundreds of hooks, REST API and WP-CLI for developers. Free <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/\\\">guides<\\/a> and <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/ebooks\\/\\\">SEO ebooks<\\/a>.<\\/li>\\n    <li><strong>Battle-tested<\\/strong>: 350,000+ active installs, weekly releases, dedicated team since 2017.<\\/li>\\n<\\/ul>\\n<h3>SEOPress Free Features<\\/h3>\\n<ul>\\n    <li><strong>Installation wizard<\\/strong>: Get configured in minutes.<\\/li>\\n    <li><strong>Universal SEO metabox<\\/strong>: Edit titles, descriptions, Open Graph, X Cards, schema, robots and canonical from any editor (Gutenberg, Elementor, Divi, Bricks, Oxygen, Breakdance, WPBakery, Avada, Kadence\\u2026).<\\/li>\\n    <li><strong>Command palette<\\/strong> (Cmd\\/Ctrl+K): Jump to any setting instantly.<\\/li>\\n    <li><strong>Content analysis<\\/strong> with **unlimited target keywords** to write content that ranks.<\\/li>\\n    <li><strong>Mobile &amp; Desktop Google preview<\\/strong>: See your SERP snippet before you publish.<\\/li>\\n    <li><strong>Facebook &amp; X (Twitter) social preview<\\/strong> for higher CTR on social.<\\/li>\\n    <li><strong>Titles &amp; meta descriptions<\\/strong> with <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/manage-titles-meta-descriptions\\/\\\">dynamic variables<\\/a> (custom fields, terms, taxonomies).<\\/li>\\n    <li><strong>Open Graph &amp; X (Twitter) Cards<\\/strong> for Facebook, LinkedIn, Instagram, Pinterest, WhatsApp, Threads\\u2026<\\/li>\\n    <li><strong>Google Knowledge Graph<\\/strong>: Organization data with address &amp; legal fields (new in 9.8).<\\/li>\\n    <li><strong>llms.txt &amp; Agent Readiness<\\/strong>: Help AI search engines understand your site (new in 9.8).<\\/li>\\n    <li><strong>Google Analytics 4 &amp; Matomo<\\/strong>: Downloads tracking, custom dimensions, IP anonymization, remarketing, demographics, cross-domain tracking, GDPR-friendly.<\\/li>\\n    <li><strong>Microsoft Clarity<\\/strong> integration: Free heatmaps and session recordings.<\\/li>\\n    <li><strong>Custom canonical URLs<\\/strong> and <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/manage-meta-robots\\/\\\">meta robots<\\/a> (noindex, nofollow, noimageindex, nosnippet).<\\/li>\\n    <li><strong>XML sitemaps<\\/strong> (posts, pages, CPTs, taxonomies, images, authors): <a href=\\\"https:\\/\\/www.seopress.org\\/features\\/sitemaps\\/\\\">faster than ever<\\/a> in 9.8.<\\/li>\\n    <li><strong>HTML sitemap<\\/strong> for accessibility &amp; navigation.<\\/li>\\n    <li><strong>Image XML sitemap<\\/strong> for Google Images.<\\/li>\\n    <li><strong>Redirections<\\/strong> at the post \\/ page \\/ CPT level.<\\/li>\\n    <li><strong>URL clean-up<\\/strong>: Remove \\/category\\/, \\/product-category\\/, ?replytocom; redirect attachment pages to parent or file URL.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/image-seo\\/\\\"><strong>Image SEO<\\/strong><\\/a>: Auto-set image title, alt, caption and description.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/google-indexing-api-with-seopress\\/\\\"><strong>Google Indexing API &amp; IndexNow<\\/strong><\\/a> (Bing\\/Yandex) for instant indexing.<\\/li>\\n    <li><strong>Import\\/export settings<\\/strong> from site to site.<\\/li>\\n    <li><strong>One-click migration<\\/strong> from Yoast, Rank Math, AIOSEO, SEO Framework, SureRank, Slim SEO, SmartCrawl, Squirrly, SEO Ultimate, WP Meta SEO, Premium SEO Pack, SiteSEO.<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/wordpress-seo-plugins\\/free\\/features\\/\\\">Check out all SEOPress Free features here<\\/a><\\/p>\\n<h3>SEOPress PRO: Take SEO further<\\/h3>\\n<p>[youtube <a href=\\\"https:\\/\\/youtu.be\\/zxGCY-bJYwE\\\">https:\\/\\/youtu.be\\/zxGCY-bJYwE<\\/a>]<\\/p>\\n<ul>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/openai\\/\\\"><strong>AI SEO<\\/strong><\\/a>: Auto-generate titles, descriptions, OG \\/ X tags and image alt text in bulk with OpenAI, Google Gemini (incl. **Gemini 3 Flash &amp; 3.1 Pro**), Anthropic Claude, MistralAI, DeepSeek.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/site-audit\\/\\\"><strong>Site Audit<\\/strong><\\/a>: Full React + DataViews experience with **GSC-backed recommendations**, scan history, live progress, one-click AI alt text fixes, CSV export.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/seo-alerts\\/\\\"><strong>SEO alerts<\\/strong><\\/a>: Be warned before SEO regressions hit production.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-search-console\\/\\\"><strong>Google Search Console<\\/strong><\\/a>: Clicks, impressions, CTR, average position right inside post lists.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-suggest\\/\\\"><strong>Google Suggestions<\\/strong><\\/a> in content analysis for long-tail keyword discovery.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/301-redirects\\/\\\"><strong>Redirect manager<\\/strong><\\/a>: Unlimited 301\\/302\\/307\\/410\\/451 redirects, regex, URL tester modal, categories, CSV\\/htaccess import &amp; export.<\\/li>\\n    <li><strong>404 monitoring &amp; auto-redirect<\\/strong> with email notifications.<\\/li>\\n    <li><strong>Broken link checker<\\/strong>: Reliable CRON-based batch scan, even on the largest sites.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-structured-data-types\\/\\\"><strong>Schema.org \\/ JSON-LD editor<\\/strong><\\/a> with **live preview**: Article, LocalBusiness, Service, How-to, FAQ, Course, Recipe, SoftwareApplication, Video, Event, Product, JobPosting, Review, ProfilePage, Custom schema.<\\/li>\\n    <li><strong>Automatic schemas<\\/strong> with advanced conditions (AND\\/OR, post types, taxonomies).<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/breadcrumbs\\/\\\"><strong>Accessible breadcrumbs<\\/strong><\\/a>: Schema.org, A11Y-ready, live preview, custom per CPT\\/term.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/local-seo\\/\\\"><strong>Local SEO<\\/strong><\\/a>: Local Business schema with opening hours, multiple stores.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/woocommerce-seo\\/\\\"><strong>WooCommerce SEO<\\/strong><\\/a>: Product schema with global identifiers (GTIN, MPN, brand), Enhanced Ecommerce, OG price\\/currency, noindex on cart\\/checkout\\/account.<\\/li>\\n    <li><strong>Easy Digital Downloads<\\/strong> integration.<\\/li>\\n    <li><strong>Internal linking suggestions<\\/strong>.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/sitemaps\\/\\\"><strong>Video XML Sitemap<\\/strong><\\/a> with automatic YouTube discovery + **Google News sitemap**.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/google-analytics\\/\\\"><strong>Google Analytics dashboard<\\/strong><\\/a>: Metrics inside WordPress, no context switching.<\\/li>\\n    <li><strong>PageSpeed Insights &amp; Core Web Vitals<\\/strong> reports.<\\/li>\\n    <li><a href=\\\"https:\\/\\/www.seopress.org\\/features\\/htaccess-robots-txt\\/\\\"><strong>robots.txt &amp; .htaccess editor<\\/strong><\\/a>: Multisite \\/ multidomain ready.<\\/li>\\n    <li><strong>Custom RSS feed<\\/strong> options.<\\/li>\\n    <li><strong>Multilingual llms.txt<\\/strong> with TranslatePress.<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>Get SEOPress PRO \\u2192<\\/strong><\\/a><\\/p>\\n<h3>SEOPress Insights: Track rankings &amp; backlinks inside WordPress<\\/h3>\\n<ul>\\n    <li><strong>Keyword rank tracker<\\/strong>: 52 Google Search locations.<\\/li>\\n    <li>Track <strong>50 keywords\\/site daily<\\/strong>.<\\/li>\\n    <li><strong>Competitor tracking<\\/strong>: See who outranks you.<\\/li>\\n    <li><strong>Backlinks<\\/strong> monitored weekly.<\\/li>\\n    <li><strong>Google Trends<\\/strong>: Find new content angles.<\\/li>\\n    <li><strong>Lifetime data access<\\/strong>: Export to CSV \\/ PDF \\/ Excel.<\\/li>\\n    <li><strong>Email &amp; Slack alerts<\\/strong>.<\\/li>\\n<\\/ul>\\n<p>[youtube <a href=\\\"https:\\/\\/youtu.be\\/p6v9Jd5lRIU\\\">https:\\/\\/youtu.be\\/p6v9Jd5lRIU<\\/a>]<\\/p>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>Get SEOPress Insights \\u2192<\\/strong><\\/a><\\/p>\\n<h3>WooCommerce &amp; EDD SEO (SEOPress PRO)<\\/h3>\\n<ul>\\n    <li>Product schema with global identifiers (GTIN, MPN, brand).<\\/li>\\n    <li>OG price &amp; currency for richer social shares.<\\/li>\\n    <li>XML sitemaps for products, including image galleries.<\\/li>\\n    <li>Centralized noindex for cart\\/checkout\\/account\\/thank-you pages.<\\/li>\\n    <li>Removes WooCommerce\\/EDD generator meta tag.<\\/li>\\n    <li>Manual or automatic JSON-LD product schemas.<\\/li>\\n    <li>Breadcrumbs with WooCommerce support.<\\/li>\\n    <li>Global dynamic tags for titles &amp; meta descriptions.<\\/li>\\n    <li>Google Enhanced Ecommerce: purchases, product views, cart events.<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/pricing\\/\\\"><strong>Boost your store\'s SEO \\u2192<\\/strong><\\/a><\\/p>\\n<h3>Universal SEO metabox: works with every editor<\\/h3>\\n<p>[youtube <a href=\\\"https:\\/\\/youtu.be\\/sf0ocG7vQMM\\\">https:\\/\\/youtu.be\\/sf0ocG7vQMM<\\/a>]<\\/p>\\n<p>Edit your SEO directly inside Gutenberg, Elementor, Divi, Bricks, Oxygen, Breakdance, WPBakery, Avada, Kadence, WP Fusion. <strong>No more back-and-forth<\\/strong> between page builder and WordPress admin.<\\/p>\\n<h3>Built for developers<\\/h3>\\n<ul>\\n    <li><strong>Hundreds of hooks<\\/strong>: <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/hooks\\/\\\">Browse the hooks reference<\\/a>.<\\/li>\\n    <li><strong>REST API<\\/strong>: Power headless and static sites. <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/get-started-with-the-seopress-rest-api\\/\\\">Get started<\\/a>.<\\/li>\\n    <li><strong>WP-CLI commands<\\/strong>: Automate everything. <a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/seopress-wp-cli\\/\\\">CLI reference<\\/a>.<\\/li>\\n    <li><strong>13+ new dev hooks in 9.8<\\/strong>.<\\/li>\\n<\\/ul>\\n<h3>From the same team<\\/h3>\\n<a href=\\\"https:\\/\\/wordpress.org\\/plugins\\/mailerpress\\/\\\">Try MailerPress, the best email marketing plugin for WordPress<\\/a>\"],\"changelog\":[\"<h4> 9.9 <a href=\\\"https:\\/\\/www.seopress.org\\/newsroom\\/product-news\\/seopress-9-9\\/\\\">Read the blog post update<\\/a> <\\/h4>\\n<ul>\\n<li>NEW Brand new SEO dashboard and admin header: cleaner two-column layout, one-click module toggles, a guided \\\"Get Started\\\" with numbered steps, and quick access to Help, Display options and notifications (with counter badge) on every SEO page<\\/li>\\n<li>NEW Setup wizard fully redesigned: faster, mobile-friendly, and easier to follow from start to finish<\\/li>\\n<li>NEW Smarter SEO box: double-click your target keywords to edit them in place, Google keyword suggestions with autocomplete as you type, and clicking \\\"Update\\\" in the Block Editor now saves every section at once (Title, Description, Advanced, Social, Redirections, Content Analysis)<\\/li>\\n<li>NEW Content Analysis: new content quality &amp; structure checks to help you write better articles, plus the ability to hide an issue you don\'t want to fix on a given page<\\/li>\\n<li>NEW One-click migration from SureRank, and a full migration from SmartCrawl (variables in your titles &amp; descriptions are automatically translated)<\\/li>\\n<li>NEW Tools redesigned: Reset page with confirmation prompts so nothing happens by accident, and Import \\/ Export with a cleaner layout, \\\"export everything\\\" by default, and a Cancel button on CSV exports<\\/li>\\n<li>NEW Appearance \\u203a Columns: live preview of your post lists with grouped checkboxes \\u2014 see what you\'ll get before you save<\\/li>\\n<li>NEW Category URL settings now read directly from your WordPress permalink settings (no risk of mismatch)<\\/li>\\n<li>NEW Easier-to-remember date variables for schemas (ISO 8601 aliases)<\\/li>\\n<li>NEW Big accessibility upgrade across the whole SEO admin (WCAG 2.1 AA \\/ RGAA 4.1 compliant), and the admin now matches your WordPress color scheme automatically<\\/li>\\n<li>NEW Cleaner dashboard: removed the Newsroom and SEO Ebooks sections<\\/li>\\n<li>NEW [PRO] Site Overview now shows your Google Analytics 4 and Matomo stats directly on the SEO dashboard, with period &amp; metric filters, an interactive chart, and a sync button<\\/li>\\n<li>NEW [PRO] Video schema is auto-filled from the first YouTube video found in your post \\u2014 no manual copy-paste<\\/li>\\n<li>NEW [PRO] Redirections: Quick Edit, search results that stay when you go back, search by destination URL, and a dedicated 404 view with a \\\"Delete 404s\\\" shortcut<\\/li>\\n<li>NEW [PRO] Friendlier empty states on Schemas and Broken Links screens (clear guidance when there\'s nothing yet)<\\/li>\\n<li>NEW [PRO] Site Audit: detects the new content quality &amp; structure issues<\\/li>\\n<li>NEW [PRO] Better Search Console URL matching for multilingual sites (WPML \\/ Polylang), <\\/li>\\n<li>NEW Developer filters: <code>seopress_search_console_match_url<\\/code>, <code>seopress_search_console_match_post_id<\\/code>, and <code>seopress_gtag_ec_item_id<\\/code> to customize the product identifier sent to GA4<\\/li>\\n<li>INFO Tested up to WordPress 7.0<\\/li>\\n<li>FIX Google snippet preview now displays the correct title and description, and no longer shows the Elementor template instead of your actual post<\\/li>\\n<li>FIX Internal Linking tab no longer crashes the whole SEO box, and the tag picker no longer scrolls uncontrollably when hovering the last item<\\/li>\\n<li>FIX Title \\/ meta description templates: spaces around variables are preserved on save, and custom field variables (%%<em>cf<\\/em><em>%%, %%<\\/em><em>ct<\\/em>%%, %%<em>ucf<\\/em>*%%) now work on the home page and blog page<\\/li>\\n<li>FIX White-label \\\"remove help links\\\" setting is now respected in the new admin header<\\/li>\\n<li>FIX SEOPress columns and bulk actions in your post lists are restored after toggling the metabox option (and no error when the bulk actions list is empty)<\\/li>\\n<li>FIX Notifications counter and \\\"hide notification\\\" behavior now work as expected<\\/li>\\n<li>FIX X (Twitter) handle is now cleaned up automatically in social tags<\\/li>\\n<li>FIX [PRO] Custom automatic schemas created in the new editor are now correctly displayed on the front-end, and the Knowledge Graph logo appears in the JSON-LD preview<\\/li>\\n<li>FIX [PRO] Redirections: URLs with accented \\/ non-Latin characters are saved correctly, and sorting (hits, type, last hit\\u2026) + category counts now match what\'s shown in the list<\\/li>\\n<li>FIX [PRO] OpenAI \\\"Test connection\\\" now works again after OpenAI retired the previous endpoint<\\/li>\\n<li>FIX [PRO] AI metadata generation now uses the correct language per post on WPML \\/ Polylang sites<\\/li>\\n<li>FIX [PRO] Article schema: X handle and domain are normalized in <code>sameAs<\\/code><\\/li>\\n<li>FIX [PRO] Breadcrumbs: display a name fallback when a crumb has no URL<\\/li>\\n<li>FIX [PRO] Translations now load correctly when running WP-CLI commands or cron jobs<\\/li>\\n<li>FIX [PRO] CSV export: cleaner error messages, no leftover data between exports<\\/li>\\n<\\/ul>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/changelog\\/\\\">View our complete changelog<\\/a>\\n<a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/how-to-downgrade-seopress-pro-to-a-previous-version\\/\\\">Need to downgrade\\/rollback?<\\/a><\\/p>\"],\"installation\":[\"<ol>\\n<li>Upload <code>wp-seopress<\\/code> to <code>\\/wp-content\\/plugins\\/<\\/code>, or install via <strong>Plugins \\u2192 Add New<\\/strong> in your WordPress admin.<\\/li>\\n<li>Activate SEOPress through the <strong>Plugins<\\/strong> menu.<\\/li>\\n<li>Run the installation wizard from <strong>SEO<\\/strong> in the admin sidebar.<\\/li>\\n<\\/ol>\\n<p><a href=\\\"https:\\/\\/www.seopress.org\\/support\\/guides\\/get-started-seopress\\/\\\">Full installation &amp; getting-started guide \\u2192<\\/a><\\/p>\"],\"plugin\":\"wp-seopress-pro\\/seopress-pro.php\",\"id\":\"wp-seopress-pro\\/seopress-pro.php\",\"requires\":\"\",\"requires_php\":\"\"}\";}', 'off'),
