(10877, 'edd_sl_8f27e2599352cb07a6bd4001ae425ad3', 'a:2:{s:7:\"timeout\";i:1781543752;s:5:\"value\";s:3420:\"{\"name\":\"Gravity PDF\",\"new_version\":\"6.14.3\",\"stable_version\":\"6.14.3\",\"sections\":{\"description\":\"<p>Gravity PDF is the ultimate automation tool for generating digital PDFs using Gravity Forms.<\\/p>\\n\",\"changelog\":\"<p>6.14.3<\\/p>\\n<ul>\\n<li>&#x1f9f9; Housekeeping: WordPress 7.0 Compatibility<\\/li>\\n<li>&#x1f9f9; Housekeeping: Improved screen-reader support for admin pages<\\/li>\\n<li>&#x1f9f9; Housekeeping: Remove obsolete Gravity Forms cache workaround<\\/li>\\n<li>&#x1f41e; Bug: Honor PDF Conditional Logic toggle setting, so disabling it in the UI skips stale conditional rules<\\/li>\\n<li>&#x1f41e; Bug: Fix Rich Text Editor rendering error when switching PDF templates<\\/li>\\n<li>&#x1f41e; Bug: Preserve unsaved edits to the Template fields if switching to a PDF template with the same fields (eg. Core \\/ Invoice \\/ Certificate)<\\/li>\\n<li>&#x1f41e; Bug: Preserve the selected template when adding a new PDF<\\/li>\\n<li>&#x1f41e; Bug: Fix Gravity Forms 2.6+ version detection on PDF form-settings pages<\\/li>\\n<li>&#x1f41e; Bug: Fix regression in the Template Manager when an invalid .zip is uploaded<\\/li>\\n<li>&#x1f41e; Bug: Minor UI fixes in the Template Manager<\\/li>\\n<li>&#x1f41e; Bug: Fix regression in the Core Fonts installer when a download error occurs<\\/li>\\n<li>&#x1f41e; Bug: Reset Gravity Wiz Nested Form field IDs after each group in PDFs<\\/li>\\n<\\/ul>\\n<p>https:\\/\\/gravitypdf.com\\/shop\\/gravity-pdf\\/changelog<\\/p>\\n\"},\"license_check\":\"\",\"msg\":\"\",\"homepage\":\"https:\\/\\/gravitypdf.com\\/shop\\/gravity-pdf\\/\",\"package\":\"https:\\/\\/composer.gravitypdf.com\\/gravity-pdf-6.14.3.zip\",\"icons\":{\"1x\":\"https:\\/\\/resources.gravitypdf.com\\/uploads\\/2024\\/10\\/gravity-pdf-plugin-icon-128x128.png\",\"2x\":\"https:\\/\\/resources.gravitypdf.com\\/uploads\\/2024\\/10\\/gravity-pdf-plugin-icon-256x256.png\"},\"banners\":{\"high\":\"\",\"low\":\"\"},\"slug\":\"gravity-pdf\",\"url\":\"https:\\/\\/gravitypdf.com\\/shop\\/gravity-pdf\\/?changelog=1\",\"last_updated\":\"2026-05-20 19:43:38\",\"download_link\":\"https:\\/\\/composer.gravitypdf.com\\/gravity-pdf-6.14.3.zip\",\"upgrade_notice\":\"\",\"description\":[\"<p>Gravity PDF is the ultimate automation tool for generating digital PDFs using Gravity Forms.<\\/p>\\n\"],\"changelog\":[\"<p>6.14.3<\\/p>\\n<ul>\\n<li>&#x1f9f9; Housekeeping: WordPress 7.0 Compatibility<\\/li>\\n<li>&#x1f9f9; Housekeeping: Improved screen-reader support for admin pages<\\/li>\\n<li>&#x1f9f9; Housekeeping: Remove obsolete Gravity Forms cache workaround<\\/li>\\n<li>&#x1f41e; Bug: Honor PDF Conditional Logic toggle setting, so disabling it in the UI skips stale conditional rules<\\/li>\\n<li>&#x1f41e; Bug: Fix Rich Text Editor rendering error when switching PDF templates<\\/li>\\n<li>&#x1f41e; Bug: Preserve unsaved edits to the Template fields if switching to a PDF template with the same fields (eg. Core \\/ Invoice \\/ Certificate)<\\/li>\\n<li>&#x1f41e; Bug: Preserve the selected template when adding a new PDF<\\/li>\\n<li>&#x1f41e; Bug: Fix Gravity Forms 2.6+ version detection on PDF form-settings pages<\\/li>\\n<li>&#x1f41e; Bug: Fix regression in the Template Manager when an invalid .zip is uploaded<\\/li>\\n<li>&#x1f41e; Bug: Minor UI fixes in the Template Manager<\\/li>\\n<li>&#x1f41e; Bug: Fix regression in the Core Fonts installer when a download error occurs<\\/li>\\n<li>&#x1f41e; Bug: Reset Gravity Wiz Nested Form field IDs after each group in PDFs<\\/li>\\n<\\/ul>\\n<p>https:\\/\\/gravitypdf.com\\/shop\\/gravity-pdf\\/changelog<\\/p>\\n\"]}\";}', 'off'),
