ix.php\";s:10:\"screenshot\";s:74:\"https://brave.local/app/plugins/gravity-pdf/src/templates/images/rubix.png\";}s:109:\"/Users/mikevandenhoek/localsites/brave/app/public/web/app/plugins/gravity-pdf/src/templates/focus-gravity.php\";a:11:{s:8:\"template\";s:13:\"Focus Gravity\";s:7:\"version\";s:5:\"2.0.4\";s:11:\"description\";s:331:\"Focus Gravity providing a classic layout which epitomises Gravity Forms Print Preview. It\'s the familiar layout you\'ve come to love. Through the Template tab you can control the PDF header and footer, change the background color or image, and show or hide the form title, page names, HTML fields and the Section Break descriptions.\";s:6:\"author\";s:11:\"Gravity PDF\";s:10:\"author uri\";s:22:\"https://gravitypdf.com\";s:5:\"group\";s:4:\"Core\";s:20:\"required_pdf_version\";s:9:\"4.0-alpha\";s:4:\"tags\";s:102:\"Header, Footer, Background, Optional HTML Fields, Optional Page Fields, Combined Row, Alternate Colors\";s:2:\"id\";s:13:\"focus-gravity\";s:4:\"path\";s:109:\"/Users/mikevandenhoek/localsites/brave/app/public/web/app/plugins/gravity-pdf/src/templates/focus-gravity.php\";s:10:\"screenshot\";s:82:\"https://brave.local/app/plugins/gravity-pdf/src/templates/images/focus-gravity.png\";}s:107:\"/Users/mikevandenhoek/localsites/brave/app/public/web/app/plugins/gravity-pdf/src/templates/blank-slate.php\";a:11:{s:8:\"template\";s:11:\"Blank Slate\";s:7:\"version\";s:5:\"2.0.2\";s:11:\"description\";s:268:\"A print-friendly template focusing solely on the user-submitted data. Through the Template tab you can control the PDF header and footer, change the background color or image, and show or hide the form title, page names, HTML fields and the Section Break descriptions.\";s:6:\"author\";s:11:\"Gravity PDF\";s:10:\"author uri\";s:22:\"https://gravitypdf.com\";s:5:\"group\";s:4:\"Core\";s:20:\"required_pdf_version\";s:9:\"4.0-alpha\";s:4:\"tags\";s:70:\"Header, Footer, Background, Optional HTML Fields, Optional Page Fields\";s:2:\"id