(16406, 1, '_site_transient_wp_plugin_dependencies_plugin_data', 'a:4:{s:16:\"action-scheduler\";a:35:{s:4:\"name\";s:16:\"Action Scheduler\";s:4:\"slug\";s:16:\"action-scheduler\";s:7:\"version\";s:5:\"3.9.3\";s:6:\"author\";s:67:\"<a href=\"https://profiles.wordpress.org/automattic/\">Automattic</a>\";s:14:\"author_profile\";s:42:\"https://profiles.wordpress.org/automattic/\";s:12:\"contributors\";a:11:{s:10:\"automattic\";a:3:{s:7:\"profile\";s:42:\"https://profiles.wordpress.org/automattic/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/73edc627541112a447e978843cf72f516bdbf6350e7cbac10016c71ab1b8c8a1?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:10:\"Automattic\";}s:8:\"wpmuguru\";a:3:{s:7:\"profile\";s:40:\"https://profiles.wordpress.org/wpmuguru/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/23afb25faac780cb6ec9533b2ac9e5daedf7a1faf444b41db471b9529701f87e?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:11:\"Ron Rennick\";}s:14:\"claudiosanches\";a:3:{s:7:\"profile\";s:46:\"https://profiles.wordpress.org/claudiosanches/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/ac91c7d73bb4501567ab3790755bf001d53dac8d1f4311a2480a5fb62dfb180c?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:15:\"Claudio Sanches\";}s:15:\"peterfabian1000\";a:3:{s:7:\"profile\";s:47:\"https://profiles.wordpress.org/peterfabian1000/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/c25372df076206b9fe44dddd7ec6af6ba427d3fe2a457fa301fcb9cf90b23ddd?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:12:\"Peter Fabian\";}s:7:\"vedjain\";a:3:{s:7:\"profile\";s:39:\"https://profiles.wordpress.org/vedjain/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/eb19da24784b2f86d310a213b60c903b0a5464a6c725cf5fcabfd274383337c4?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:19:\"Vedanshu - Urumi.AI\";}s:8:\"jamosova\";a:3:{s:7:\"profile\";s:40:\"https://profiles.wordpress.org/jamosova/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/73f150b0172cbb319293e372b3b20f4b78f0d5fbe70558318f69aad70908e95a?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"Julia Amosova\";}s:16:\"obliviousharmony\";a:3:{s:7:\"profile\";s:48:\"https://profiles.wordpress.org/obliviousharmony/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/67851e0deeb2c6a7a4c238cf45c0e9694a919e2c5e02706c5852e67c4ad279c9?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:16:\"obliviousharmony\";}s:9:\"konamiman\";a:3:{s:7:\"profile\";s:41:\"https://profiles.wordpress.org/konamiman/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/ee97f225bf5be24cd3c3b04990b9fc3dfc67a2c9aaea418ec2bdd32e164ed9b1?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:23:\"Néstor Soriano Vilchez\";}s:8:\"sadowski\";a:3:{s:7:\"profile\";s:40:\"https://profiles.wordpress.org/sadowski/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/cee318a6ec06e747df7f70f274da4e0cf4adba60c59e12d660d0f5a6ba78658a?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:8:\"sadowski\";}s:5:\"royho\";a:3:{s:7:\"profile\";s:37:\"https://profiles.wordpress.org/royho/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/1beda14f19fa93030ba2c66359dc270286820af6c667cdfeb4e87833c747f3a0?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:5:\"royho\";}s:13:\"barryhughes-1\";a:3:{s:7:\"profile\";s:45:\"https://profiles.wordpress.org/barryhughes-1/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/6ce0f4afb77f8d32da9c43e9a39c84fcfb3ed0e9cac24f440c46a151946cdec8?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:5:\"Barry\";}}s:8:\"requires\";s:3:\"6.5\";s:6:\"tested\";s:5:\"6.8.5\";s:12:\"requires_php\";s:3:\"7.2\";s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:70;s:7:\"ratings\";a:5:{i:5;i:8;i:4;i:0;i:3;i:0;i:2;i:1;i:1;i:4;}s:11:\"num_ratings\";i:13;s:11:\"support_url\";s:54:\"https://wordpress.org/support/plugin/action-scheduler/\";s:15:\"support_threads\";i:2;s:24:\"support_threads_resolved\";i:1;s:15:\"active_installs\";i:20000;s:12:\"last_updated\";s:21:\"2025-07-15 9:33am GMT\";s:5:\"added\";s:10:\"2020-07-14\";s:8:\"homepage\";s:27:\"https://actionscheduler.org\";s:8:\"sections\";a:3:{s:11:\"description\";s:3164:\"<p>Action Scheduler is een schaalbare, traceerbare taak wachtrij voor het op de achtergrond verwerken van grote sets acties in WordPress. Het is speciaal ontworpen om verspreid te worden in WordPress plugins.</p>\n<p>Action Scheduler werkt door het triggeren van een actie hook om op een bepaald moment in de toekomst uit te voeren. Elke hook kan worden gepland met unieke gegevens, zodat callbacks bewerkingen op die gegevens kunnen uitvoeren. De hook kan ook worden gepland om op één of meer momenten te worden uitgevoerd.</p>\n<p>Zie het als een uitbreiding op <code>do_action()</code> die de mogelijkheid toevoegt om een hook te vertragen en te herhalen.</p>\n<h3>Battle-Tested Background Processing</h3>\n<p>Elke maand verwerkt Action Scheduler miljoenen betalingen voor <a href=\"https://woocommerce.com/products/woocommerce-subscriptions/\" rel=\"nofollow ugc\">Subscriptions</a> , webhooks voor <a href=\"https://wordpress.org/plugins/woocommerce/\" rel=\"ugc\">WooCommerce</a> en e-mails en andere gebeurtenissen voor een reeks andere plugins.</p>\n<p>Het is gezien op live sites waar wachtrijen van meer dan 50.000 opdrachten werden verwerkt en resource intensieve operaties, zoals het verwerken van betalingen en het aanmaken van orders, met een aanhoudende snelheid van meer dan 10.000 per uur werden uitgevoerd zonder de normale werking van de site negatief te beïnvloeden.</p>\n<p>Dit is allemaal op infrastructuur en WordPress sites buiten de controle van de plugin auteur.</p>\n<p>Als je plugin achtergrondverwerking nodig heeft, vooral van grote reeksen taken, kan Action Scheduler helpen.</p>\n<h3>Lees verder</h3>\n<p>Lees verder over hoe Action Scheduler werkt en hoe je het in je plugin gebruikt? Bekijk de documentatie op <a href=\"https://actionscheduler.org\" rel=\"nofollow ugc\">ActionScheduler.org</a>.</p>\n<p>Daar zul je vinden:</p>\n<ul>\n<li><a href=\"https://actionscheduler.org/usage/\" rel=\"nofollow ugc\">Gebruiksaanwijzing</a> : instructies voor installatie en gebruik van Action Scheduler</li>\n<li><a href=\"https://actionscheduler.org/wp-cli/\" rel=\"nofollow ugc\">WP CLI gids</a> : instructies voor het uitvoeren van Action Scheduler op schaal via WP CLI</li>\n<li><a href=\"https://actionscheduler.org/api/\" rel=\"nofollow ugc\">API referentie</a> : volledige referentiegids voor alle API functies</li>\n<li><a href=\"https://actionscheduler.org/admin/\" rel=\"nofollow ugc\">Beheergids</a> : gids voor het beheer van geplande acties via het beheerscherm</li>\n<li><a href=\"https://actionscheduler.org/perf/\" rel=\"nofollow ugc\">Gids voor achtergrondverwerking op schaal</a> : instructies voor het uitvoeren van Action Scheduler op schaal via de standaard WP Cron queue runner</li>\n</ul>\n<h3>Credits</h3>\n<p>Action Scheduler wordt ontwikkeld en onderhouden door <a href=\"http://automattic.com/\" rel=\"nofollow ugc\">Automattic</a> , met een aanzienlijke vroege ontwikkeling door <a href=\"https://flightless.us/\" rel=\"nofollow ugc\">Flightless</a>.</p>\n<p>Samenwerking is cool. We zouden graag met je samenwerken om Action Scheduler te verbeteren. <a href=\"https://github.com/woocommerce/action-scheduler/pulls\" rel=\"nofollow ugc\">Pull Requests</a> zijn welkom.</p>\n\";s:9:\"changelog\";s:11721:\"<h4>3.9.3 &#8211; 2025-07-15</h4>\n<ul>\n<li>Add hook &#8216;action_scheduler_ensure_recurring_actions&#8217; specifically for scheduling recurring actions.</li>\n<li>Assume an action is valid until proven otherwise.</li>\n<li>Implement SKIP LOCKED during action claiming.</li>\n<li>Import <code>get_flag_value()</code> from <code>WP_CLI\\Utils</code> before using.</li>\n<li>Make <code>$unique</code> available to all pre-creation/short-circuit hooks.</li>\n<li>Make version/source information available via new class.</li>\n<li>Only release claims on pending actions.</li>\n<li>Tweak &#8211; WP 6.8 compatibility.</li>\n<li>Update minimum supported php and phpunit versions.</li>\n<li>Update readme.txt.</li>\n<li>WP CLI get action command: correct parentheses/nesting of conditional checks.</li>\n</ul>\n<h4>3.9.2 &#8211; 2025-02-03</h4>\n<ul>\n<li>Fixed fatal errors by moving version info methods to a new class and deprecating conflicting ones in ActionScheduler_Versions</li>\n</ul>\n<h4>3.9.1 &#8211; 2025-01-21</h4>\n<ul>\n<li>A number of new WP CLI commands have been added, making it easier to manage actions in the terminal and from scripts.</li>\n<li>New wp action-scheduler source command to help determine how Action Scheduler is being loaded.</li>\n<li>Additional information about the active instance of Action Scheduler is now available in the Help pull-down drawer.</li>\n<li>Make some other nullable parameters explicitly nullable.</li>\n<li>Set option value to <code>no</code> rather than deleting.</li>\n</ul>\n<h4>3.9.0 &#8211; 2024-11-14</h4>\n<ul>\n<li>Minimum required version of PHP is now 7.1.  </li>\n<li>Performance improvements for the <code>as_pending_actions_due()</code> function.  </li>\n<li>Existing filter hook <code>action_scheduler_claim_actions_order_by</code> enhanced to provide callbacks with additional information.  </li>\n<li>Improved compatibility with PHP 8.4, specifically by making implicitly nullable parameters explicitly nullable.  </li>\n<li>A large number of coding standards-enhancements, to help reduce friction when submitting plugins to marketplaces and plugin directories. Special props @crstauf for this effort.  </li>\n<li>Minor documentation tweaks and improvements.</li>\n</ul>\n<h4>3.8.2 &#8211; 2024-09-12</h4>\n<ul>\n<li>Add missing parameter to the <code>pre_as_enqueue_async_action</code> hook.</li>\n<li>Bump minimum PHP version to 7.0.</li>\n<li>Bump minimum WordPress version to 6.4.</li>\n<li>Make the batch size adjustable during processing.</li>\n</ul>\n<h4>3.8.1 &#8211; 2024-06-20</h4>\n<ul>\n<li>Fix typos.</li>\n<li>Improve the messaging in our unidentified action exceptions.</li>\n</ul>\n<h4>3.8.0 &#8211; 2024-05-22</h4>\n<ul>\n<li>Documentation &#8211; Fixed typos in perf.md.</li>\n<li>Update &#8211; We now require WordPress 6.3 or higher.</li>\n<li>Update &#8211; We now require PHP 7.0 or higher.</li>\n</ul>\n<h4>3.7.4 &#8211; 2024-04-05</h4>\n<ul>\n<li>Give a clear description of how the $unique parameter works.</li>\n<li>Preserve the tab field if set.</li>\n<li>Tweak &#8211; WP 6.5 compatibility.</li>\n</ul>\n<h4>3.7.3 &#8211; 2024-03-20</h4>\n<ul>\n<li>Do not iterate over all of GET when building form in list table.</li>\n<li>Fix a few issues reported by PCP (Plugin Check Plugin).</li>\n<li>Try to save actions as unique even when the store doesn&#8217;t support it.</li>\n<li>Tweak &#8211; WP 6.4 compatibility.</li>\n<li>Update &#8220;Tested up to&#8221; tag to WordPress 6.5.</li>\n<li>update version in package-lock.json.</li>\n</ul>\n<h4>3.7.2 &#8211; 2024-02-14</h4>\n<ul>\n<li>No longer user variables in <code>_n()</code> translation function.</li>\n</ul>\n<h4>3.7.1 &#8211; 2023-12-13</h4>\n<ul>\n<li>update semver to 5.7.2 because of a security vulnerability in 5.7.1.</li>\n</ul>\n<h4>3.7.0 &#8211; 2023-11-20</h4>\n<ul>\n<li>Important: starting with this release, Action Scheduler follows an L-2 version policy (WordPress, and consequently PHP).</li>\n<li>Add extended indexes for hook_status_scheduled_date_gmt and status_scheduled_date_gmt.</li>\n<li>Catch and log exceptions thrown when actions can&#8217;t be created, e.g. under a corrupt database schema.</li>\n<li>Tweak &#8211; WP 6.4 compatibility.</li>\n<li>Update unit tests for upcoming dependency version policy.</li>\n<li>make sure hook action_scheduler_failed_execution can access original exception object.</li>\n<li>mention dependency version policy in usage.md.</li>\n</ul>\n<h4>3.6.4 &#8211; 2023-10-11</h4>\n<ul>\n<li>Performance improvements when bulk cancelling actions.</li>\n<li>Dev-related fixes.</li>\n</ul>\n<h4>3.6.3 &#8211; 2023-09-13</h4>\n<ul>\n<li>Use <code>_doing_it_wrong</code> in initialization check.</li>\n</ul>\n<h4>3.6.2 &#8211; 2023-08-09</h4>\n<ul>\n<li>Add guidance about passing arguments.</li>\n<li>Atomic option locking.</li>\n<li>Improve bulk delete handling.</li>\n<li>Include database error in the exception message.</li>\n<li>Tweak &#8211; WP 6.3 compatibility.</li>\n</ul>\n<h4>3.6.1 &#8211; 2023-06-14</h4>\n<ul>\n<li>Document new optional <code>$priority</code> arg for various API functions.</li>\n<li>Document the new <code>--exclude-groups</code> WP CLI option.</li>\n<li>Document the new <code>action_scheduler_init</code> hook.</li>\n<li>Ensure actions within each claim are executed in the expected order.</li>\n<li>Fix incorrect text domain.</li>\n<li>Remove SHOW TABLES usage when checking if tables exist.</li>\n</ul>\n<h4>3.6.0 &#8211; 2023-05-10</h4>\n<ul>\n<li>Add $unique parameter to function signatures.</li>\n<li>Add a cast-to-int for extra safety before forming new DateTime object.</li>\n<li>Add a hook allowing exceptions for consistently failing recurring actions.</li>\n<li>Add action priorities.</li>\n<li>Add init hook.</li>\n<li>Always raise the time limit.</li>\n<li>Bump minimatch from 3.0.4 to 3.0.8.</li>\n<li>Bump yaml from 2.2.1 to 2.2.2.</li>\n<li>Defensive coding relating to gaps in declared schedule types.</li>\n<li>Do not process an action if it cannot be set to <code>in-progress</code>.</li>\n<li>Filter view labels (status names) should be translatable | #919.</li>\n<li>Fix WPCLI progress messages.</li>\n<li>Improve data-store initialization flow.</li>\n<li>Improve error handling across all supported PHP versions.</li>\n<li>Improve logic for flushing the runtime cache.</li>\n<li>Support exclusion of multiple groups.</li>\n<li>Update lint-staged and Node/NPM requirements.</li>\n<li>add CLI clean command.</li>\n<li>add CLI exclude-group filter.</li>\n<li>exclude past-due from list table all filter count.</li>\n<li>throwing an exception if as_schedule_recurring_action interval param is not of type integer.</li>\n</ul>\n<h4>3.5.4 &#8211; 2023-01-17</h4>\n<ul>\n<li>Add pre filters during action registration.</li>\n<li>Async scheduling.</li>\n<li>Calculate timeouts based on total actions.</li>\n<li>Correctly order the parameters for <code>ActionScheduler_ActionFactory</code>&#8217;s calls to <code>single_unique</code>.</li>\n<li>Fetch action in memory first before releasing claim to avoid deadlock.</li>\n<li>PHP 8.2: declare property to fix creation of dynamic property warning.</li>\n<li>PHP 8.2: fix &#8220;Using ${var} in strings is deprecated, use {$var} instead&#8221;.</li>\n<li>Prevent <code>undefined variable</code> warning for <code>$num_pastdue_actions</code>.</li>\n</ul>\n<h4>3.5.3 &#8211; 2022-11-09</h4>\n<ul>\n<li>Query actions with partial match.</li>\n</ul>\n<h4>3.5.2 &#8211; 2022-09-16</h4>\n<ul>\n<li>Fix &#8211; erroneous 3.5.1 release.</li>\n</ul>\n<h4>3.5.1 &#8211; 2022-09-13</h4>\n<ul>\n<li>Onderhoud aan A/S-documenten.</li>\n<li>fix: PHP 8.2 deprecated notice.</li>\n</ul>\n<h4>3.5.0 &#8211; 2022-08-25</h4>\n<ul>\n<li>Add &#8211; The active view link within the &#8220;Tools &gt; Scheduled Actions&#8221; screen is now clickable.</li>\n<li>Add &#8211; A warning when there are past-due actions.</li>\n<li>Enhancement &#8211; Added the ability to schedule unique actions via an atomic operation.</li>\n<li>Enhancement &#8211; Improvements to cache invalidation when processing batches (when running on WordPress 6.0+).</li>\n<li>Enhancement &#8211; If a recurring action is found to be consistently failing, it will stop being rescheduled.</li>\n<li>Enhancement &#8211; Adds a new &#8220;Past Due&#8221; view to the scheduled actions list table.</li>\n</ul>\n<h4>3.4.2 &#8211; 2022-06-08</h4>\n<ul>\n<li>Fix &#8211; Change the include for better linting.</li>\n<li>Fix &#8211; update: Added Action scheduler completed action hook.</li>\n</ul>\n<h4>3.4.1 &#8211; 2022-05-24</h4>\n<ul>\n<li>Fix &#8211; Change the include for better linting.</li>\n<li>Fix &#8211; Fix the documented return type.</li>\n</ul>\n<h4>3.4.0 &#8211; 2021-10-29</h4>\n<ul>\n<li>Enhancement &#8211; Number of items per page can now be set for the Scheduled Actions view (props @ovidiul). #771</li>\n<li>Fix &#8211; Do not lower the max_execution_time if it is already set to 0 (unlimited) (props @barryhughes). #755</li>\n<li>Fix &#8211; Avoid triggering autoloaders during the version resolution process (props @olegabr). #731 &amp; #776</li>\n<li>Dev &#8211; ActionScheduler_wcSystemStatus PHPCS fixes (props @ovidiul). #761</li>\n<li>Dev &#8211; ActionScheduler_DBLogger.php PHPCS fixes (props @ovidiul). #768</li>\n<li>Dev &#8211; Fixed phpcs for ActionScheduler_Schedule_Deprecated (props @ovidiul). #762</li>\n<li>Dev &#8211; Improve actions table indices (props @glagonikas). #774 &amp; #777</li>\n<li>Dev &#8211; PHPCS fixes for ActionScheduler_DBStore.php (props @ovidiul). #769 &amp; #778</li>\n<li>Dev &#8211; PHPCS Fixes for ActionScheduler_Abstract_ListTable (props @ovidiul). #763 &amp; #779</li>\n<li>Dev &#8211; Adds new filter action_scheduler_claim_actions_order_by to allow tuning of the claim query (props @glagonikas). #773</li>\n<li>Dev &#8211; PHPCS fixes for ActionScheduler_WpPostStore class (props @ovidiul). #780</li>\n</ul>\n<h4>3.3.0 &#8211; 2021-09-15</h4>\n<ul>\n<li>Enhancement &#8211; Adds as_has_scheduled_action() to provide a performant way to test for existing actions. #645</li>\n<li>Fix &#8211; Improves compatibility with environments where NO_ZERO_DATE is enabled. #519</li>\n<li>Fix &#8211; Adds safety checks to guard against errors when our database tables cannot be created. #645</li>\n<li>Dev &#8211; Now supports queries that use multiple statuses. #649</li>\n<li>Dev &#8211; Minimumvereisten voor WordPress en PHP verhoogd (naar respectievelijk 5.2 en 5.6). #723</li>\n</ul>\n<h4>3.2.1 &#8211; 2021-06-21</h4>\n<ul>\n<li>Fix &#8211; Add extra safety/account for different versions of AS and different loading patterns. #714</li>\n<li>Fix &#8211; Handle hidden columns (Tools <span aria-hidden=\"true\" class=\"wp-exclude-emoji\">→</span> Scheduled Actions) | #600.</li>\n</ul>\n<h4>3.2.0 &#8211; 2021-06-03</h4>\n<ul>\n<li>Fix &#8211; Add &#8220;no ordering&#8221; option to as_next_scheduled_action().</li>\n<li>Fix &#8211; Add secondary scheduled date checks when claiming actions (DBStore) | #634.</li>\n<li>Fix &#8211; Add secondary scheduled date checks when claiming actions (wpPostStore) | #634.</li>\n<li>Fix &#8211; Adds a new index to the action table, reducing the potential for deadlocks (props: @glagonikas).</li>\n<li>Fix &#8211; Fix unit tests infrastructure and adapt tests to PHP 8.</li>\n<li>Fix &#8211; Identify in-use data store.</li>\n<li>Fix &#8211; Improve test_migration_is_scheduled.</li>\n<li>Fix &#8211; PHP notice on list table.</li>\n<li>Fix &#8211; Speed up clean up and batch selects.</li>\n<li>Fix &#8211; Update pending dependencies.</li>\n<li>Fix &#8211; [PHP 8.0] Only pass action arg values through to do_action_ref_array().</li>\n<li>Fix &#8211; [PHP 8] Set the PHP version to 7.1 in composer.json for PHP 8 compatibility.</li>\n<li>Fix &#8211; add is_initialized() to docs.</li>\n<li>Fix &#8211; fix file permissions.</li>\n<li>Fix &#8211; fixes #664 by replacing __ with esc_html__.</li>\n</ul>\n\";s:7:\"reviews\";s:19437:\"<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Did the job !</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/pscolv/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/76d878a087a59c429808970b4d460a31d0e276c7b9d285b866e4861ec24c37b0?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/76d878a087a59c429808970b4d460a31d0e276c7b9d285b866e4861ec24c37b0?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/pscolv/\" class=\"reviewer-name\">pol <small>(pscolv)</small></a> op <span class=\"review-date\">november 24, 2025</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I was missing the actionscheduler_logs table in my database. This plugin detected it and restored it.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Thanks for your efforts !</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Pascal. </p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">This plugin is broken and almost malicious in nature.</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"1 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"1\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/smokex365/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/b1dd33c2e454e9b6ef810bf9a8d199af48071065005c5268124f3aac421d41e2?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/b1dd33c2e454e9b6ef810bf9a8d199af48071065005c5268124f3aac421d41e2?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/smokex365/\" class=\"reviewer-name\">smokex365</a> op <span class=\"review-date\">oktober 28, 2025</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>I started wondering why my db server was tracking TB\'s of internal traffic. After a few days I tracked it down to this plugin. It was scheduling millions of claims and logs. You can\'t manage any of them through the GUI without other 3rd party plugins and even then Action Scheduler just re-adds anything tasks you delete or attempt to pause. This means GB\'s of useless garbage from claims and logs in my DB which slowed my server to a crawl trying to delete. I tried reinstalling the plugin. Tried pausing its schedule. Nothing work.  Well, not nothing. Uninstalling the plugin and deleting the tables it added worked fine. No more 4GB WP DB or 4-6TB or network traffic. Considering I never even intentionally installed this plugin I find it incredibly frustrating how broken and incomplete it is. Do better.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">It&#039;s great.</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/milafabio/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/258cc8821c1ea67de196920e77b9fe26bcd49144aeafdae5b26ac8349b9c8385?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/258cc8821c1ea67de196920e77b9fe26bcd49144aeafdae5b26ac8349b9c8385?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/milafabio/\" class=\"reviewer-name\">mfwriter <small>(milafabio)</small></a> op <span class=\"review-date\">maart 10, 2025</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Everything works as stated. There was a problem with hung tasks, now cron+wp cli executes everything. Other options did not work to solve the problem.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Incredibly powerful</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/aukepiersma/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/59b0253e5d04fe15f02efe46a8684eada33ce19105503a68e38e1d7accb7f9d3?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/59b0253e5d04fe15f02efe46a8684eada33ce19105503a68e38e1d7accb7f9d3?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/aukepiersma/\" class=\"reviewer-name\">Auke Piersma <small>(aukepiersma)</small></a> op <span class=\"review-date\">maart 18, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p class=\"\">What this plugin/library adds to WordPress is incredibly powerful. It\'s asynchronous execution of actions gives developers incredible possibilities. The fact that plugin developers have the option to integrate this plugin/library into their own plugins is fantastic. Keep up the good work!</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Like a Leech</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"1 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"1\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/traqbar/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/075ac5f9288dcc22b6bbf5058a062225573fe524cde7be8cc6953bcd97d88fee?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/075ac5f9288dcc22b6bbf5058a062225573fe524cde7be8cc6953bcd97d88fee?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/traqbar/\" class=\"reviewer-name\">traqbar</a> op <span class=\"review-date\">maart 5, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p class=\"\">Only tested it, I didnt like it, and now it wont leave. Manually removing tables – crashes my site. Sucking the life out of my server. I have to ask support for how to get rid of it.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Horrible Horrible</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">This is malware</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"1 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"1\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/forcesail/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/a8dca1230367f4be330bfce938659a6e5f67cee4bac6aeb8b5842e2aff2b41a2?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/a8dca1230367f4be330bfce938659a6e5f67cee4bac6aeb8b5842e2aff2b41a2?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/forcesail/\" class=\"reviewer-name\">Alexander Guskov <small>(forcesail)</small></a> op <span class=\"review-date\">december 17, 2023</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p class=\"\"><strong>This plugin is a classical malware:</strong><br />1) it acts hidden: it integrates in Wordpress core, don\'t identificate itself for site owner, don\'t allow any management of it\'s activity or control for site owner.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">2) It secretly and non-stop (every minute) allocates all server resources displacing all useful processes like processing user\'s requests and all others too. It slow down site in times. From my experience \"server response time\" decreased from 7-8s to 1,2s just as I started to limit this malware, but I still can\'t stop or remove it completely (there is no woocommerce on my site, but I believe that it were the result would be more impressive). </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">3) It acts as extension to Wordpress\'s wp_cron service. All that it does can be done under pure wp_cron but not hidden and without slowing down site. So, it\'s crear to understand that if some other plugin use Scheduled Actions it does it only to hide something from site owner eyes or/and slow down site (probably to upsale pro version that acts without Scheduled Actions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">4) There is no way how to completely stop neither uninstall it neither remove it\'s actions neither it\'s wp_cron task.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">5) It\'s impossible just to short circle some functions in it to stop it\'s working - it\'s code made the way that it break site down if someone try to stop it. I have found the way to limit it\'s activity but can\'t stop it completely.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">6) All question to developers regarding this behavior return with answer like \"it runs as we wish, keep enjoying slow down your site\" or buy our other plugins or employ us to find why your site is slow down. Explanations about clear difference with Scheduled Actions working as they with and limited they just ignore.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">I strictly advice plugin developer run a mile of this malware otherwise site owners have to remove already your plugins accusing already you in the fatal slow of their sites and probably with criminal charge (at least in EU).</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Great time savior plugin</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/unapersona/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/6782efc34064425c148ef7f5fffdba5a19de8609d6bdf51400f7ac3957db7e8b?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/6782efc34064425c148ef7f5fffdba5a19de8609d6bdf51400f7ac3957db7e8b?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/unapersona/\" class=\"reviewer-name\">unapersona</a> op <span class=\"review-date\">juni 28, 2023</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>A must-use if you want to schedule any type of task, no more <kbd>wp_schedule</kbd> headaches.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Refuses to Support</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"1 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"1\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/kevp75/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/f2bfc89a476a9d8a99060781f5e9dba4435b6e1b5dc4a673af23e3d9416f0a89?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/f2bfc89a476a9d8a99060781f5e9dba4435b6e1b5dc4a673af23e3d9416f0a89?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/kevp75/\" class=\"reviewer-name\">Kevin Pirnie <small>(kevp75)</small></a> op <span class=\"review-date\">maart 22, 2023</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Developers refuse to support their own plugin.  I have no use for something that does not work, and something the developers will not support.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Cannot and will not recommend to anyone... sadly will not make much of a difference because it\'s in use in every site that utilizes WooCommerce, but, whatever...</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Needs code placement instructions</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"2 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"2\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span><span class=\"star dashicons dashicons-star-empty\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/welcomeblack/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/3f85b82b45f442634497f2248c47d037761885421abf8bd82d14260e464e3f2d?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/3f85b82b45f442634497f2248c47d037761885421abf8bd82d14260e464e3f2d?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/welcomeblack/\" class=\"reviewer-name\">welcomeblack</a> op <span class=\"review-date\">november 8, 2022</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Look, I\'m fine with having to do some coding. After all, I want to write my own php code to be called every five minutes or so. But you have to tell me WHERE to put the calls. I\'ve installed your service via plugin, and your usage page (actionscheduler [dot] org [slash] usage) tells me exactly nothing about where I need to make these API calls. Is it function.php in my home WP directory? Can I make these calls from my own self-made directory? Tell me!</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Wonderful - a Project saver</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/keithrowley/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/617c6e62c889619ef2f92f5ca2ea7bcf0868921649bbcda500259dcc1bc78658?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/617c6e62c889619ef2f92f5ca2ea7bcf0868921649bbcda500259dcc1bc78658?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/keithrowley/\" class=\"reviewer-name\">KeithRowley</a> op <span class=\"review-date\">januari 6, 2022</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">I had migrated a ton of sites to a new server and (I thought) tested them. But one site malfunctioned when I tested it again and woocommerce would not activate without fatal errors.\nThe error involved the action scheduler Fatal error: Uncaught Error: Class \'Action_Scheduler\\Migration\\Controller\' not found in\n\nI had already paid a ton of money to migrate the site from another ecommerce system to woocommerce b efore this latest server change so this was a nightmare.\n\nYour plugin fixed it and saved me much heartache. Sincere thanks.\n</div>\n</div>\n\";}s:17:\"short_description\";s:47:\"Action Scheduler - Taak wachtrij voor WordPress\";s:13:\"download_link\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.9.3.zip\";s:14:\"upgrade_notice\";a:0:{}s:11:\"screenshots\";a:0:{}s:4:\"tags\";a:2:{s:4:\"cron\";s:4:\"cron\";s:9:\"scheduler\";s:9:\"scheduler\";}s:8:\"versions\";a:30:{s:5:\"3.1.6\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.1.6.zip\";s:5:\"3.2.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.2.0.zip\";s:5:\"3.2.1\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.2.1.zip\";s:5:\"3.3.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.3.0.zip\";s:5:\"3.4.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.4.0.zip\";s:5:\"3.4.1\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.4.1.zip\";s:5:\"3.4.2\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.4.2.zip\";s:5:\"3.5.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.5.0.zip\";s:5:\"3.5.1\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.5.1.zip\";s:5:\"3.5.2\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.5.2.zip\";s:5:\"3.5.3\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.5.3.zip\";s:5:\"3.5.4\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.5.4.zip\";s:5:\"3.6.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.6.0.zip\";s:5:\"3.6.1\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.6.1.zip\";s:5:\"3.6.2\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.6.2.zip\";s:5:\"3.6.3\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.6.3.zip\";s:5:\"3.6.4\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.6.4.zip\";s:5:\"3.7.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.7.0.zip\";s:5:\"3.7.1\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.7.1.zip\";s:5:\"3.7.2\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.7.2.zip\";s:5:\"3.7.3\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.7.3.zip\";s:5:\"3.7.4\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.7.4.zip\";s:5:\"3.8.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.8.0.zip\";s:5:\"3.8.1\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.8.1.zip\";s:5:\"3.8.2\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.8.2.zip\";s:5:\"3.9.0\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.9.0.zip\";s:5:\"3.9.1\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.9.1.zip\";s:5:\"3.9.2\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.9.2.zip\";s:5:\"3.9.3\";s:65:\"https://downloads.wordpress.org/plugin/action-scheduler.3.9.3.zip\";s:5:\"trunk\";s:59:\"https://downloads.wordpress.org/plugin/action-scheduler.zip\";}s:14:\"business_model\";b:0;s:14:\"repository_url\";s:0:\"\";s:22:\"commercial_support_url\";s:0:\"\";s:11:\"donate_link\";s:0:\"\";s:7:\"banners\";a:0:{}s:5:\"icons\";a:1:{s:7:\"default\";s:60:\"https://s.w.org/plugins/geopattern-icon/action-scheduler.svg\";}s:12:\"preview_link\";s:0:\"\";s:4:\"Name\";s:16:\"Action Scheduler\";}s:4:\"cmb2\";a:35:{s:4:\"name\";s:4:\"CMB2\";s:4:\"slug\";s:4:\"cmb2\";s:7:\"version\";s:6:\"2.12.0\";s:6:\"author\";s:74:\"<a href=\"https://profiles.wordpress.org/jtsternberg/\">Justin Sternberg</a>\";s:14:\"author_profile\";s:43:\"https://profiles.wordpress.org/jtsternberg/\";s:12:\"contributors\";a:3:{s:11:\"jtsternberg\";a:3:{s:7:\"profile\";s:43:\"https://profiles.wordpress.org/jtsternberg/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/32c5cc7746882995949359e61e2eb608a441551274a86242ecb9d04720bbf333?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:16:\"Justin Sternberg\";}s:13:\"webdevstudios\";a:3:{s:7:\"profile\";s:45:\"https://profiles.wordpress.org/webdevstudios/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/1871eb9cf5592f9aef06a1a2b2065ad6e24a0e5ddd7908c835a1f6d8ef4fa56e?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:13:\"webdevstudios\";}s:6:\"tw2113\";a:3:{s:7:\"profile\";s:38:\"https://profiles.wordpress.org/tw2113/\";s:6:\"avatar\";s:120:\"https://secure.gravatar.com/avatar/956d6d4d83a9fe6c96ae5af588fa4eccf961e003fc1e58e205a4c1a048510e79?s=96&d=monsterid&r=g\";s:12:\"display_name\";s:16:\"Michael Beckwith\";}}s:8:\"requires\";s:5:\"3.8.0\";s:6:\"tested\";s:3:\"7.0\";s:12:\"requires_php\";s:3:\"7.4\";s:16:\"requires_plugins\";a:0:{}s:6:\"rating\";i:100;s:7:\"ratings\";a:5:{i:5;i:90;i:4;i:0;i:3;i:0;i:2;i:0;i:1;i:1;}s:11:\"num_ratings\";i:91;s:11:\"support_url\";s:42:\"https://wordpress.org/support/plugin/cmb2/\";s:15:\"support_threads\";i:1;s:24:\"support_threads_resolved\";i:1;s:15:\"active_installs\";i:300000;s:12:\"last_updated\";s:21:\"2026-05-31 2:41am GMT\";s:5:\"added\";s:10:\"2014-09-16\";s:8:\"homepage\";s:28:\"https://github.com/CMB2/CMB2\";s:8:\"sections\";a:5:{s:11:\"description\";s:18474:\"<p>CMB2 is a developer&#8217;s toolkit for building metaboxes, custom fields, and forms for WordPress that will blow your mind. Easily manage meta for posts, terms, users, comments, or create custom option pages.</p>\n<p>CMB2 is a complete rewrite of Custom Metaboxes and Fields for WordPress. To get started, please follow the examples in the included <code>example-functions.php</code> file and have a look at the <a href=\"https://github.com/CMB2/CMB2/wiki/Basic-Usage\" rel=\"nofollow ugc\">basic usage instructions</a>.</p>\n<p>You can see a list of available field types <a href=\"https://github.com/CMB2/CMB2/wiki/Field-Types#types\" rel=\"nofollow ugc\">here</a>.</p>\n<h3>Contribution</h3>\n<p>Development occurs on Github, and all contributions welcome. Please read the <a href=\"https://github.com/CMB2/CMB2/blob/master/CONTRIBUTING.md\" rel=\"nofollow ugc\">CONTRIBUTING</a> doc for more details.</p>\n<p>A complete list of all our awesome contributors found here: <a href=\"https://github.com/CMB2/CMB2/graphs/contributors\" rel=\"nofollow ugc\">github.com/CMB2/CMB2/graphs/contributors</a></p>\n<h3>Features:</h3>\n<ul>\n<li>Create metaboxes to be used on post edit screens.</li>\n<li><a href=\"https://github.com/CMB2/CMB2/wiki/Using-CMB-to-create-an-Admin-Theme-Options-Page\" rel=\"nofollow ugc\">Create forms to be used on an options pages</a>.</li>\n<li>Create forms to handle user meta and display them on user profile add/edit pages.</li>\n<li>Create forms to handle term meta and display wherever your taxonomies are used.</li>\n<li><a href=\"https://github.com/CMB2/CMB2/wiki/Bringing-Metaboxes-to-the-Front-end\" rel=\"nofollow ugc\">Flexible API that allows you to use CMB forms almost anywhere, even on the front-end</a>.</li>\n<li><a href=\"https://github.com/CMB2/CMB2/wiki/Field-Types\" rel=\"nofollow ugc\">Several field types are included</a>.</li>\n<li><a href=\"https://github.com/CMB2/CMB2/wiki/Adding-your-own-field-types\" rel=\"nofollow ugc\">Custom API hook that allows you to create your own field types</a>.</li>\n<li>There are numerous hooks and filters, allowing you to modify many aspects of the library (without editing it directly).</li>\n<li>Repeatable fields for most field types are supported, as well as repeatable field groups.</li>\n<li>CMB2 is safe to bundle with any project. It will only load the newest version in the system.</li>\n</ul>\n<h3>Vertaling</h3>\n<p>If you are looking to provide language translation files, Please do so via <a href=\"https://translate.wordpress.org/projects/wp-plugins/cmb2\" rel=\"nofollow ugc\">WordPress Plugin Translations</a>.</p>\n<h3>Documentatie</h3>\n<ul>\n<li>CMB2 documentation can be found at <a href=\"https://github.com/CMB2/CMB2/wiki\" rel=\"nofollow ugc\">the CMB2 wiki</a> on github. Also, If you&#8217;re into reading code and inline documentation, we tried to keep all functions and methods fully inline-documented.</li>\n</ul>\n<h3>3rd Party Resources</h3>\n<p>Custom Field Types</p>\n<ul>\n<li><a href=\"https://github.com/coreymcollins/cmb-attached-posts\" rel=\"nofollow ugc\">CMB2 Field Type: CMB Attached Posts Field</a> from <a href=\"https://github.com/coreymcollins\" rel=\"nofollow ugc\">coreymcollins</a>: <code>custom_attached_posts</code>, for attaching posts to a page.</li>\n<li><a href=\"https://github.com/alexis-magina/cmb2-field-post-search-ajax\" rel=\"nofollow ugc\">CMB2 Field Type: Post Search Ajax</a> by <a href=\"https://github.com/alexis-magina\" rel=\"nofollow ugc\">alexis-magina</a>: <code>post_search_ajax</code> Attach posts to each other. Same approach as <a href=\"https://github.com/coreymcollins/cmb-attached-posts\" rel=\"nofollow ugc\">CMB2 Attached Posts Field</a> but with Ajax request, multiple/single option, and different UI.</li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-ajax-search\" rel=\"nofollow ugc\">CMB2 Field Type: Ajax Search</a> from <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: 3 different fields with the same UI in AJAX to search (with query parameters) to users, post type and taxonomy terms.</li>\n<li><a href=\"https://github.com/Mte90/CMB2-User-Search-field\" rel=\"nofollow ugc\">CMB2 Field Type: CMB2 User Search field</a> from <a href=\"https://github.com/Mte90\" rel=\"nofollow ugc\">Mte90</a>: <code>user_search_text</code> adds a user-search dialog for searching/attaching other User IDs.</li>\n<li>\n<p><a href=\"https://github.com/mustardBees/cmb_field_map\" rel=\"nofollow ugc\">CMB2 Field Type: Google Maps</a> from <a href=\"https://github.com/mustardBees\" rel=\"nofollow ugc\">mustardBees</a>: Custom field type for Google Maps.</p>\n<blockquote>\n<p>The <code>pw_map</code> field stores the latitude/longitude values which you can then use to display a map in your theme.</p>\n</blockquote>\n</li>\n<li>\n<p><a href=\"https://github.com/villeristi/CMB2-field-Leaflet-Geocoder\" rel=\"nofollow ugc\">CMB2 Field Type: Leaflet Maps</a> from <a href=\"https://github.com/villeristi\" rel=\"nofollow ugc\">villeristi</a>: Custom field type for <a href=\"https://leafletjs.com/\" rel=\"nofollow ugc\">Leaflet</a> Maps.</p>\n</li>\n<li>\n<p><a href=\"https://github.com/mustardBees/cmb-field-select2\" rel=\"nofollow ugc\">CMB2 Field Type: Select2</a> from <a href=\"https://github.com/mustardBees\" rel=\"nofollow ugc\">mustardBees</a>: Custom field types which use the <a href=\"https://select2.org/\" rel=\"nofollow ugc\">Select2</a> script:</p>\n<blockquote>\n<ol>\n<li>The <code>pw_select field</code> acts much like the default select field. However, it adds typeahead-style search allowing you to quickly make a selection from a large list</li>\n<li>The <code>pw_multiselect</code> field allows you to select multiple values with typeahead-style search. The values can be dragged and dropped to reorder</li>\n</ol>\n</blockquote>\n</li>\n<li>\n<p><a href=\"https://github.com/qmatt/cmb2-field-slider\" rel=\"nofollow ugc\">CMB Field Type: Slider</a> from <a href=\"https://github.com/mattkrupnik/\" rel=\"nofollow ugc\">mattkrupnik</a>: Adds a jQuery UI Slider field.</p>\n</li>\n<li><a href=\"https://github.com/CMB2/CMB2-Date-Range-Field\" rel=\"nofollow ugc\">WDS CMB2 Date Range Field</a> from <a href=\"https://github.com/dustyf\" rel=\"nofollow ugc\">dustyf</a> of <a href=\"https://github.com/WebDevStudios\" rel=\"nofollow ugc\">WebDevStudios</a>: Adds a date range field.</li>\n<li><a href=\"https://github.com/CMB2/CMB2-Remote-Image-Select-Field\" rel=\"nofollow ugc\">CMB2 Remote Image Select</a> from <a href=\"https://github.com/JayWood\" rel=\"nofollow ugc\">JayWood</a> of <a href=\"https://github.com/WebDevStudios\" rel=\"nofollow ugc\">WebDevStudios</a>: Allows users to enter a URL in a text field and select a single image for use in post meta. Similar to Facebook&#8217;s featured image selector.</li>\n<li><a href=\"https://wordpress.org/plugins/cmb-field-type-sorter/\" rel=\"ugc\">CMB Field Type: Sorter</a>: This plugin gives you two CMB field types based on the Sorter script.</li>\n<li><a href=\"https://github.com/florianbeck/cmb2-field-type-tags\" rel=\"nofollow ugc\">CMB Field Type: Tags</a>: WordPress-Tags-like field type for CMB2. <em>note: this does not set the post tags, but simply provides a unique text input</em></li>\n<li><a href=\"https://wordpress.org/plugins/link-picker-for-cmb2/\" rel=\"ugc\">CMB Field Type: Link Picker</a>: Using the Link Picker for CMB2 control, you can choose a link from your WordPress site, or manually enter a link. You can also identify if the link should open in a new window, or not.</li>\n<li><a href=\"https://github.com/origgami/cmb2-multidates-picker\" rel=\"nofollow ugc\">CMB Field Type: MultidatesPicker</a>: Creates a CMB2 field type that enables a multiple date calendar. It uses a plugin called <a href=\"https://dubrox.github.io/Multiple-Dates-Picker-for-jQuery-UI/\" rel=\"nofollow ugc\">MultiDatesPicker v1.6.3 for jQuery UI</a>.</li>\n<li><a href=\"https://github.com/satwinderrathore/CMB2-radio-image\" rel=\"nofollow ugc\">CMB Field Type: CMB2-radio-image</a>: Image as radio buttons.</li>\n<li><a href=\"https://github.com/florianbeck/cmb2-field-type-tags\" rel=\"nofollow ugc\">CMB2 Term Select</a>: Special CMB2 Field that allows users to define an autocomplete text field for terms. <em>Note: this will set the taxonomy terms, but has the option (<code>\'apply_term\' =&gt; false</code>) to disable and save the term ids as data instead (like for options pages, etc).</em></li>\n<li><a href=\"https://github.com/jtsternberg/CMB2-Related-Links\" rel=\"nofollow ugc\">CMB2 Related Links</a>: Allows users to add a related links via a repeating field group. Field inputs are powered by the <a href=\"https://github.com/CMB2/CMB2-Post-Search-field\" rel=\"nofollow ugc\">CMB2 Field Type: CMB2 Post Search field</a> documented above, and so each link can be populated with existing WordPress content by clicking on the search button. <em>Note: this is not a standard field type, but instead a function you use in combination with CMB2::add_field().</em></li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-order\" rel=\"nofollow ugc\">CMB2 Field Type: Order</a> by <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: Allows users to define custom order of predefined options.</li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-animation\" rel=\"nofollow ugc\">CMB2 Field Type: Animation</a> by <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: Allows users to pickup an animation from <a href=\"https://github.com/daneden/animate.css\" rel=\"nofollow ugc\">Animate.css</a> (includes preview of chosen animation).</li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-ajax-search\" rel=\"nofollow ugc\">CMB2 Field Type: Ajax Search</a> by <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: Based on <a href=\"https://github.com/alexis-magina/cmb2-field-post-search-ajax\" rel=\"nofollow ugc\">CMB2 Field Type: Post Search Ajax</a>, adds the ability to attach posts/users/terms, and the ability to limit the maximum number of attached objects.</li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-visual-style-editor\" rel=\"nofollow ugc\">CMB2 Field Type: Visual Style Editor</a> by <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: Custom field for CMB2 which allows customizing style from a small set of controls.</li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-content-wrap\" rel=\"nofollow ugc\">CMB2 Field Type: Content Wrap</a> by <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: Custom field for CMB2 to store a content wrap values (padding, margin or border width).</li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-js-controls\" rel=\"nofollow ugc\">CMB2 Field JS Controls</a> by <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: Show any field similar to WordPress publishing actions (Post/Page post_status, visibility and post_date submit box field).</li>\n<li><a href=\"https://github.com/rubengc/cmb2-field-position\" rel=\"nofollow ugc\">CMB2 Field Type: Position</a> by <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">rubengc</a>: CMB2 field type to setup a jquery UI position values.</li>\n<li><a href=\"https://github.com/pixelwatt/cmb2-roadway-segments\" rel=\"nofollow ugc\">CMB2 Field Type: CMB2 Roadway Segments</a> by <a href=\"https://github.com/pixelwatt\" rel=\"nofollow ugc\">pixelwatt</a>: This plugin adds a new CMB2 fieldtype for drawing roadway segments onto a map and provides a shortcode for display.</li>\n<li><a href=\"https://github.com/serkanalgur/cmb2-field-faiconselect\" rel=\"nofollow ugc\">CMB2 Field Type: Font Awesome</a> by <a href=\"https://github.com/serkanalgur\" rel=\"nofollow ugc\">serkanalgur</a>: This plugin adds a new CMB2 field type for selecting Font Awesome icons.</li>\n<li><a href=\"https://github.com/eduplessis/cmb2-typography\" rel=\"nofollow ugc\">CMB2 Field Type: Typography</a> by <a href=\"https://github.com/eduplessis\" rel=\"nofollow ugc\">eduplessis</a>: This plugin adds a new CMB2 field type &#8220;Typography&#8221; and it use jQuery fontselect for the font-family selection.</li>\n<li><a href=\"https://github.com/Rekenna/cmb2-markdown\" rel=\"nofollow ugc\">CMB2 Field Type: Markdown</a> by <a href=\"https://github.com/Rekenna\" rel=\"nofollow ugc\">Rekenna</a>: This plugin adds a new CMB2 field type &#8220;CMB2 Markdown&#8221; where you can type in markdown and view a live preview of the results or convert to html with a button.</li>\n<li><a href=\"https://github.com/themevan/CMB2-Switch-Button\" rel=\"nofollow ugc\">CMB2 Field Type: Switch Button</a> by <a href=\"https://github.com/themevan\" rel=\"nofollow ugc\">themevan</a>: This plugin adds a Custom Switch Button field type for CMB2.</li>\n<li><a href=\"https://github.com/manzoorwanijk/cmb2-select-plus\" rel=\"nofollow ugc\">CMB2 Field Type: select_plus</a> from <a href=\"https://github.com/manzoorwanijk/\" rel=\"nofollow ugc\">manzoorwanijk</a>: Select field type which acts much like the default <code>select</code> field. However, it adds the support for <code>optgroup</code> and saving of values with <code>multiple</code> attribute.</li>\n<li><a href=\"https://github.com/scottsawyer/cmb2-field-address\" rel=\"nofollow ugc\">CMB2 Field Type: Address</a> by <a href=\"https://github.com/scottsawyer\" rel=\"nofollow ugc\">scottsawyer</a>: Just a simple, repeatable address field.  It&#8217;s really just the snippet from <a href=\"https://github.com/CMB2/CMB2-Snippet-Library\" rel=\"nofollow ugc\">CMB2 Snippet Library</a> converted to a plugin.</li>\n<li><a href=\"https://github.com/scottsawyer/cmb2-field-link\" rel=\"nofollow ugc\">CMB2 Field Type: Link</a> by <a href=\"https://github.com/scottsawyer\" rel=\"nofollow ugc\">scottsawyer</a>: Create a link field with some attributes. Very nice for styling links.</li>\n<li><a href=\"https://github.com/scottsawyer/cmb2-field-widget-selector\" rel=\"nofollow ugc\">CMB2 Field Type: Widget Selector</a> by <a href=\"https://github.com/scottsawyer\" rel=\"nofollow ugc\">scottsawyer</a>: Need a field that lets you ( or your editor ) select / display an existing widget instance? Then this is the plugin for you.</li>\n</ul>\n<p>Other Helpful Resources</p>\n<ul>\n<li><a href=\"https://github.com/CMB2/cmb2-woocommerce-hpos-orders\" rel=\"nofollow ugc\">CMB2 WooCommerce HPOS Orders</a>: Adds the ability to add custom fields to the new WooCommerce HPOS orders page.</li>\n<li><a href=\"https://github.com/twoelevenjay/CMB2-Admin-Extension\" rel=\"nofollow ugc\">CMB2 Admin Extension</a>: Adds a UI to create CMB2 meta boxes from the WordPress admin. Also on <a href=\"https://wordpress.org/plugins/cmb2-admin-extension/\" rel=\"ugc\">wordpress.org</a>.</li>\n<li><a href=\"https://github.com/jtsternberg/Shortcode_Button\" rel=\"nofollow ugc\">WordPress Shortcode Button</a>: Uses CMB2 fields to generate fields for shortcode input modals.</li>\n<li><a href=\"https://github.com/WebDevStudios/WDS-Simple-Page-Builder\" rel=\"nofollow ugc\">WDS-Simple-Page-Builder</a>: Uses existing template parts in the currently-active theme to build a customized page with rearrangeable elements. Built with CMB2.</li>\n<li><a href=\"https://github.com/CMB2/CMB2-Example-Theme\" rel=\"nofollow ugc\">CMB2 Example Theme</a>: Demonstrate how to include CMB2 in your theme, as well as some cool tips and tricks.</li>\n<li><a href=\"https://github.com//WebDevStudios/facetwp-cmb2\" rel=\"nofollow ugc\">facetwp-cmb2</a>: FacetWP integration with CMB2.</li>\n<li><a href=\"https://github.com/origgami/CMB2-grid\" rel=\"nofollow ugc\">CMB2-grid</a> from <a href=\"https://github.com/origgami/\" rel=\"nofollow ugc\">origgami</a>: A grid system for WordPress CMB2 library that allows the creation of columns for a better layout in the admin.</li>\n<li><a href=\"https://github.com/rogerlos/cmb2-metatabs-options\" rel=\"nofollow ugc\">CMB2 Metatabs Options</a> from <a href=\"https://github.com/rogerlos/\" rel=\"nofollow ugc\">rogerlos</a>: CMO makes it easy to create options pages with multiple metaboxes&#8211;and optional WordPress admin tabs.</li>\n<li><a href=\"https://github.com/jcchavezs/cmb2-conditionals\" rel=\"nofollow ugc\">CMB2 Conditionals</a> from <a href=\"https://github.com/jcchavezs/\" rel=\"nofollow ugc\">jcchavezs</a>: Allows developers to relate fields so the display of one is conditional on the value of another.</li>\n<li><a href=\"https://willthemoor.github.io/cmb2-metabox-generator/\" rel=\"nofollow ugc\">CMB2 Metabox Code Generator</a> from <a href=\"https://github.com/willthemoor/\" rel=\"nofollow ugc\">willthemoor</a>: Skip the boring bits. Use this generator to create fully functional CMB2 metaboxes easily. Now with bulk entry!</li>\n<li><a href=\"https://wordpress.org/plugins/caldera-metaplate/\" rel=\"ugc\">Caldera Metaplate</a> by <a href=\"https://calderawp.com/\" rel=\"nofollow ugc\">CalderaWP</a>: Not specific to CMB2, but allows creating templates for outputting your custom fields.</li>\n<li><a href=\"https://github.com/alexis-magina/yoast-cmb2-field-analysis\" rel=\"nofollow ugc\">Yoast CMB2 Field Analysis WP Plugin</a> by <a href=\"https://github.com/alexis-magina\" rel=\"nofollow ugc\">alexis-magina</a>: This plugin adds in a js based method of recalculating Yoast SEO&#8217;s content scores when updating page content, specifically custom meta fields added via the CMB2 library.</li>\n<li><a href=\"https://github.com/awethemes/skeleton\" rel=\"nofollow ugc\">Skeleton</a> by <a href=\"https://github.com/awethemes\" rel=\"nofollow ugc\">awethemes</a>: A complete framework for WordPress, uses CMB2 engine.</li>\n<li><a href=\"https://wordpress.org/plugins/wp-simple-iconfonts/\" rel=\"ugc\">WP Simple Iconfonts</a> by <a href=\"https://github.com/awethemes\" rel=\"nofollow ugc\">awethemes</a>: An icon fonts manager and provides a font icon picker for CMB2.</li>\n<li><a href=\"https://github.com/nsrosenqvist/cmb2-nav-menus\" rel=\"nofollow ugc\">CMB2 Nav Menus</a> by <a href=\"https://github.com/nsrosenqvist\" rel=\"nofollow ugc\">nsrosenqvist</a>: Lets you use CMB2 in nav menu entries..</li>\n</ul>\n<h3>Links</h3>\n<ul>\n<li><a href=\"http://cmb2.io\" rel=\"nofollow ugc\">Project Homepage</a></li>\n<li><a href=\"https://github.com/CMB2/CMB2\" rel=\"nofollow ugc\">Github project page</a></li>\n<li><a href=\"https://github.com/CMB2/CMB2/wiki\" rel=\"nofollow ugc\">Documentation (GitHub wiki)</a></li>\n<li><a href=\"https://github.com/CMB2/CMB2-Snippet-Library/\" rel=\"nofollow ugc\">Snippet Library</a></li>\n</ul>\n<p><strong><a href=\"https://github.com/CMB2/CMB2/blob/master/CHANGELOG.md\" rel=\"nofollow ugc\">View CHANGELOG</a></strong></p>\n<h3>Known Issues</h3>\n<ul>\n<li>Metabox containing WYSIWYG editor cannot be moved or used in a repeatable way at this time (this is a TinyMCE issue).</li>\n<li>Not all fields work well in a repeatable group.</li>\n</ul>\n\";s:12:\"installation\";s:977:\"<p>If installing the plugin from wordpress.org:</p>\n<ol>\n<li>Upload the entire <code>/CMB2</code> directory to the <code>/wp-content/plugins/</code> directory.</li>\n<li>Activate CMB2 through the &#8216;Plugins&#8217; menu in WordPress.</li>\n<li>Copy (and rename if desired) <code>example-functions.php</code> into to your theme or plugin&#8217;s directory.</li>\n<li>Edit to only include the fields you need and rename the functions.</li>\n<li>Profit.</li>\n</ol>\n<p>If including the library in your plugin or theme:</p>\n<ol>\n<li>Place the CMB directory inside of your theme or plugin.</li>\n<li>Copy (and rename if desired) <code>example-functions.php</code> into a folder <em>above</em> the CMB directory OR copy the entirety of its contents to your theme&#8217;s <code>functions.php</code> file.</li>\n<li>Edit to only include the fields you need and rename the functions (CMB directory should be left unedited in order to easily update the library).</li>\n<li>Profit.</li>\n</ol>\n\";s:3:\"faq\";s:121:\"<p>FAQ&#8217;s usually end up in the <a href=\"https://github.com/CMB2/CMB2/wiki\" rel=\"nofollow ugc\">github wiki</a>.</p>\n\";s:9:\"changelog\";s:65437:\"<h3>2.12.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Confirmed compatibility with PHP 8.2 and 8.3, and tested up to WordPress 7.0.</li>\n<li>[Development] Migrated end-to-end testing from Cypress to Playwright and replaced Grunt with npm scripts for the asset build pipeline. (<a href=\"https://github.com/CMB2/CMB2/pull/1550\" rel=\"nofollow ugc\">#1550</a>).</li>\n<li>[Development] Moved the local development and test environment to <code>@wordpress/env</code> (wp-env) on pinned ports, running both PHPUnit and Playwright through it. (<a href=\"https://github.com/CMB2/CMB2/pull/1554\" rel=\"nofollow ugc\">#1554</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1558\" rel=\"nofollow ugc\">#1558</a>).</li>\n<li>[Development] Replaced Travis CI with GitHub Actions, added a PHPCompatibility check (PHP 7.4+) and a PHPCS/WPCS lint gate, and overhauled <code>install-wp-tests.sh</code> for modern WordPress. (<a href=\"https://github.com/CMB2/CMB2/pull/1555\" rel=\"nofollow ugc\">#1555</a>).</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fixed a PHP 8.1+ deprecation when sanitizing an empty <code>textarea</code>-based field (passing <code>null</code> to <code>wp_kses_post()</code>). Props <a href=\"https://github.com/baljindersingh88\" rel=\"nofollow ugc\">@baljindersingh88</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1537\" rel=\"nofollow ugc\">#1537</a>).</li>\n<li>Fixed row iterator value desync between the data attribute and jQuery data when reordering repeatable group rows. Props <a href=\"https://github.com/angryaxi\" rel=\"nofollow ugc\">@angryaxi</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1518\" rel=\"nofollow ugc\">#1518</a>).</li>\n<li>Fixed a PHP 8.3 <code>ltrim()</code> deprecation in the taxonomy field display.</li>\n<li>Hardened against PHP 8.2+ dynamic property deprecations by widening <code>#[AllowDynamicProperties]</code> to the class roots.</li>\n<li>Removed a focus-background rule on <code>.cmb2-wrap</code> inputs that caused unexpected input styling. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1556\" rel=\"nofollow ugc\">#1556</a>/<a href=\"https://wordpress.org/support/topic/weird-checkbox-behaviour-on-wp-7/\" rel=\"ugc\">wordpress.org/support/topic/weird-checkbox-behaviour-on-wp-7</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1557\" rel=\"nofollow ugc\">#1557</a>).</li>\n</ul>\n<h3>2.11.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Package updates.</li>\n<li>Update WordPress Tested up to tag 6.1. Props <a href=\"https://github.com/RubenMartins\" rel=\"nofollow ugc\">@RubenMartins</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1477\" rel=\"nofollow ugc\">#1477</a>).</li>\n<li>Add filters for setting <code>object_id</code> and <code>mb_object_type</code> and in <code>do_scripts</code> &#8211; Allows overriding by plugins/libs. (Added to support the new <a href=\"https://github.com/CMB2/cmb2-woocommerce-hpos-orders\" rel=\"nofollow ugc\">CMB2 WooCommerce HPOS Orders</a> extension)</li>\n<li>Added a <code>cmb2_init_hooks</code> hook when hookup is called.</li>\n<li>Addressed some security concerns with the unserialization process for the stored serialized <code>DateTime</code> field values (<code>text_datetime_timestamp_timezone</code> field type only). (<a href=\"https://github.com/CMB2/CMB2/pull/1510\" rel=\"nofollow ugc\">#1510</a>)</li>\n<li>[Development] Some build script improvements.</li>\n<li>[Development] Added some PHPCS/WPCS config.</li>\n<li>[Development] Added a phpcompatibility action. Props <a href=\"https://github.com/jazzsequence\" rel=\"nofollow ugc\">@jazzsequence</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1499\" rel=\"nofollow ugc\">#1499</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1500\" rel=\"nofollow ugc\">#1500</a>).</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix some line-height issues with dashicon buttons. Fixes [#1443](</li>\n<li>Fix issue where image can be attached to wrong group after removing previous group. (<a href=\"https://github.com/CMB2/CMB2/pull/1473\" rel=\"nofollow ugc\">#1473</a>)</li>\n<li>Fixes issue where Select/Deselect all does not trigger change JS DOM events. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1504\" rel=\"nofollow ugc\">#1504</a>.</li>\n</ul>\n<h3>2.10.1</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix issue with date picker formatting. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1448\" rel=\"nofollow ugc\">#1448</a>.</li>\n</ul>\n<h3>2.10.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Sanitize URLs, defaulting to <code>https</code>. Props <a href=\"https://github.com/paulschreiber\" rel=\"nofollow ugc\">@paulschreiber</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1413\" rel=\"nofollow ugc\">#1413</a>).</li>\n<li>Establish Cypress E2E Testing. Props <a href=\"https://github.com/markjaquith\" rel=\"nofollow ugc\">@markjaquith</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1437\" rel=\"nofollow ugc\">#1437</a>).</li>\n<li>Updated the JS <code>shiftRows</code> functionality to be simpler, and fix issues with JS initialization. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1426\" rel=\"nofollow ugc\">#1426</a> and <a href=\"https://github.com/CMB2/CMB2/issues/1431\" rel=\"nofollow ugc\">#1431</a>.</li>\n<li>Updated various NPM dependencies for security issues.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Update to prevent deprecation notice:<code>Required parameter $i follows optional parameter $args...</code>. Props <a href=\"https://github.com/carloswph\" rel=\"nofollow ugc\">@carloswph</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1417\" rel=\"nofollow ugc\">#1417</a>).</li>\n<li>Make each date field more resilient to various date/timestamp values passed in (from REST API).</li>\n</ul>\n<h3>2.9.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Added <code>cmb2_tab_group_tabs</code> filter for adding arbitrary menu page urls to the cmb2 tabs, and move tab markup output to separate method, <code>CMB2_Options_Hookup::options_page_tab_nav_output()</code>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1407\" rel=\"nofollow ugc\">#1407</a>.</li>\n<li>Limit use of italic, including removing from field descriptions. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1404\" rel=\"nofollow ugc\">#1404</a>.</li>\n<li>Add to list of valid image types from <code>get_allowed_mime_types()</code>, which makes SVGs more reliable when using the <a href=\"https://wordpress.org/plugins/safe-svg/\" rel=\"ugc\">Safe SVG</a> plugin. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1223\" rel=\"nofollow ugc\">#1223</a>.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fixes PHP warnings on repeatable ColorPicker with an array as default. Props <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">@rubengc</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1340\" rel=\"nofollow ugc\">#1340</a>).</li>\n<li>Address PHP 7.4, compatibility issues with <code>func_get_args()</code>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1389\" rel=\"nofollow ugc\">#1389</a>.</li>\n<li>Better generated array key for cached fields, fixes issue where wrong field is found. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/14053\" rel=\"nofollow ugc\">#14053</a>.</li>\n<li>Fix issue with options-pages being changed to register on a hook priority of <code>5</code> instead of the default <code>10</code>, causing some back-compatibility issues. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1410\" rel=\"nofollow ugc\">#1410</a>.</li>\n</ul>\n<h3>2.8.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Added <a href=\"https://github.com/CMB2/CMB2/blob/develop/CODE_OF_CONDUCT.md\" rel=\"nofollow ugc\">CODE_OF_CONDUCT.md</a> file to meet GitHub Community standards. Props <a href=\"https://github.com/RubenMartins\" rel=\"nofollow ugc\">@RubenMartins</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1331\" rel=\"nofollow ugc\">#1331</a>).</li>\n<li>Add ability to define the page-registration admin menu hook priority for options pages. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1380\" rel=\"nofollow ugc\">#1380</a>.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Ensure <code>enqueue wp-color-picker</code> is enqueued for color fields. Props <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">@rubengc</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1339\" rel=\"nofollow ugc\">#1339</a>).</li>\n<li>Fix empty name/id attributes on <code>\'file_list\'</code> buttons. Props <a href=\"https://github.com/pgroot91\" rel=\"nofollow ugc\">@pgroot91</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1347\" rel=\"nofollow ugc\">#1347</a>).</li>\n<li>Fix <code>wysiwyg</code> field type not working in a group, by ensuring scripts properly enqueued. Props <a href=\"https://github.com/yoren\" rel=\"nofollow ugc\">@yoren</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1361\" rel=\"nofollow ugc\">#1361</a>).</li>\n<li>Fix <code>$object_id</code> doc block types in helper-functions.php. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1365\" rel=\"nofollow ugc\">#1365</a>.</li>\n<li>Fix Metabox toggles visually broken with WP 5.5.x. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1382\" rel=\"nofollow ugc\">#1382</a>.</li>\n<li>Fix <code>PHP Deprecated: Required parameter $field_id follows optional parameter $type</code>, due to changes in PHP 8.0. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1396\" rel=\"nofollow ugc\">#1396</a>.</li>\n<li>Fix PHP notice caused by <code>deprecated_param</code> method in PHP 7.4. Props <a href=\"https://github.com/jonathanstegall\" rel=\"nofollow ugc\">@jonathanstegall</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1400\" rel=\"nofollow ugc\">#1400</a>).</li>\n</ul>\n<h3>2.7.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Added support for sortable columns by default, with ability to disable with <code>\'column\' =&gt; array( \'disable_sortable\' =&gt; true )</code>. Props <a href=\"https://github.com/RubenMartins\" rel=\"nofollow ugc\">@RubenMartins</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1281\" rel=\"nofollow ugc\">#1281</a>).</li>\n<li>New field type, <code>\'taxonomy_select_hierarchical\'</code>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/751\" rel=\"nofollow ugc\">#751</a></li>\n<li>New <code>text</code>, <code>textarea</code> and <code>wysiwyg</code> character counter options. For now, this feature is not available to <code>wysiwyg</code> field types within repeatable groups. Props <a href=\"https://github.com/gyrus\" rel=\"nofollow ugc\">@gyrus</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1276\" rel=\"nofollow ugc\">#1276</a>).\n<ul>\n<li>The new parameters:\n<ul>\n<li><code>\'char_counter\'</code> &#8211; Defaults to false, no counter. Set to true, or <code>words</code> to count words instead of characters.</li>\n<li><code>\'char_max\'</code> &#8211; integer. When defined, counter shows remaining characters/words.</li>\n<li><code>\'char_max_enforce\'</code> &#8211; boolean, default: false. Currently only applied (as maxlength attribute) to <code>text</code> and <code>textarea</code> fields which use <code>\'characters\'</code> for counter.</li>\n</ul>\n</li>\n<li>You can also <a href=\"https://github.com/CMB2/CMB2/wiki/Field-Parameters#text\" rel=\"nofollow ugc\">override the default text strings</a> associated with these parameters:\n<ul>\n<li><code>\'words_left_text\'</code> &#8211; Default: &#8220;Words left&#8221;</li>\n<li><code>\'words_text\'</code> &#8211; Default: &#8220;Words&#8221;</li>\n<li><code>\'characters_left_text\'</code> &#8211; Default: &#8220;Characters left&#8221;</li>\n<li><code>\'characters_text\'</code> &#8211; Default: &#8220;Characters&#8221;</li>\n<li><code>\'characters_truncated_text\'</code> &#8211; Default: &#8220;Your text may be truncated.&#8221;</li>\n</ul>\n</li>\n</ul>\n</li>\n<li>Update styling to be more compatible with WordPress 5.3. Props <a href=\"https://github.com/galengidman\" rel=\"nofollow ugc\">@galengidman</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1314\" rel=\"nofollow ugc\">#1314</a>)</li>\n<li>Add a new box parameter, <code>register_rest_field_cb</code>, which when used allows overriding the way CMB2 handles the <code>register_rest_field</code> callbacks, and defining your own REST prefix for your fields. See <a href=\"https://github.com/CMB2/CMB2/pull/1240#issuecomment-552548488\" rel=\"nofollow ugc\">this PR comment</a> for more context.</li>\n<li>Cleanup by renaming <code>CMB2_hookup</code> to <code>CMB2_Hookup</code>. Classes are case-insensitive, so this is a backwards-compatible change. Props <a href=\"https://github.com/szepeviktor\" rel=\"nofollow ugc\">@szepeviktor</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1330\" rel=\"nofollow ugc\">#1330</a>, <a href=\"https://github.com/CMB2/CMB2/issues/1328\" rel=\"nofollow ugc\">#1328</a>).</li>\n<li>Validate composer.json for Travis CI. Props <a href=\"https://github.com/szepeviktor\" rel=\"nofollow ugc\">@szepeviktor</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1326\" rel=\"nofollow ugc\">#1326</a>).</li>\n<li>Added <a href=\"https://github.com/CMB2/CMB2/blob/develop/LICENSE\" rel=\"nofollow ugc\">LICENSE</a> file to meet GitHub Community standards. Props <a href=\"https://github.com/RubenMartins\" rel=\"nofollow ugc\">@RubenMartins</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1316\" rel=\"nofollow ugc\">#1316</a>).</li>\n<li>Add new <code>\"cmb2_display_class_{$fieldtype}\"</code> filter and <code>\'display_class\'</code> field parameter to allow specifying the class to use to display the field (in admin columns, etc).</li>\n<li>Update <code>CMB2_Types::_id()</code> to allow not appending the iterator attribute if a repeatable field.</li>\n<li>Added <code>CMB2_Utils::concat_attrs()</code> test for nested arrays as data attributes.</li>\n<li>Various updates per <a href=\"https://github.com/CMB2/CMB2/issues/1260\" rel=\"nofollow ugc\">VIP feedback</a>. Props <a href=\"https://github.com/kevinlangleyjr\" rel=\"nofollow ugc\">@kevinlangleyjr</a>, <a href=\"https://github.com/mikeselander\" rel=\"nofollow ugc\">@mikeselander</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1255\" rel=\"nofollow ugc\">#1255</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1257\" rel=\"nofollow ugc\">#1257</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1259\" rel=\"nofollow ugc\">#1259</a>,  <a href=\"https://github.com/CMB2/CMB2/pull/1261\" rel=\"nofollow ugc\">#1261</a> <a href=\"https://github.com/CMB2/CMB2/pull/1262\" rel=\"nofollow ugc\">#1262</a>, and various direct commits. See <a href=\"https://github.com/CMB2/CMB2/issues/1260\" rel=\"nofollow ugc\">#1260</a>).</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix some issues with Travis. Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1220\" rel=\"nofollow ugc\">#1220</a>).</li>\n<li>Javascript: Correctly pass the newly created row to the <code>cmb2_add_row</code> triggered event.</li>\n<li>Various code-formatting and code documentation improvements. Props <a href=\"https://github.com/tw2113\" rel=\"nofollow ugc\">@tw2113</a>.</li>\n<li>Don&#8217;t exclude composer.json from the distribution. Props <a href=\"https://github.com/johnbillion\" rel=\"nofollow ugc\">@johnbillion</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1225\" rel=\"nofollow ugc\">#1225</a>).</li>\n<li>Ignore some more directories in the distribution package. Props <a href=\"https://github.com/johnbillion\" rel=\"nofollow ugc\">@johnbillion</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1226\" rel=\"nofollow ugc\">#1226</a>).</li>\n<li>Use <code>CMB2_Field::get_rest_value()</code> to get values for fields in the post REST API endpoints (<a href=\"https://github.com/CMB2/CMB2/issues/1284\" rel=\"nofollow ugc\">#1284</a>).</li>\n<li>Fix issue where oEmbed fields&#8217; live-preview would not work if the field was added within a group, along with some other similarly related issues. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1157\" rel=\"nofollow ugc\">#1157</a>.</li>\n<li>Fix issue when using REST API for <code>file</code> and <code>text_datetime_timestamp_timezone</code> field types, the supporting field data was not provided (e.g. the file id for <code>file</code> field, and the <code>utc</code> value for the <code>text_datetime_timestamp_timezone</code> field). Fixes <a href=\"https://wordpress.org/support/topic/cmb2-rest-api-image-file-field-as-an-object/\" rel=\"ugc\">https://wordpress.org/support/topic/cmb2-rest-api-image-file-field-as-an-object/</a>.</li>\n<li>Escaping Improvements to File Base and File Fields. Props <a href=\"https://github.com/tomjn\" rel=\"nofollow ugc\">@tomjn</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1296\" rel=\"nofollow ugc\">#1296</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1297\" rel=\"nofollow ugc\">#1297</a>).</li>\n<li>Fix issue where repeatable CodeMirror textareas could not be clicked/draggged to highlight text. Props <a href=\"https://github.com/JPry\" rel=\"nofollow ugc\">@JPry</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1300\" rel=\"nofollow ugc\">#1300</a>).</li>\n<li><code>taxonomy_select_hierarchical</code> now saves to the correct location, the term relationships table. Props <a href=\"https://github.com/latheva\" rel=\"nofollow ugc\">@latheva</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1307\" rel=\"nofollow ugc\">#1307</a>).</li>\n<li>Fix issue (<a href=\"https://github.com/CMB2/CMB2/issues/1158\" rel=\"nofollow ugc\">#1158</a>) where default REST API endpoints (e.g. <code>/wp/v2/{post_type}</code>) would show all boxes for all custom post types even though not registered to the post-type. Props <a href=\"https://github.com/Mte90\" rel=\"nofollow ugc\">@Mte90</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1238\" rel=\"nofollow ugc\">#1238</a>).</li>\n<li>Update and cull npm dependencis. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1308\" rel=\"nofollow ugc\">#1308</a>.</li>\n<li>Fix some jshint issues.</li>\n<li>Updated the WordPress embeds URL references.</li>\n<li>Updates to account for WordPress 5.2 oEmbed changes.</li>\n<li>Fix to ensure date picker fields can have a default value. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1245\" rel=\"nofollow ugc\">#1245</a>.</li>\n<li>Added <code>function_exists( \'add_action\' )</code> check to bootstrap file to ensure compatibility with composer usage. Props <a href=\"https://github.com/salcode\" rel=\"nofollow ugc\">@salcode</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1271\" rel=\"nofollow ugc\">#1271</a>, <a href=\"https://github.com/CMB2/CMB2/issues/1270\" rel=\"nofollow ugc\">#1270</a>)</li>\n<li>Corrected link to facetwp-cmb2 in README.md. Props <a href=\"https://github.com/marcelreschke\" rel=\"nofollow ugc\">@marcelreschke</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1248\" rel=\"nofollow ugc\">#1248</a>).</li>\n<li>Use <code>get_user_locale()</code> in admin area instead of <code>get_locale()</code>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1267\" rel=\"nofollow ugc\">#1267</a>.</li>\n<li><code>CMB2::is_box_type()</code> now also checks for taxonomies if box is registered to &#8220;term&#8221; object type. This should fix some issues where CMB2 term meta was not showing up in REST API requests to the term endpoints.</li>\n</ul>\n<h3>2.6.0</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Remove superfluous method definitions. Props <a href=\"https://github.com/tnorthcutt\" rel=\"nofollow ugc\">@tnorthcutt</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1200\" rel=\"nofollow ugc\">#1200</a>).</li>\n<li>Fix <code>rest_value_cb</code> registering of filter. Props <a href=\"https://github.com/lipemat\" rel=\"nofollow ugc\">@lipemat</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1212\" rel=\"nofollow ugc\">#1212</a>).</li>\n<li>Do not trigger tinyMCE editor save for the activeEditor. Prevents cursor jump in Gutenberg. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1202\" rel=\"nofollow ugc\">#1202</a></li>\n<li>Fix issue where making a field repeatable would generate a Javascript error because of missing sortable library. Props <a href=\"https://github.com/slaFFik\" rel=\"nofollow ugc\">@slaFFik</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1216\" rel=\"nofollow ugc\">#1216</a>).</li>\n<li>Ensure value passed to <code>CMB2_Utils::filter_empty</code> from <code>CMB2::save_group_field</code> is always an array. (<a href=\"https://github.com/CMB2/CMB2/issues/1026\" rel=\"nofollow ugc\">#1026</a>)</li>\n<li>Fix potential issue with test path location. Props <a href=\"https://github.com/quasel\" rel=\"nofollow ugc\">@quasel</a> (<a href=\"https://github.com/CMB2/CMB2/pull/463\" rel=\"nofollow ugc\">#463</a>).</li>\n</ul>\n<h4>Enhancements</h4>\n<ul>\n<li>Updated PHPUnit version in composer.json. Props <a href=\"https://github.com/slaFFik\" rel=\"nofollow ugc\">@slaFFik</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1204\" rel=\"nofollow ugc\">#1204</a>).</li>\n<li>Package.json: fix the need of global (old) grunt. Props <a href=\"https://github.com/slaFFik\" rel=\"nofollow ugc\">@slaFFik</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1206\" rel=\"nofollow ugc\">#1206</a>).</li>\n<li>Add optional confirmation dialog to group field&#8217;s Remove button. Example <a href=\"https://github.com/CMB2/CMB2/blob/12036e2dcdeb5b019e844b814eca154bb0eee791/example-functions.php#L525\" rel=\"nofollow ugc\">documented in the example functions file</a>. Props <a href=\"https://github.com/slaFFik\" rel=\"nofollow ugc\">@slaFFik</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1208\" rel=\"nofollow ugc\">#1208</a>).</li>\n<li>Add &#8216;id&#8217; attribute on group field <code>.postbox</code> divs to ensure compatibility with scripts which expect ids there. Props <a href=\"https://github.com/amans2k\" rel=\"nofollow ugc\">@amans2k</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1108\" rel=\"nofollow ugc\">#1108</a>).</li>\n<li>Make <code>CMB2_Option</code> properties accessible. (<a href=\"https://github.com/CMB2/CMB2/issues/1052\" rel=\"nofollow ugc\">#1052</a>)</li>\n<li>New Before/After row hooks: <code>\'cmb2_before_field_row\'</code>, <code>\"cmb2_before_{$field_type}_field_row\"</code>, <code>\"cmb2_after_{$field_type}_field_row\"</code>, <code>\'cmb2_after_field_row\'</code>. Props <a href=\"https://github.com/rubengc\" rel=\"nofollow ugc\">@rubengc</a> (<a href=\"https://github.com/CMB2/CMB2/pull/953\" rel=\"nofollow ugc\">#953</a>).</li>\n<li>Introduce three new filters to filter field arguments: <code>\'cmb2_field_defaults\'</code>, <code>\'cmb2_field_arguments_raw\'</code>, <code>\'cmb2_field_arguments\'</code>. Props <a href=\"https://github.com/jrfnl\" rel=\"nofollow ugc\">@jrfnl</a> (<a href=\"https://github.com/CMB2/CMB2/pull/588\" rel=\"nofollow ugc\">#588</a>).</li>\n</ul>\n<h3>2.5.1</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix issue when the <code>core/editor</code> object does not exist (is undefined), causing incompatibility issues with Yoast and likely others. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1197\" rel=\"nofollow ugc\">#1197</a></li>\n</ul>\n<h3>2.5.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Repeatable fields are now drag-sortable. Props <a href=\"https://github.com/lipemat\" rel=\"nofollow ugc\">@lipemat</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1142\" rel=\"nofollow ugc\">#1142</a>).</li>\n<li>Update the <code>sv_SE</code> translation. Props <a href=\"https://github.com/edvind\" rel=\"nofollow ugc\">@edvind</a> (<a href=\"https://github.com/CMB2/CMB2/pull/370\" rel=\"nofollow ugc\">#370</a>).</li>\n<li>QA/PHPCS cleanup. Props <a href=\"https://github.com/tw2113\" rel=\"nofollow ugc\">@tw2113</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1179\" rel=\"nofollow ugc\">#1179</a>).</li>\n<li>Add optional <code>\'mb_callback_args\'</code> CMB2 box property which allows defining the <code>$callback_args</code> passed into <code>add_meta_box()</code>. This allows using defining the new <a href=\"https://wordpress.org/gutenberg/handbook/extensibility/meta-box/\" rel=\"ugc\">Gutenberg/block-editor compatibility parameters</a>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1191\" rel=\"nofollow ugc\">#1191</a></li>\n<li>Support any type of markup when customizing repeating group row. Props <a href=\"https://github.com/lipemat\" rel=\"nofollow ugc\">@lipemat</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1187\" rel=\"nofollow ugc\">#1187</a>).</li>\n<li>Add <code>cmb_init_pickers</code> and <code>cmb_init_code_editors</code> Javascript events for allowing just-in-time configuration for pickers/editors.</li>\n<li>Fix field descriptions color contrast ratio for better accessibility. h/t <a href=\"https://github.com/rianrietveld\" rel=\"nofollow ugc\">@rianrietveld</a>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1193\" rel=\"nofollow ugc\">#1193</a>.</li>\n<li>Add <code>CMB2_Field::get_rest_value()</code> method for sending value through several filters (<code>\'cmb2_get_rest_value\'</code>, <code>\"cmb2_get_rest_value_{$field_type}\"</code>, <code>\"cmb2_get_rest_value_for_{$field_id}\"</code> ) before sending to REST request.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix the options page errors when using CMB2 in WordPress prior to 4.7. Props <a href=\"https://github.com/manzoorwanijk\" rel=\"nofollow ugc\">@manzoorwanijk</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1166\" rel=\"nofollow ugc\">#1166</a>).</li>\n<li>Fix occasonal fatal errors that can occur by using callback functions directly vs <code>call_user_func</code>. Props <a href=\"https://github.com/manzoorwanijk\" rel=\"nofollow ugc\">@manzoorwanijk</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1177\" rel=\"nofollow ugc\">#1177</a>).</li>\n<li>Fix issue where <code>wysiwyg</code> fields&#8217; visual tab wouldn&#8217;t save content on Gutenberg/block-editor posts. Props <a href=\"https://github.com/staurand\" rel=\"nofollow ugc\">@staurand</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1190\" rel=\"nofollow ugc\">#1190</a> fixes <a href=\"https://github.com/CMB2/CMB2/issues/1156\" rel=\"nofollow ugc\">#1156</a>).</li>\n<li>Fix issue when <code>remove_default</code> wouldn&#8217;t actually remove the default taxonomy metabox when box registration used an alternate box context. Props <a href=\"https://github.com/lipemat\" rel=\"nofollow ugc\">@lipemat</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1147\" rel=\"nofollow ugc\">#1147</a>).</li>\n</ul>\n<h3>2.4.2</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Do not enqueue/register WordPress code editor JS if there are no <code>textarea_code</code> fields registered on the page. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1110\" rel=\"nofollow ugc\">#1110</a>.</li>\n<li>Do not set repeated <code>wysiwyg</code> field values to string &#8220;false&#8221; when boolean false. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1138\" rel=\"nofollow ugc\">#1138</a> (again!).</li>\n</ul>\n<h3>2.4.1</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Do not set repeated field values to string &#8220;false&#8221; when boolean false. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1138\" rel=\"nofollow ugc\">#1138</a>.</li>\n</ul>\n<h3>2.4.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Enable linking options pages via tabbed-navigation. Will output tabbed navigation for options-pages which share the same <code>\'tab_group\'</code> CMB2 box property. <a href=\"https://github.com/CMB2/CMB2-Snippet-Library/blob/master/options-and-settings-pages/options-pages-with-tabs-and-submenus.php\" rel=\"nofollow ugc\">This snippet</a> demonstrates how to create a top-level menu options page with multiple submenu pages, each with the tabbed navigation. To specify a different tab title than the options-page title, set the <code>\'tab_title\'</code> CMB2 box property. See <a href=\"https://github.com/CMB2/CMB2/issues/301\" rel=\"nofollow ugc\">#301</a>, <a href=\"https://github.com/CMB2/CMB2/issues/627\" rel=\"nofollow ugc\">#627</a>.</li>\n<li>Complete the <code>zh-CN</code> translation. Props <a href=\"https://github.com/uicestone\" rel=\"nofollow ugc\">@uicestone</a> (<a href=\"https://github.com/CMB2/CMB2/issues/1089\" rel=\"nofollow ugc\">#1089</a>).</li>\n<li>Update the <code>nl_NL</code> translation. Props <a href=\"https://github.com/tammohaannl\" rel=\"nofollow ugc\">@tammohaannl</a> (<a href=\"https://github.com/CMB2/CMB2/issues/1101\" rel=\"nofollow ugc\">#1101</a>).</li>\n<li>Better display for white over transparent images (e.g. logos) by using a checkered background for images. (<a href=\"https://github.com/CMB2/CMB2/issues/1103\" rel=\"nofollow ugc\">#1103</a>)</li>\n<li>Ability to disable the options <a href=\"https://codex.wordpress.org/Function_Reference/add_option#Parameters\" rel=\"nofollow ugc\">autoload parameter</a> via filter (<code>\"cmb2_should_autoload_{$options_key}\"</code>) or via a box parameter for <code>\'options-page\'</code> box registrations (<code>\'autoload\' =&gt; false,</code>). (<a href=\"https://github.com/CMB2/CMB2/issues/1093\" rel=\"nofollow ugc\">#1093</a>)</li>\n<li>\n<p><code>\'textarea_code\'</code> field type now uses CodeMirror that is <a href=\"https://make.wordpress.org/core/2017/10/22/code-editing-improvements-in-wordpress-4-9/\" rel=\"nofollow ugc\">used by WordPress</a> (<a href=\"https://github.com/CMB2/CMB2/issues/1096\" rel=\"nofollow ugc\">#1096</a>). A field can opt-out to return to the previous behavior by specifying an <code>\'options\'</code> parameter:<br />\n&#8216;options&#8217; =&gt; array( &#8216;disable_codemirror&#8217; =&gt; true )<br />\nAs with the other javascript-enabled fields, the code-editor defaults can be overridden via a <code>data-codeeditor</code> attribute. E.g:</p>\n<pre><code>`php\n</code></pre>\n<p>&#8216;attributes&#8217; =&gt; array(<br />\n    &#8216;data-codeeditor&#8217; =&gt; json_encode( array(<br />\n        &#8216;codemirror&#8217; =&gt; array(<br />\n            &#8216;mode&#8217; =&gt; &#8216;css&#8217;,<br />\n        ),<br />\n    ) ),<br />\n),<br />\n    `</p>\n</li>\n<li>Improve/add comment info banners at top of CMB2 CSS files.</li>\n<li>Added <code>resetBoxes</code>/<code>resetBox</code> Javascript methods for resetting CMB2 box forms.</li>\n<li>Improved styles for fields in the new-term form.</li>\n<li>New <code>CMB2_Boxes</code> methods for filtering instances of <code>CMB2</code>, <code>CMB2_Boxes::get_by( $property, $optional_compare )</code> and <code>CMB2_Boxes::filter_by( $property, $to_ignore = null )</code>.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix the <code>\'taxonomy_*\'</code> fields when used for term fields/meta. Save the value to term-meta.</li>\n<li>Clear the CMB2 fields when a term is added. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/794\" rel=\"nofollow ugc\">#794</a>.</li>\n<li>Repeated fields now use registered field defaults for values. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1137\" rel=\"nofollow ugc\">#1137</a>.</li>\n<li>Fixed the formatting for deprecated messages in the log.</li>\n<li>Prevent opening of media modal when clicking the file &#8220;Download&#8221; link. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1130\" rel=\"nofollow ugc\">#1130</a>.</li>\n</ul>\n<h3>2.3.0</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Updated Italian translation. Props <a href=\"https://github.com/Mte90\" rel=\"nofollow ugc\">@Mte90</a> (<a href=\"https://github.com/CMB2/CMB2/issues/1067\" rel=\"nofollow ugc\">#1067</a>).</li>\n<li>Starting with this release, we are fully switching to the more communicative and standard <a href=\"https://semver.org/\" rel=\"nofollow ugc\">Semantic Versioning</a>. (<a href=\"https://github.com/CMB2/CMB2/issues/1061\" rel=\"nofollow ugc\">#1061</a>).</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Update for compatibility with PHP 7.2 (e.g. fixes <code>Fatal error: Declaration of CMB2_Type_Colorpicker::render() must be compatible with CMB2_Type_Text::render($args = Array)...</code>). (<a href=\"https://github.com/CMB2/CMB2/issues/1070\" rel=\"nofollow ugc\">#1070</a>, <a href=\"https://github.com/CMB2/CMB2/issues/1074\" rel=\"nofollow ugc\">#1074</a>, <a href=\"https://github.com/CMB2/CMB2/issues/1075\" rel=\"nofollow ugc\">#1075</a>).</li>\n</ul>\n<h3>2.2.6.2</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix another issue (introduced in 2.2.6) with repeatable fields not being able to save additional fields. Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1059\" rel=\"nofollow ugc\">#1059</a>, <a href=\"https://github.com/CMB2/CMB2/issues/1058\" rel=\"nofollow ugc\">#1058</a>).</li>\n<li>Only dequeue <code>jw-cmb2-rgba-picker-js</code> script (and enqueue our <code>wp-color-picker-alpha</code>) if it is actually found.</li>\n</ul>\n<h3>2.2.6.1</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Merge in the <a href=\"https://github.com/JayWood/CMB2_RGBa_Picker\" rel=\"nofollow ugc\">CMB2 RGBa Colorpicker</a> field type functionality to the CMB2 colopicker field type. Adds the ability to add an alpha (transparency) slider to the colorpicker by adding the <code>\'alpha\'</code> option <a href=\"https://github.com/CMB2/CMB2/blob/6fce2e7ba8f41345a23bc2064e30433bdb11c16c/example-functions.php#L263-L265\" rel=\"nofollow ugc\">to the field options array</a>. Thank you to <a href=\"https://github.com/JayWood\" rel=\"nofollow ugc\">JayWood</a> for his work on his custom field type.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix issue (introduced in 2.2.6) with complex fields set as repeatable not being able to save additional fields. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1054\" rel=\"nofollow ugc\">#1054</a>.</li>\n</ul>\n<h3>2.2.6</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Move the fetching of group label and description to <em>after</em> calling <code>\'before_group\'</code> parameter.</li>\n<li>Allow using the <code>\'render_row_cb\'</code> param for group fields. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1041\" rel=\"nofollow ugc\">#1041</a>.</li>\n<li>Allow resetting cached CMB2 field objects (new 3rd parameter to <code>CMB2::get_field()</code>).</li>\n<li>Allow resetting cached callback results (<code>CMB2_Base::unset_param_callback_cache()</code>).</li>\n<li>Persian translation provided by <a href=\"https://github.com/reza-irdev\" rel=\"nofollow ugc\">@reza-irdev</a> (<a href=\"https://github.com/CMB2/CMB2/issues/1046\" rel=\"nofollow ugc\">#1046</a>).</li>\n<li>Added a <code>\'message_cb\'</code> box property, which allows defining a custom callback for adding options-save messages on <code>options-page</code> boxes.</li>\n<li>Updated many the oembed-related unit tests to more reliably test the relevant parts, and not so much the actual success of the WordPress functions.</li>\n<li>Updated travis config to Install PHP5.2/5.3 on trusty for unit tests. Stolen from <a href=\"https://github.com/WordPress/gutenberg/pull/2049\" rel=\"nofollow ugc\">gutenberg/pull/2049</a>. Intended to compensate for Travis removing support for PHP 5.2/5.3.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Ensure <code>\'file\'</code> field type ID is removed from the database if the <code>\'file\'</code> field type&#8217;s value is empty (<a href=\"https://wordpress.org/support/topic/bug-field-of-type-file-does-not-delete-postmeta-properly/\" rel=\"ugc\">Support thread</a>).</li>\n<li>Fix JS errors when <code>user_can_richedit()</code> is false (&#8220;Disable the visual editor when writing&#8221; user option is checked, or various unsupported browsers). See <a href=\"https://github.com/CMB2/CMB2/pull/1031\" rel=\"nofollow ugc\">#1031</a>.</li>\n<li>Fix issue where some European date formats (e.g. <code>F j, Y</code>) would not properly translate into jQuery UI date formats. <a href=\"https://wordpress.org/support/topic/using-wordpresss-date-time-format-settings\" rel=\"ugc\">Support thread</a></li>\n<li>Fix repeating fields within repeating groups having the values/indexes incorrectly associated. Props <a href=\"https://github.com/daggerhart\" rel=\"nofollow ugc\">@daggerhart</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1047\" rel=\"nofollow ugc\">#1047</a>). Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1035\" rel=\"nofollow ugc\">#1035</a>, <a href=\"https://github.com/CMB2/CMB2/issues/348\" rel=\"nofollow ugc\">#348</a>.</li>\n<li>Fixed multiple update messages on settings pages when CMB2 option pages were registered (<a href=\"https://github.com/CMB2/CMB2/issues/1049\" rel=\"nofollow ugc\">#1049</a>).</li>\n<li>Fix issue where using multiple oembed fields could cause incorrectly cached arguments to be used.</li>\n<li>Fix bug where <code>\'select_all_button\' =&gt; false</code> was not working for <code>\'taxonomy_multicheck\'</code> field type (<a href=\"https://github.com/CMB2/CMB2/issues/1005\" rel=\"nofollow ugc\">#1005</a>).</li>\n</ul>\n<h3>2.2.5.3</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Update to instead initate CMB2 hookup via <code>\"cmb2_init_hookup_{$cmb_id}\"</code> hook. Allows plugins to unhook/rehook/etc.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Spelling/Grammar fixes. Props <a href=\"https://github.com/garrett-eclipse\" rel=\"nofollow ugc\">@garrett-eclipse</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1012\" rel=\"nofollow ugc\">#1012</a>).</li>\n<li>Fix &#8220;PHP Strict Standards: Static function should not be abstract&#8221; notice.</li>\n<li>Add <code>CMB2_Utils::normalize_if_numeric()</code> to address problems when using floats as select/radio values. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/869\" rel=\"nofollow ugc\">#869</a>. See <a href=\"https://github.com/CMB2/CMB2/pull/1013\" rel=\"nofollow ugc\">#1013</a>.</li>\n<li>Fix issues with apostrophes in money values. (e.g. in Swiss German the thousand separator is an apostrophe). Props <a href=\"https://github.com/ocean90\" rel=\"nofollow ugc\">@ocean90</a> (<a href=\"https://github.com/CMB2/CMB2/issues/1014\" rel=\"nofollow ugc\">#1014</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1015\" rel=\"nofollow ugc\">#1015</a>).</li>\n<li>Provide public access to the <code>CMB2_Options_Hookup::$option_key</code> property.</li>\n<li>Change the updated-settings notice query variable so that WordPress does not auto-add settings notices on top of ours.</li>\n<li>For settings pages, only output settings errors if WordPress does not do it by default (for sub-pages of <code>options-general.php</code>), and if the errors are not disabled via the <code>\'disable_settings_errors\'</code> box property.</li>\n</ul>\n<h3>2.2.5.2</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix issue in 2.2.5 with non-sortable repeatable groups not having new groups values be emptied on creation/clone.</li>\n<li>Fix issue in 2.2.5 with options pages not saving when parent_slug was used. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1008\" rel=\"nofollow ugc\">#1008</a>.</li>\n</ul>\n<h3>2.2.5.1</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix issue in 2.2.5 which caused empty repeatable groups having the buttons set to have a disabled &#8220;Remove Group&#8221; button.</li>\n</ul>\n<h3>2.2.5 &#8211; 2017-08-07</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Options pages are now first-class CMB2 citizens, and registering a box to show on an options page will automatically register the menu page and output the form on the page. <a href=\"https://github.com/CMB2/CMB2/blob/v2.2.5/example-functions.php#L640-L683\" rel=\"nofollow ugc\">See example</a>. (The <a href=\"https://github.com/CMB2/CMB2-Snippet-Library/tree/master/options-and-settings-pages\" rel=\"nofollow ugc\">snippets</a> in the snippet library will be updated to reflect this change)</li>\n<li>Improved Options Page styling. Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1006\" rel=\"nofollow ugc\">#1006</a>).</li>\n<li>Improved cohesive styles for repeatable fields. Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/819\" rel=\"nofollow ugc\">#819</a>).</li>\n<li>New field types, <code>\'taxonomy_radio_hierarchical\'</code>, and <code>\'taxonomy_multicheck_hierarchical\'</code>, for displaying taxonomy options in a hierarchical layout. Props to <a href=\"https://github.com/eriktelepovsky\" rel=\"nofollow ugc\">eriktelepovsky</a> for the <a href=\"https://github.com/CMB2/CMB2/issues/640#issuecomment-246938690\" rel=\"nofollow ugc\">working code</a>. (<a href=\"https://github.com/CMB2/CMB2/issues/640\" rel=\"nofollow ugc\">#640</a>)</li>\n<li>Removing last repeat item row (and repeat group row) is now somewhat allowed in that the &#8220;remove&#8221; button simply resets the last item to empty. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/312\" rel=\"nofollow ugc\">#312</a>.</li>\n<li>Enable the additional media library modal filters. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/873\" rel=\"nofollow ugc\">#873</a>.</li>\n<li>Sanitize the attributes added via the <code>cmb2_group_wrap_attributes</code> filter.</li>\n<li>New field parameter, <code>\'query_args\'</code>, which can be used by the <code>\'taxonomy_*\'</code> fields. Provides ability to override the arguments passed to <code>get_terms()</code>.</li>\n<li>The <code>cmb2_can_save</code> filter now passes the CMB2 object as the 2nd parameter. Props <a href=\"https://github.com/Arno33\" rel=\"nofollow ugc\">@Arno33</a> (<a href=\"https://github.com/CMB2/CMB2/pull/994\" rel=\"nofollow ugc\">#994</a>).</li>\n<li>Update the file field type to work properly within a custom field context by allowing the passing of override arguments to <code>CMB2_Types::file()</code> method.</li>\n<li>Many WordPress Code Standards improvements/updates. Props <a href=\"https://github.com/bradp\" rel=\"nofollow ugc\">@bradp</a></li>\n<li>Include absolute paths when including the core php files. Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/998\" rel=\"nofollow ugc\">#998</a>).</li>\n<li>Change language throught to reflect CMB2&#8217;s move to its own organization.</li>\n<li>Break <code>CMB2_Field:options()</code> method apart to allow re-setting options from field params. Related: <a href=\"https://github.com/reaktivstudios/cmb2-flexible-content/pull/8\" rel=\"nofollow ugc\">reaktivstudios/cmb2-flexible-content/pull/8</a>.</li>\n<li>New <code>CMB2:box_types()</code> method for getting the array of registered <code>\'object_types\'</code> for a box. Ensures the return is an array.</li>\n<li>Improved inline hooks documentation.</li>\n<li>Updated several CMB2 methods to return the CMB2 object (for method chaining). Methods include:\n<ul>\n<li><code>CMB2::show_form()</code></li>\n<li><code>CMB2::render_form_open()</code></li>\n<li><code>CMB2::render_form_close()</code></li>\n<li><code>CMB2::render_group_row()</code></li>\n<li><code>CMB2::render_hidden_fields()</code></li>\n<li><code>CMB2::save_fields()</code></li>\n<li><code>CMB2::process_fields()</code></li>\n<li><code>CMB2::process_field()</code></li>\n<li><code>CMB2::pre_process()</code></li>\n<li><code>CMB2::after_save()</code></li>\n<li><code>CMB2::add_fields()</code></li>\n</ul>\n</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Update for <code>file</code>/<code>file_list</code> fields to properly show a preview for SVG images. Fixes <a href=\"https://github.com/CMB2/CMB2/pull/874\" rel=\"nofollow ugc\">#874</a>.</li>\n<li>Fix and standardize inconsistent button classes. Update all buttons to use the <code>.button-secondary</code> class instead of the <code>.button</code> class. This alleviates some front-end issues for themes which target the <code>.button</code> class. <em>This is a backwards-compatibility break.</em> If your theme or plugin targets the <code>.button</code> class within CMB2, you will need to update to use <code>.button-secondary</code>.</li>\n<li>Correct the before/after form hooks order. For more details see (<a href=\"https://github.com/CMB2/CMB2/pull/954\" rel=\"nofollow ugc\">#954</a>).</li>\n<li>Fix regression with custom fields not properly repeating. Props <a href=\"https://github.com/desrosj\" rel=\"nofollow ugc\">@desrosj</a> (<a href=\"https://github.com/CMB2/CMB2/pull/969\" rel=\"nofollow ugc\">#969</a>). Fixes <a href=\"https://github.com/CMB2/CMB2/issues/901\" rel=\"nofollow ugc\">#901</a>.</li>\n<li>Fix &#8220;Illegal string offset&#8221; notices when <code>CMB2_Option</code> methods are called when the option value is empty, as well as additional unit tests for the <code>CMB2_Option</code> class. Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/993\" rel=\"nofollow ugc\">#993</a>).</li>\n<li>Fix bug where select fields or checkbox fields occasionally would retain previous group&#8217;s value when adding new groups. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/853\" rel=\"nofollow ugc\">#853</a>.</li>\n<li>Fix JS to prevent meta keys with <code>|</code> or <code>/</code> from breaking file fields. Props <a href=\"https://github.com/lipemat\" rel=\"nofollow ugc\">@lipemat</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1003\" rel=\"nofollow ugc\">#1003</a>).</li>\n<li>Fix jQuery Migrate&#8217;s <code>jQuery.fn.attr(\'value\', val) no longer sets properties</code> warning.</li>\n<li>Fix issue with CMB2 being too aggressive with stripping slashes from values. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/981\" rel=\"nofollow ugc\">#981</a>.</li>\n</ul>\n<h3>2.2.4 &#8211; 2017-02-27</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Modify <code>\'taxonomy_*\'</code> fields to return stored terms for non-post objects.</li>\n<li>Modify <code>CMB2::get_sanitized_values()</code> to return the sanitized <code>\'taxonomy_*\'</code> field values. Also added <code>\"cmb2_return_taxonomy_values_{$cmb_id}\"</code> filter to modify if <code>\'taxonomy_*\'</code> field values are returned. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/538\" rel=\"nofollow ugc\">#538</a>.</li>\n<li>\n<p>Allow outputting CMB2 boxes/fields in additional locations in the post-editor.</p>\n<p><strong>The new locations are:</strong> <a href=\"https://developer.wordpress.org/reference/hooks/edit_form_top/\" rel=\"nofollow ugc\"><code>form_top</code></a>, <a href=\"https://developer.wordpress.org/reference/hooks/edit_form_before_permalink/\" rel=\"nofollow ugc\"><code>before_permalink</code></a>, <a href=\"https://developer.wordpress.org/reference/hooks/edit_form_after_title/\" rel=\"nofollow ugc\"><code>after_title</code></a>, and <a href=\"https://developer.wordpress.org/reference/hooks/edit_form_after_editor/\" rel=\"nofollow ugc\"><code>after_editor</code></a></p>\n<p>These would be defined by setting the <code>context</code> property for your box:</p>\n<pre><code>`php\n</code></pre>\n<p>$cmb_demo = new_cmb2_box( array(<br />\n    &#8230;<br />\n    &#8216;context&#8217; =&gt; &#8216;before_permalink&#8217;,<br />\n) );<br />\n    `</p>\n<p>If it is preferred that the fields are output without the metabox, then omit the <code>\'title\'</code> property from the metabox registration array, and instead add <code>\'remove_box_wrap\' =&gt; true,</code>.</p>\n<p>Props <a href=\"https://github.com/norcross\" rel=\"nofollow ugc\">@norcross</a> (<a href=\"https://github.com/CMB2/CMB2/pull/836\" rel=\"nofollow ugc\">#836</a>).</p>\n</li>\n<li>New field parameter, <code>\'render_class\'</code>, allowing you to override the default <code>\'CMB2_Type_Base\'</code> class that is used when rendering the field. This provides interesting object-oriented ways to override default CMB2 behavior by subclassing the default class and overriding methods. The render class can also be overridden with the <code>\"cmb2_render_class_{$fieldtype}\"</code> filter, which is passed the default render class name as well as the <code>CMB2_Types</code> object, but this should be used sparingly, and within the context of your project&#8217;s boxes/fields or you could break other plugins&#8217;/themes&#8217; CMB2 fields.</li>\n<li>Improvements to the <code>file</code>/<code>file_list</code> fields javascript APIs, including using undersore templates.</li>\n<li>Small improvements to the styling for the <code>file_list</code> field type.</li>\n<li>New action hook, <code>cmb2_footer_enqueue</code>, which occurs after CMB2 enqueues its assets.</li>\n<li>Example functions clean up. Props <a href=\"https://github.com/PavelK27\" rel=\"nofollow ugc\">@PavelK27</a> (<a href=\"https://github.com/CMB2/CMB2/pull/866\" rel=\"nofollow ugc\">#866</a>).</li>\n<li>New <code>CMB2_Utils</code> methods, <code>get_available_image_sizes()</code> and <code>get_named_size()</code>. Props <a href=\"https://github.com/Cai333\" rel=\"nofollow ugc\">@Cai333</a>.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix datepicker month/year dropdown text color. On windows, the option text was showing as white (invisible). Fixes <a href=\"https://github.com/CMB2/CMB2/issues/770\" rel=\"nofollow ugc\">#770</a>.</li>\n<li>Repeatable WYSIWYG no longer breaks if <code>\'quicktags\'</code> param is set to false. Props <a href=\"https://github.com/timburden\" rel=\"nofollow ugc\">@timburden</a> (<a href=\"https://github.com/CMB2/CMB2/pull/797\" rel=\"nofollow ugc\">#797</a>, <a href=\"https://github.com/CMB2/CMB2/issues/796\" rel=\"nofollow ugc\">#796</a>).</li>\n<li>Do not process title fields during group field save process.</li>\n<li>Fix issue where term-meta values were not being displayed for some users. Props <a href=\"https://github.com/sbussetti\" rel=\"nofollow ugc\">@sbussetti</a> (<a href=\"https://github.com/CMB2/CMB2/pull/763\" rel=\"nofollow ugc\">#763</a>, <a href=\"https://github.com/CMB2/CMB2/issues/700\" rel=\"nofollow ugc\">#700</a>).</li>\n<li>Fix issue where term meta would not be applied when using the new term form if multiple object types were specified. Props <a href=\"https://github.com/ADC07\" rel=\"nofollow ugc\">@ADC07</a> (<a href=\"https://github.com/CMB2/CMB2/pull/842\" rel=\"nofollow ugc\">#842</a>, <a href=\"https://github.com/CMB2/CMB2/issues/841\" rel=\"nofollow ugc\">#841</a>).</li>\n<li>Fix WordPress spinner styling when boxes/fields used on the frontend.</li>\n<li>Fix issue where clicking to remove a <code>file_list</code> item could occasionally remove the field row. (<a href=\"https://github.com/CMB2/CMB2/pull/828\" rel=\"nofollow ugc\">#828</a>).</li>\n<li>Fix issue where empty file field in group would still cause non-empty values to store to database. (<a href=\"https://github.com/CMB2/CMB2/issues/721\" rel=\"nofollow ugc\">#721</a>).</li>\n<li>Make <code>file</code>/<code>file_list</code> field preview images work with named sizes. Props <a href=\"https://github.com/Cai333\" rel=\"nofollow ugc\">@Cai333</a> (<a href=\"https://github.com/CMB2/CMB2/pull/848\" rel=\"nofollow ugc\">#848</a>, <a href=\"https://github.com/CMB2/CMB2/issues/844\" rel=\"nofollow ugc\">#844</a>).</li>\n<li>Fix incorrect text-domain. (<a href=\"https://github.com/CMB2/CMB2/issues/798\" rel=\"nofollow ugc\">#798</a>)</li>\n<li>Do not silence notices/errors in <code>CMB2_Utils::get_file_ext()</code>.</li>\n<li>If <code>title</code> field type has no name value, then only output a span element (instead of a header element).</li>\n</ul>\n<h3>2.2.3.1 &#8211; 2016-11-08</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Better styling for disabled group &#8220;X&#8221; buttons, and add title attr. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/773\" rel=\"nofollow ugc\">#773</a>.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Use quotes for <code>label[for=\"\"]</code> selector. Fixed <code>Syntax error, unrecognized expression</code>. Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/789\" rel=\"nofollow ugc\">#789</a>).</li>\n<li>Fix <code>ReferenceError: tinyMCE is not defined</code> javascript errors (happening when trying to remove a repeatable field/group). Fixes <a href=\"https://github.com/CMB2/CMB2/issues/790\" rel=\"nofollow ugc\">#790</a>, and <a href=\"https://github.com/CMB2/CMB2/issues/730\" rel=\"nofollow ugc\">#730</a>.</li>\n<li>Fix REST API <code>\'show_in_rest\'</code> examples in <code>example-functions.php</code>. Any REST API boxes/fields must use the <code>\'cmb2_init\'</code> hook (as opposed to the <code>\'cmb2_admin_init\'</code> hook).</li>\n</ul>\n<h3>2.2.3 &#8211; 2016-10-25</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>CMB2 REST API! CMB2 now has WP REST API endpoints for displaying your boxes and fields data, as well as registers rest fields in the existing post, user, term, and comment endpoints (in the cmb2 namespace). Enabling the REST API for your boxes/fields is opt-in, meaning it will not be automatically enabled. For more info, <a href=\"https://github.com/CMB2/CMB2/wiki/REST-API\" rel=\"nofollow ugc\">check out the wiki</a>.</li>\n<li>Small string improvement, move a period inside the translatable string. Props <a href=\"https://github.com/pedro-mendonca\" rel=\"nofollow ugc\">@pedro-mendonca</a> (<a href=\"https://github.com/CMB2/CMB2/pull/672\" rel=\"nofollow ugc\">#672</a>).</li>\n<li>Introduce the <code>\'save_field\'</code> boolean field parameter for disabling the saving of a field. Useful if you want to display the value of another field, or use a disabled/read-only field. Props <a href=\"https://github.com/jamesgol\" rel=\"nofollow ugc\">@jamesgol</a> (<a href=\"https://github.com/CMB2/CMB2/pull/674\" rel=\"nofollow ugc\">#674</a>, <a href=\"https://github.com/CMB2/CMB2/issues/346\" rel=\"nofollow ugc\">#346</a>, <a href=\"https://github.com/CMB2/CMB2/issues/500\" rel=\"nofollow ugc\">#500</a>).</li>\n<li>Update docblocks for <code>CMB2_Field::save_field_from_data()</code> and <code>CMB2_Field::save_field()</code>. Props <a href=\"https://github.com/jamesgol\" rel=\"nofollow ugc\">@jamesgol</a> (<a href=\"https://github.com/CMB2/CMB2/pull/675\" rel=\"nofollow ugc\">#675</a>).</li>\n<li>More javascript events tied to the media modal actions (related to the <code>\'file\'</code> and &#8216;<code>file_list\'</code> fields). <code>\'cmb_media_modal_init\'</code>, <code>\'cmb_media_modal_open\'</code>, and <code>\'cmb_media_modal_select\'</code>.</li>\n<li>All CMB2 JS events now also get the CMB2 JS object passed in the list of arguments.</li>\n<li>CMB2 JS object is now instantiated without stomping existing object, to enable extending.</li>\n<li>New field parameter for taxonomy fields, <code>\'remove_default\'</code> which allows disabling the default taxonomy metabox. Props <a href=\"https://github.com/c3mdigital\" rel=\"nofollow ugc\">@c3mdigital</a> (<a href=\"https://github.com/CMB2/CMB2/pull/593\" rel=\"nofollow ugc\">#593</a>).</li>\n<li>Change <code>\'row_classes\'</code> to just <code>\'classes\'</code>, to mirror the metabox <code>\'classes\'</code> property. Also now accepts a <code>\'classes_cb\'</code> parameter for specifying a callback which returns a string or array. The callback will receive <code>$field_args</code> as the first argument, and the CMB2_Field <code>$field</code> object as the second argument. (<code>\'row_classes\'</code> will continue to work, but is deprecated)</li>\n<li>Make wysiwyg editors work in the repeatable groups context. A standard repeatable (non-group) wysiwyg field is not supported (but will possibly be included in a future update). Props <a href=\"https://github.com/johnsonpaul1014\" rel=\"nofollow ugc\">@johnsonpaul1014</a> (<a href=\"https://github.com/CMB2/CMB2/pull/26\" rel=\"nofollow ugc\">#26</a>, <a href=\"https://github.com/CMB2/CMB2/pull/99\" rel=\"nofollow ugc\">#99</a>, <a href=\"https://github.com/CMB2/CMB2/pull/260\" rel=\"nofollow ugc\">#260</a>, <a href=\"https://github.com/CMB2/CMB2/pull/264\" rel=\"nofollow ugc\">#264</a>, <a href=\"https://github.com/CMB2/CMB2/pull/356\" rel=\"nofollow ugc\">#356</a>, <a href=\"https://github.com/CMB2/CMB2/pull/431\" rel=\"nofollow ugc\">#431</a>, <a href=\"https://github.com/CMB2/CMB2/pull/462\" rel=\"nofollow ugc\">#462</a>, <a href=\"https://github.com/CMB2/CMB2/pull/657\" rel=\"nofollow ugc\">#657</a>, <a href=\"https://github.com/CMB2/CMB2/pull/693\" rel=\"nofollow ugc\">#693</a>).</li>\n<li>Add an id to the heading tag in the title field. This allows linking to a particular title using the id.</li>\n<li>Internationalization improvements. Props <a href=\"https://github.com/ramiy\" rel=\"nofollow ugc\">ramiy</a> (<a href=\"https://github.com/CMB2/CMB2/pull/696\" rel=\"nofollow ugc\">#696</a>).</li>\n<li>Ensure that saving does not happen during a switch-to-blog session, as data would be saved to the wrong object. <a href=\"https://wordpress.org/support/topic/bug-in-lastest-version?replies=2\" rel=\"ugc\">See more</a>.</li>\n<li>Add <code>\'cmb2_group_wrap_attributes\'</code> filter to modifying the group wrap div&#8217;s attributes. Filter gets passed an array of attributes and expects the return to be an array. Props <a href=\"https://github.com/jrfnl\" rel=\"nofollow ugc\">jrfnl</a> (<a href=\"https://github.com/CMB2/CMB2/pull/582\" rel=\"nofollow ugc\">#582</a>).</li>\n<li>Update the unit-tests README and inline docs. Props <a href=\"https://github.com/bobbingwide\" rel=\"nofollow ugc\">bobbingwide</a> (<a href=\"https://github.com/CMB2/CMB2/pull/714\" rel=\"nofollow ugc\">#714</a>, <a href=\"https://github.com/CMB2/CMB2/pull/715\" rel=\"nofollow ugc\">#715</a>).</li>\n<li>Minor update to make naming-conventions consistent. Props <a href=\"https://github.com/ramiy\" rel=\"nofollow ugc\">ramiy</a> (<a href=\"https://github.com/CMB2/CMB2/pull/718\" rel=\"nofollow ugc\">#718</a>).</li>\n<li>Update files to be compatible with PHP7 CodeSniffer standards. Props <a href=\"https://github.com/ryanshoover\" rel=\"nofollow ugc\">ryanshoover</a> (<a href=\"https://github.com/CMB2/CMB2/pull/719\" rel=\"nofollow ugc\">#719</a>, <a href=\"https://github.com/CMB2/CMB2/pull/720\" rel=\"nofollow ugc\">#720</a>).</li>\n<li>Make exception message translatable. Props <a href=\"https://github.com/ramiy\" rel=\"nofollow ugc\">ramiy</a> (<a href=\"https://github.com/CMB2/CMB2/pull/724\" rel=\"nofollow ugc\">#724</a>).</li>\n<li>Portuguese translation provided by <a href=\"https://github.com/alvarogois\" rel=\"nofollow ugc\">@alvarogois</a> and <a href=\"https://github.com/pedro-mendonca\" rel=\"nofollow ugc\">@pedro-mendonca</a> &#8211; <a href=\"https://github.com/CMB2/CMB2/pull/709\" rel=\"nofollow ugc\">#709</a>, <a href=\"https://github.com/CMB2/CMB2/pull/727\" rel=\"nofollow ugc\">#727</a>.</li>\n<li>Stop using <code>$wp_version</code> global. Props <a href=\"https://github.com/ramiy\" rel=\"nofollow ugc\">ramiy</a> (<a href=\"https://github.com/CMB2/CMB2/pull/731\" rel=\"nofollow ugc\">#731</a>).</li>\n<li>Closures (anonymous functions) are now supported for any box/field <code>\'*_cb\'</code> parameters. E.g.<br />\n<code>php<br />\n...<br />\n\'show_on_cb\' =&gt; function( $cmb ) { return has_tag( \'cats\', $cmb-&gt;object_id ); },<br />\n...</code></li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>If custom field types use a method and the Type object has not been instantiated, Try to guess the Type object and instantiate.</li>\n<li>Normalize WordPress root path (<code>ABSPATH</code>) and theme rooth path (<code>get_theme_root()</code>). Props <a href=\"https://github.com/rianbotha\" rel=\"nofollow ugc\">@rianbotha</a> (<a href=\"https://github.com/CMB2/CMB2/pull/677\" rel=\"nofollow ugc\">#677</a>, <a href=\"https://github.com/CMB2/CMB2/pull/676\" rel=\"nofollow ugc\">#676</a>).</li>\n<li>Fix issue with <code>\'cmb2_remove_row\'</code> Javascript callback for non-group row removal. Fixes <a href=\"https://github.com/CMB2/CMB2/pull/729\" rel=\"nofollow ugc\">#729</a>).</li>\n<li>Fix issue with missing assignment of variable (undefined variable). Props <a href=\"https://github.com/anhskohbo\" rel=\"nofollow ugc\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/779\" rel=\"nofollow ugc\">#779</a>).</li>\n</ul>\n<h3>2.2.2.1 &#8211; 2016-06-27</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix issue that kept CMB2 stylesheet from being enqueued when using the <a href=\"https://github.com/CMB2/CMB2-Snippet-Library/tree/master/options-and-settings-pages\" rel=\"nofollow ugc\">options-page snippets</a>.</li>\n<li>Fix issue which caused the CMB2 column display styles to be enqueued in the wrong pages. Now only enqueues on admin pages with columns.</li>\n</ul>\n<h3>2.2.2 &#8211; 2016-06-27</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>You can now set admin post-listing columns with an extra field parameter, <code>\'column\' =&gt; true,</code>. If you want to dictate what position the column is, use <code>\'column\' =&gt; array( \'position\' =&gt; 2 ),</code>. If you want to dictate the column title (instead of using the field <code>\'name\'</code> value), use <code>\'column\' =&gt; array( \'name\' =&gt; \'My Column\' ),</code>. If you need to specify the column display callback, set the <code>\'display_cb\'</code> parameter to <a href=\"https://github.com/CMB2/CMB2/wiki/Field-Parameters#render_row_cb\" rel=\"nofollow ugc\">a callback function</a>. Columns work for post (all post-types), comment, user, and term object types.</li>\n<li>Updated Datepicker styles using JJJ&#8217;s &#8220;jQuery UI Datepicker CSS for WordPress&#8221;, so props Props <a href=\"https://github.com/stuttter\" rel=\"nofollow ugc\">@stuttter</a>, <a href=\"https://github.com/johnjamesjacoby\" rel=\"nofollow ugc\">@johnjamesjacoby</a>. Also cleaned up the timepicker styles (specifically the buttons) to more closely align with the datepicker and WordPress styles.</li>\n<li>CMB2 is now a lot more intelligent about where it is located in your installation. This update should solve almost all of the reasons to use the <code>\'cmb2_meta_box_url\'</code> filter (thought it will continue to work as expected). (<a href=\"https://github.com/CMB2/CMB2/issues/27\" rel=\"nofollow ugc\">#27</a>, <a href=\"https://github.com/CMB2/CMB2/issues/118\" rel=\"nofollow ugc\">#118</a>, <a href=\"https://github.com/CMB2/CMB2/issues/432\" rel=\"nofollow ugc\">#432</a>, <a href=\"https://github.com/CMB2/CMB2/wiki/Troubleshooting#cmb2-urls-issues\" rel=\"nofollow ugc\">related wiki item</a>)</li>\n<li>Implement CMB2_Ajax as a singleton. Props <a href=\"https://github.com/jrfnl\" rel=\"nofollow ugc\">jrfnl</a> (<a href=\"https://github.com/CMB2/CMB2/pull/602\" rel=\"nofollow ugc\">#602</a>).</li>\n<li>Add <code>classes</code> and <code>classes_cb</code> CMB2 box params which allows you to add additional classes to the cmb-wrap. The <code>classes</code> parameter can take a string or array, and the <code>classes_cb</code> takes a callback which returns a string or array. The callback will receive <code>$cmb</code> as an argument. These classes are also passed through a new filter, <code>\'cmb2_wrap_classes\'</code>, which receives the array of classes as the first argument, and the CMB2 object as the second. Reported/requested in <a href=\"https://github.com/CMB2/CMB2/issues/364#issuecomment-213223692\" rel=\"nofollow ugc\">#364</a>.</li>\n<li>Make the <code>\'title\'</code> field type accept extra arguments. Props <a href=\"https://github.com/vladolaru\" rel=\"nofollow ugc\">@vladolaru</a>, <a href=\"https://github.com/pixelgrade\" rel=\"nofollow ugc\">@pixelgrade</a> (<a href=\"https://github.com/CMB2/CMB2/pull/656\" rel=\"nofollow ugc\">#656</a>).</li>\n<li>Updated <code>cmb2_get_oembed()</code> function to NOT return the &#8220;remove&#8221; link, as it&#8217;s intended for outputting the oembed only. <strong>This is a backwards-compatibility concern.</strong> If you were depending on the &#8220;remove&#8221; link, use <code>cmb2_ajax()-&gt;get_oembed( $args )</code> instead.</li>\n<li>New function, <code>cmb2_do_oembed()</code>&#8216;, which is hooked to <code>\'cmb2_do_oembed\'</code>, so you can use <code>do_action( \'cmb2_do_oembed\', $args )</code> in your themes without <code>function_exists()</code> checks.</li>\n<li>New method, <code>CMB2:set_prop( $property, $value )</code>, for setting a CMB2 metabox object property.</li>\n<li>The <code>CMB2_Field</code> object instances will now have a <code>cmb_id</code> property and a <code>get_cmb</code> method to enable access to the field&#8217;s <code>CMB2</code> parent object&#8217;s instance, in places like field callbacks and filters (e.g. <code>$cmb = $field-&gt;get_cmb();</code>).</li>\n<li>Add a <code>data-fieldtype</code> attribute to the field rows for simpler identification in Javascript.</li>\n<li>Moved each type in <code>CMB2_Types</code> to it&#8217;s own class so that each field type can handle it&#8217;s own field display, and added the infrastructure to maintainn back-compatibility.</li>\n<li>New <code>CMB2_Utils</code> methods, <code>notempty()</code> and <code>filter_empty()</code>, both of which consider <code>null</code>, <code>\'\'</code> and <code>false</code> as empty, but allow <code>0</code> (for saving <code>0</code> as a field value).</li>\n<li>New <code>CMB2_Utils</code> public methods, <code>get_url_from_dir()</code>, <code>get_file_ext()</code>, <code>get_file_name_from_path()</code>, and <code>wp_at_least()</code>.</li>\n<li>Add a <code>cmb_pre_init</code> Javascript event to allow overriding CMB2 defaults via JS.</li>\n</ul>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fix issue with &#8216;default&#8217; callback not being applied in all instances. Introduced new <code>CMB2_Field::get_default()</code> method, and <code>\'default_cb\'</code> field parameter. Using the <code>\'default\'</code> field parameter with a callback will be deprecated in the next few releases. (<a href=\"https://github.com/CMB2/CMB2/issues/572\" rel=\"nofollow ugc\">#572</a>).</li>\n<li>Be sure to call <code>CMB2_Field::row_classes()</code> for group field rows. Also, update CSS to use the &#8220;cmb-type-group&#8221; classname instead of &#8220;cmb-repeat-group-wrap&#8221;.</li>\n<li>Introduce new <code>\'text\'</code> and <code>\'text_cb\'</code> field parameters for overriding CMB2 text strings instead of using the <code>\'options\'</code> array. (<a href=\"https://github.com/CMB2/CMB2/pull/630\" rel=\"nofollow ugc\">#630</a>)</li>\n<li>Fix bug where the value of &#8216;0&#8217; could not be saved in group fields.</li>\n<li>Fix bug where a serialized empty array value in the database for a repeatable field would output as &#8220;Array&#8221;.</li>\n<li>Allow for optional/empty money field. Props <a href=\"https://github.com/jrfnl\" rel=\"nofollow ugc\">@jrfnl</a> (<a href=\"https://github.com/CMB2/CMB2/pull/577\" rel=\"nofollow ugc\">#577</a>).</li>\n<li>The <code>CMB2::$updated</code> parameter (which contains field ids for all fields updated during a save) now also correctly adds group field ids to the array.</li>\n</ul>\n<h3>2.2.1</h3>\n<h4>Bug Fixes</h4>\n<ul>\n<li>Fixes back-compatibility issue which could allow multiple CMB2 instances to load (causing fatal errors). (<a href=\"https://github.com/CMB2/CMB2/pull/520\" rel=\"nofollow ugc\">#520</a>)</li>\n</ul>\n<h3>2.2.0 &#8211; 2016-02-27</h3>\n<h4>Enhancements</h4>\n<ul>\n<li>Term Meta! As of WordPress 4.4, <a href=\"https://make.wordpress.org/core/2015/10/23/4-4-taxonomy-roundup/\" rel=\"nofollow ugc\">WordPress will have the ability to use term metadata</a>. CMB2 will work with term  &hellip;</li>\n</ul>\n\";s:7:\"reviews\";s:15442:\"<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Super useful!</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/suiramus/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/a692bbc646d1e71cde333b2a6ba10b1e77f6fe89fbfc024da07d2ab1be0d18ed?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/a692bbc646d1e71cde333b2a6ba10b1e77f6fe89fbfc024da07d2ab1be0d18ed?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/suiramus/\" class=\"reviewer-name\">suiramus</a> op <span class=\"review-date\">mei 1, 2025</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Thank you for your hard work!<br />One of the best plugin for developers. Simple and effective.</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Simple and free and much better than advance custom fields</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/paknejad/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/8f71239a3050b2bfda7606cd9dbf546a5309c5bf116870177f019ca5c566cd36?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/8f71239a3050b2bfda7606cd9dbf546a5309c5bf116870177f019ca5c566cd36?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/paknejad/\" class=\"reviewer-name\">paknejad</a> op <span class=\"review-date\">april 27, 2025</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Simple and free and much better than advance custom fields</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Powerfull</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/adityathok/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/3a95666edbecc5ba0424015049ca544702b65c5c6713b62b576f5f1cc9fef005?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/3a95666edbecc5ba0424015049ca544702b65c5c6713b62b576f5f1cc9fef005?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/adityathok/\" class=\"reviewer-name\">Aditya Thok <small>(adityathok)</small></a> op <span class=\"review-date\">april 30, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p>Powerfull, Simple and Clean</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">highly recommended</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/nunziorash/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/d9fa6ecd0428bba0dd924b4c3e9bb1d1a3c3147fe1d12eadcac4ed80ce3003d6?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/d9fa6ecd0428bba0dd924b4c3e9bb1d1a3c3147fe1d12eadcac4ed80ce3003d6?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/nunziorash/\" class=\"reviewer-name\">nunziorash</a> op <span class=\"review-date\">april 4, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p class=\"\">Excellent plugin, I\'ve always used it</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">So Happy to See Updates</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/ipstenu/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/27180c82524020e7339e2b30818b6d8ab004c54f730f12b1434b1e365be0e175?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/27180c82524020e7339e2b30818b6d8ab004c54f730f12b1434b1e365be0e175?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/ipstenu/\" class=\"reviewer-name\">Ipstenu (Mika Epstein) <small>(Ipstenu)</small></a> op <span class=\"review-date\">april 3, 2024</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p class=\"\">I love CMB2. I love hooking into functions and extending addons so fields update each other intelligently, while locking out non-admins to sections.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Blocks are great, don’t get me wrong, and the extensions to make the, more hookable and meta-integrated is nice, but CMB2 gives you full and complete control, with API documented and dozens of add on plugins out there.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Using FacetWP? We have an add on!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Need to attach posts? We have an add on?</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Want to use Shadow Taxonomies to connect posts instead of attaching them and somehow manage to do so dynamically and speedily?</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Hey buddy. They’ve got you.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">The power is yours to command.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Seeing even a version-matching-tested-up-to update makes me worry far less that this plugin will fall by the wayside.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p class=\"\">Up next? PHP 8 compat (I hope…)</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Works...</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/ajanes94/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/14fdfced623a532d77dc39dc439bc21a94dcbbae5b3da563beb32b483d634ee6?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/14fdfced623a532d77dc39dc439bc21a94dcbbae5b3da563beb32b483d634ee6?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/ajanes94/\" class=\"reviewer-name\">ajanes94</a> op <span class=\"review-date\">november 22, 2023</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\"><!-- wp:paragraph -->\n<p class=\"\">...easy to use, nice metaboxes for all post types</p>\n<!-- /wp:paragraph --></div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Excellent plugin</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/maxmanuel327/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/46c997a1b8d621d02c24c352fcaa85b6c3186eb1d8e349e67c68ee5deece6255?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/46c997a1b8d621d02c24c352fcaa85b6c3186eb1d8e349e67c68ee5deece6255?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/maxmanuel327/\" class=\"reviewer-name\">Max Manuel Camiña Azaña <small>(maxmanuel327)</small></a> op <span class=\"review-date\">september 6, 2022</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Perfect plugin for metboxes.</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">Best plugin for Custom Post type</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/lathieuhiep/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/8feca7d77876d2675abebc1cb3cb7403ed6f35d4e6f27c27de71796d51cbfa08?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/8feca7d77876d2675abebc1cb3cb7403ed6f35d4e6f27c27de71796d51cbfa08?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/lathieuhiep/\" class=\"reviewer-name\">lathieuhiep</a> op <span class=\"review-date\">februari 22, 2022</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Best plugin. Saved a lot of time and effort</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">perfect</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/mjr0924/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/7a8a686746a68e8a0b5e70c924e6326e88f41db611009c5fb83ad215a75b6003?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/7a8a686746a68e8a0b5e70c924e6326e88f41db611009c5fb83ad215a75b6003?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/mjr0924/\" class=\"reviewer-name\">mjr0924</a> op <span class=\"review-date\">september 13, 2021</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">merci</div>\n</div>\n<div class=\"review\">\n	<div class=\"review-head\">\n		<div class=\"reviewer-info\">\n			<div class=\"review-title-section\">\n				<h4 class=\"review-title\">keep it up !!</h4>\n				<div class=\"star-rating\">\n				<div class=\"wporg-ratings\" aria-label=\"5 van de 5 sterren\" data-title-template=\"%s van de 5 sterren\" data-rating=\"5\" style=\"color:#ffb900;\"><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span><span class=\"star dashicons dashicons-star-filled\"></span></div>				</div>\n			</div>\n			<p class=\"reviewer\">\n				Door <a href=\"https://profiles.wordpress.org/sergioz/\"><img alt=\'\' src=\'https://secure.gravatar.com/avatar/47ccdfd2069ad91ec29b1b897f5aa40ca17adc4326e07c189086c8ea6c31a7b5?s=16&#038;d=monsterid&#038;r=g\' srcset=\'https://secure.gravatar.com/avatar/47ccdfd2069ad91ec29b1b897f5aa40ca17adc4326e07c189086c8ea6c31a7b5?s=32&#038;d=monsterid&#038;r=g 2x\' class=\'avatar avatar-16 photo\' height=\'16\' width=\'16\' loading=\'lazy\' decoding=\'async\'/></a><a href=\"https://profiles.wordpress.org/sergioz/\" class=\"reviewer-name\">sergioz</a> op <span class=\"review-date\">november 30, 2020</span>			</p>\n		</div>\n	</div>\n	<div class=\"review-body\">Thank you for this awesome plugin !!\n</div>\n</div>\n\";}s:17:\"short_description\";s:91:\"CMB2 is a metabox, custom fields, and forms library for WordPress that will blow your mind.\";s:13:\"download_link\";s:54:\"https://downloads.wordpress.org/plugin/cmb2.2.12.0.zip\";s:14:\"upgrade_notice\";a:8:{s:6:\"2.11.0\";s:0:\"\";s:12:\"Enhancements\";s:4435:\"<ul>\n<li>Added support for sortable columns by default, with ability to disable with <code>&amp;#039;column&amp;#039; =&amp;gt; array( &amp;#039;disable_sortable&amp;#039; =&amp;gt; true )</code>. Props <a href=\"https://github.com/RubenMartins\">@RubenMartins</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1281\">#1281</a>).</li>\n<li>New field type, <code>&amp;#039;taxonomy_select_hierarchical&amp;#039;</code>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/751\">#751</a></li>\n<li>New <code>text</code>, <code>textarea</code> and <code>wysiwyg</code> character counter options. For now, this feature is not available to <code>wysiwyg</code> field types within repeatable groups. Props <a href=\"https://github.com/gyrus\">@gyrus</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1276\">#1276</a>).\n\n<ul>\n<li>The new parameters:\n\n<ul>\n<li><code>&amp;#039;char_counter&amp;#039;</code> - Defaults to false, no counter. Set to true, or <code>words</code> to count words instead of characters.</li>\n<li><code>&amp;#039;char_max&amp;#039;</code> - integer. When defined, counter shows remaining characters/words.</li>\n<li><code>&amp;#039;char_max_enforce&amp;#039;</code> - boolean, default: false. Currently only applied (as maxlength attribute) to <code>text</code> and <code>textarea</code> fields which use <code>&amp;#039;characters&amp;#039;</code> for counter.</li>\n</ul></li>\n<li>You can also <a href=\"https://github.com/CMB2/CMB2/wiki/Field-Parameters#text\">override the default text strings</a> associated with these parameters:\n\n<ul>\n<li><code>&amp;#039;words_left_text&amp;#039;</code> - Default: &quot;Words left&quot;</li>\n<li><code>&amp;#039;words_text&amp;#039;</code> - Default: &quot;Words&quot;</li>\n<li><code>&amp;#039;characters_left_text&amp;#039;</code> - Default: &quot;Characters left&quot;</li>\n<li><code>&amp;#039;characters_text&amp;#039;</code> - Default: &quot;Characters&quot;</li>\n<li><code>&amp;#039;characters_truncated_text&amp;#039;</code> - Default: &quot;Your text may be truncated.&quot;</li>\n</ul></li>\n</ul></li>\n<li>Update styling to be more compatible with WordPress 5.3. Props <a href=\"https://github.com/galengidman\">@galengidman</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1314\">#1314</a>)</li>\n<li>Add a new box parameter, <code>register_rest_field_cb</code>, which when used allows overriding the way CMB2 handles the <code>register_rest_field</code> callbacks, and defining your own REST prefix for your fields. See <a href=\"https://github.com/CMB2/CMB2/pull/1240#issuecomment-552548488\">this PR comment</a> for more context.</li>\n<li>Cleanup by renaming <code>CMB2_hookup</code> to <code>CMB2_Hookup</code>. Classes are case-insensitive, so this is a backwards-compatible change. Props <a href=\"https://github.com/szepeviktor\">@szepeviktor</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1330\">#1330</a>, <a href=\"https://github.com/CMB2/CMB2/issues/1328\">#1328</a>).</li>\n<li>Validate composer.json for Travis CI. Props <a href=\"https://github.com/szepeviktor\">@szepeviktor</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1326\">#1326</a>).</li>\n<li>Added <a href=\"https://github.com/CMB2/CMB2/blob/develop/LICENSE\">LICENSE</a> file to meet GitHub Community standards. Props <a href=\"https://github.com/RubenMartins\">@RubenMartins</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1316\">#1316</a>).</li>\n<li>Add new <code>&amp;quot;cmb2_display_class_{$fieldtype}&amp;quot;</code> filter and <code>&amp;#039;display_class&amp;#039;</code> field parameter to allow specifying the class to use to display the field (in admin columns, etc).</li>\n<li>Update <code>CMB2_Types::_id()</code> to allow not appending the iterator attribute if a repeatable field.</li>\n<li>Added <code>CMB2_Utils::concat_attrs()</code> test for nested arrays as data attributes.</li>\n<li>Various updates per <a href=\"https://github.com/CMB2/CMB2/issues/1260\">VIP feedback</a>. Props <a href=\"https://github.com/kevinlangleyjr\">@kevinlangleyjr</a>, <a href=\"https://github.com/mikeselander\">@mikeselander</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1255\">#1255</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1257\">#1257</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1259\">#1259</a>,  <a href=\"https://github.com/CMB2/CMB2/pull/1261\">#1261</a> <a href=\"https://github.com/CMB2/CMB2/pull/1262\">#1262</a>, and various direct commits. See <a href=\"https://github.com/CMB2/CMB2/issues/1260\">#1260</a>).</li>\n</ul>\";s:9:\"Bug Fixes\";s:4035:\"<ul>\n<li>Fix some issues with Travis. Props <a href=\"https://github.com/anhskohbo\">@anhskohbo</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1220\">#1220</a>).</li>\n<li>Javascript: Correctly pass the newly created row to the <code>cmb2_add_row</code> triggered event.</li>\n<li>Various code-formatting and code documentation improvements. Props <a href=\"https://github.com/tw2113\">@tw2113</a>.</li>\n<li>Don&#039;t exclude composer.json from the distribution. Props <a href=\"https://github.com/johnbillion\">@johnbillion</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1225\">#1225</a>).</li>\n<li>Ignore some more directories in the distribution package. Props <a href=\"https://github.com/johnbillion\">@johnbillion</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1226\">#1226</a>).</li>\n<li>Use <code>CMB2_Field::get_rest_value()</code> to get values for fields in the post REST API endpoints (<a href=\"https://github.com/CMB2/CMB2/issues/1284\">#1284</a>).</li>\n<li>Fix issue where oEmbed fields&#039; live-preview would not work if the field was added within a group, along with some other similarly related issues. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1157\">#1157</a>.</li>\n<li>Fix issue when using REST API for <code>file</code> and <code>text_datetime_timestamp_timezone</code> field types, the supporting field data was not provided (e.g. the file id for <code>file</code> field, and the <code>utc</code> value for the <code>text_datetime_timestamp_timezone</code> field). Fixes <a href=\"https://wordpress.org/support/topic/cmb2-rest-api-image-file-field-as-an-object/\">https://wordpress.org/support/topic/cmb2-rest-api-image-file-field-as-an-object/</a>.</li>\n<li>Escaping Improvements to File Base and File Fields. Props <a href=\"https://github.com/tomjn\">@tomjn</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1296\">#1296</a>, <a href=\"https://github.com/CMB2/CMB2/pull/1297\">#1297</a>).</li>\n<li>Fix issue where repeatable CodeMirror textareas could not be clicked/draggged to highlight text. Props <a href=\"https://github.com/JPry\">@JPry</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1300\">#1300</a>).</li>\n<li><code>taxonomy_select_hierarchical</code> now saves to the correct location, the term relationships table. Props <a href=\"https://github.com/latheva\">@latheva</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1307\">#1307</a>).</li>\n<li>Fix issue (<a href=\"https://github.com/CMB2/CMB2/issues/1158\">#1158</a>) where default REST API endpoints (e.g. <code>/wp/v2/{post_type}</code>) would show all boxes for all custom post types even though not registered to the post-type. Props <a href=\"https://github.com/Mte90\">@Mte90</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1238\">#1238</a>).</li>\n<li>Update and cull npm dependencis. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1308\">#1308</a>.</li>\n<li>Fix some jshint issues.</li>\n<li>Updated the WordPress embeds URL references.</li>\n<li>Updates to account for WordPress 5.2 oEmbed changes.</li>\n<li>Fix to ensure date picker fields can have a default value. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1245\">#1245</a>.</li>\n<li>Added <code>function_exists( &amp;#039;add_action&amp;#039; )</code> check to bootstrap file to ensure compatibility with composer usage. Props <a href=\"https://github.com/salcode\">@salcode</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1271\">#1271</a>, <a href=\"https://github.com/CMB2/CMB2/issues/1270\">#1270</a>)</li>\n<li>Corrected link to facetwp-cmb2 in README.md. Props <a href=\"https://github.com/marcelreschke\">@marcelreschke</a> (<a href=\"https://github.com/CMB2/CMB2/pull/1248\">#1248</a>).</li>\n<li>Use <code>get_user_locale()</code> in admin area instead of <code>get_locale()</code>. Fixes <a href=\"https://github.com/CMB2/CMB2/issues/1267\">#1267</a>.</li>\n<li><code>CMB2::is_box_type()</code> now also checks for taxonomies if box is registered to &quot;term&quot; object type. This should fix some issues where CMB2 term meta was not showing up in REST API requests to the term endpoints.</li>\n</ul>\";s:6:\"2.10.1\";s:0:\"\";s:6:\"2.10.0\";s:0:\"\";s:5:\"2.9.0\";s:0:\"\";s:5:\"2.8.0\";s:0:\"\";s:5:\"2.7.0\";s:0:\"\";}s:11:\"screenshots\";a:0:{}s:4:\"tags\";a:5:{s:6:\"fields\";s:6:\"fields\";s:5:\"forms\";s:5:\"forms\";s:9:\"metaboxes\";s:9:\"metaboxes\";s:7:\"options\";s:7:\"options\";s:8:\"settings\";s:8:\"settings\";}s:8:\"versions\";a:2:{s:6:\"2.12.0\";s:54:\"https://downloads.wordpress.org/plugin/cmb2.2.12.0.zip\";s:5:\"trunk\";s:47:\"https://downloads.wordpress.org/plugin/cmb2.zip\";}s:14:\"business_model\";b:0;s:14:\"repository_url\";s:0:\"\";s:22:\"commercial_support_url\";s:0:\"\";s:11:\"donate_link\";s:15:\"https://cmb2.io\";s:7:\"banners\";a:2:{s:3:\"low\";s:59:\"https://ps.w.org/cmb2/assets/banner-772x250.png?rev=2866672\";s:4:\"high\";s:60:\"https://ps.w.org/cmb2/assets/banner-1544x500.png?rev=2866672\";}s:5:\"icons\";a:2:{s:2:\"1x\";s:49:\"https://ps.w.org/cmb2/assets/icon.svg?rev=2866672\";s:3:\"svg\";s:49:\"https://ps.w.org/cmb2/assets/icon.svg?rev=2866672\";}s:12:\"preview_link\";s:0:\"\";s:4:\"Name\";s:4:\"CMB2\";}s:11:\"gravity-pdf\";a:21:{s:4:\"name\";s:11:\"Gravity PDF\";s:11:\"new_version\";s:6:\"6.14.3\";s:14:\"stable_version\";s:6:\"6.14.3\";s:8:\"sections\";a:2:{s:11:\"description\";s:100:\"<p>Gravity PDF is the ultimate automation tool for generating digital PDFs using Gravity Forms.</p>\n\";s:9:\"changelog\";s:1187:\"<p>6.14.3</p>\n<ul>\n<li>&#x1f9f9; Housekeeping: WordPress 7.0 Compatibility</li>\n<li>&#x1f9f9; Housekeeping: Improved screen-reader support for admin pages</li>\n<li>&#x1f9f9; Housekeeping: Remove obsolete Gravity Forms cache workaround</li>\n<li>&#x1f41e; Bug: Honor PDF Conditional Logic toggle setting, so disabling it in the UI skips stale conditional rules</li>\n<li>&#x1f41e; Bug: Fix Rich Text Editor rendering error when switching PDF templates</li>\n<li>&#x1f41e; Bug: Preserve unsaved edits to the Template fields if switching to a PDF template with the same fields (eg. Core / Invoice / Certificate)</li>\n<li>&#x1f41e; Bug: Preserve the selected template when adding a new PDF</li>\n<li>&#x1f41e; Bug: Fix Gravity Forms 2.6+ version detection on PDF form-settings pages</li>\n<li>&#x1f41e; Bug: Fix regression in the Template Manager when an invalid .zip is uploaded</li>\n<li>&#x1f41e; Bug: Minor UI fixes in the Template Manager</li>\n<li>&#x1f41e; Bug: Fix regression in the Core Fonts installer when a download error occurs</li>\n<li>&#x1f41e; Bug: Reset Gravity Wiz Nested Form field IDs after each group in PDFs</li>\n</ul>\n<p>https://gravitypdf.com/shop/gravity-pdf/changelog</p>\n\";}s:13:\"license_check\";s:0:\"\";s:3:\"msg\";s:0:\"\";s:8:\"homepage\";s:40:\"https://gravitypdf.com/shop/gravity-pdf/\";s:7:\"package\";s:54:\"https://composer.gravitypdf.com/gravity-pdf-6.14.3.zip\";s:5:\"icons\";a:2:{s:2:\"1x\";s:84:\"https://resources.gravitypdf.com/uploads/2024/10/gravity-pdf-plugin-icon-128x128.png\";s:2:\"2x\";s:84:\"https://resources.gravitypdf.com/uploads/2024/10/gravity-pdf-plugin-icon-256x256.png\";}s:7:\"banners\";a:2:{s:4:\"high\";s:0:\"\";s:3:\"low\";s:0:\"\";}s:4:\"slug\";s:11:\"gravity-pdf\";s:3:\"url\";s:52:\"https://gravitypdf.com/shop/gravity-pdf/?changelog=1\";s:12:\"last_updated\";s:19:\"2026-05-20 19:43:38\";s:13:\"download_link\";s:54:\"https://composer.gravitypdf.com/gravity-pdf-6.14.3.zip\";s:14:\"upgrade_notice\";s:0:\"\";s:11:\"description\";a:1:{i:0;s:100:\"<p>Gravity PDF is the ultimate automation tool for generating digital PDFs using Gravity Forms.</p>\n\";}s:9:\"changelog\";a:1:{i:0;s:1187:\"<p>6.14.3</p>\n<ul>\n<li>&#x1f9f9; Housekeeping: WordPress 7.0 Compatibility</li>\n<li>&#x1f9f9; Housekeeping: Improved screen-reader support for admin pages</li>\n<li>&#x1f9f9; Housekeeping: Remove obsolete Gravity Forms cache workaround</li>\n<li>&#x1f41e; Bug: Honor PDF Conditional Logic toggle setting, so disabling it in the UI skips stale conditional rules</li>\n<li>&#x1f41e; Bug: Fix Rich Text Editor rendering error when switching PDF templates</li>\n<li>&#x1f41e; Bug: Preserve unsaved edits to the Template fields if switching to a PDF template with the same fields (eg. Core / Invoice / Certificate)</li>\n<li>&#x1f41e; Bug: Preserve the selected template when adding a new PDF</li>\n<li>&#x1f41e; Bug: Fix Gravity Forms 2.6+ version detection on PDF form-settings pages</li>\n<li>&#x1f41e; Bug: Fix regression in the Template Manager when an invalid .zip is uploaded</li>\n<li>&#x1f41e; Bug: Minor UI fixes in the Template Manager</li>\n<li>&#x1f41e; Bug: Fix regression in the Core Fonts installer when a download error occurs</li>\n<li>&#x1f41e; Bug: Reset Gravity Wiz Nested Form field IDs after each group in PDFs</li>\n</ul>\n<p>https://gravitypdf.com/shop/gravity-pdf/changelog</p>\n\";}s:6:\"plugin\";s:19:\"gravity-pdf/pdf.php\";s:7:\"version\";s:6:\"6.14.3\";s:8:\"external\";b:1;s:4:\"Name\";s:11:\"Gravity PDF\";}s:12:\"gravityforms\";a:6:{s:4:\"name\";s:13:\"Gravity Forms\";s:7:\"version\";s:6:\"2.10.3\";s:13:\"download_link\";s:186:\"https://s3.dualstack.us-east-1.amazonaws.com/gravityforms/releases/gravityforms_2.10.3.zip?AWSAccessKeyId=AKIA5U3GBHC5Q2TM5N7H&Expires=1781619408&Signature=jkYJ5sRvnnrXTYrPxY050h2Cc2k%3D\";s:6:\"tested\";s:4:\"10.0\";s:8:\"external\";b:1;s:4:\"Name\";s:13:\"Gravity Forms\";}}'),
